-- Poems batch 179
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('60dcbd10-979d-4fcb-9968-0747b468f9d5','種柳吟','金朋說','宋','宋诗','song-poetry','','[]','種柳護吾廬，無妨隠者居。',24,'全唐诗/poet.song.174000.json','["種柳護吾廬，無妨隠者居。", "綠酬一樽酒，青映五車書。"]'),
('62a201fe-fe7a-4adb-b10c-f775df60306f','賦歸吟','金朋說','宋','宋诗','song-poetry','','[]','松菊存陶徑，弦歌絕武城。',24,'全唐诗/poet.song.174000.json','["松菊存陶徑，弦歌絕武城。", "江東新發櫂，僮僕笑相迎。"]'),
('a95cf830-f4ac-4930-a472-b813bf40e48b','冬雪吟','金朋說','宋','宋诗','song-poetry','','[]','彤雲垂四野，六出舞漫天。',24,'全唐诗/poet.song.174000.json','["彤雲垂四野，六出舞漫天。", "却笑廣文鄭，嚴寒無坐氈。"]'),
('6fea757f-8e96-42dc-9a39-61aec88bbd4c','種桃吟','金朋說','宋','宋诗','song-poetry','','[]','分種玄都觀，移根出武陵。',24,'全唐诗/poet.song.174000.json','["分種玄都觀，移根出武陵。", "河陽花滿縣，曾歷避狂秦。"]'),
('b67fbcc2-9d6a-4a56-aea8-2c63ee431fc3','種梅吟','金朋說','宋','宋诗','song-poetry','','[]','栽梅沿屋角，幽趣少人知。',24,'全唐诗/poet.song.174000.json','["栽梅沿屋角，幽趣少人知。", "雪後月明夜，孤芳吐幾枝。"]'),
('df042c9e-2786-4e9e-a08a-b303e7658d80','種松吟','金朋說','宋','宋诗','song-poetry','','[]','人皆愛桃李，我愛種青松。',24,'全唐诗/poet.song.174000.json','["人皆愛桃李，我愛種青松。", "桃李易凋謝，青松却耐寒。"]'),
('37683988-5ceb-4b4e-99a7-7c7f3f167588','種竹吟','金朋說','宋','宋诗','song-poetry','','[]','種竹清無俗，虛心耐歲寒。',24,'全唐诗/poet.song.174000.json','["種竹清無俗，虛心耐歲寒。", "凭窗風日爽，詩酒可盤桓。"]'),
('ad25bacb-0ca8-4d49-b1db-368ed774bb6b','種菊吟','金朋說','宋','宋诗','song-poetry','','[]','衆卉競春妍，芬芳無彼此。',24,'全唐诗/poet.song.174000.json','["衆卉競春妍，芬芳無彼此。", "霜寒摇落時，獨秀何如爾。"]'),
('7afc423f-bb39-4899-964d-f2a3239484f6','晨雞吟','金朋說','宋','宋诗','song-poetry','','[]','司晨兼五德，曾伴宋宗窗。',24,'全唐诗/poet.song.174000.json','["司晨兼五德，曾伴宋宗窗。", "日攘能防慎，終當免鑊湯。"]'),
('4805e70e-31e5-46bb-9486-55ef2d449719','持敬齋吟','金朋說','宋','宋诗','song-poetry','','[]','恭己時存養，敬以充四端。',24,'全唐诗/poet.song.174000.json','["恭己時存養，敬以充四端。", "唯狂能克念，作聖抑何難。"]'),
('80e06f54-c4f9-4818-bbb2-bcd5073ef0f6','止齋吟','金朋說','宋','宋诗','song-poetry','','[]','知止於至善，修身止用誠。',24,'全唐诗/poet.song.174000.json','["知止於至善，修身止用誠。", "五倫止此定，明德日新民。"]'),
('020a579e-81f8-4b0a-94af-2ce843e3caa9','戒五荒','金朋說','宋','宋诗','song-poetry','','[]','重色躭沉湎，娛音樂侈華。',24,'全唐诗/poet.song.174000.json','["重色躭沉湎，娛音樂侈華。", "禽荒迷不返，未有不亡家。"]'),
('b93408a6-8c92-4847-adc5-609b82d861b2','春日吟','金朋說','宋','宋诗','song-poetry','','[]','柳塘花塢矮垣牆，簾捲東風砌草芳。',32,'全唐诗/poet.song.174000.json','["柳塘花塢矮垣牆，簾捲東風砌草芳。", "天理流行隨處見，盈虛伸縮可消詳。"]'),
('d3d0eab1-c54d-4438-be07-aaac348dea4b','游山吟','金朋說','宋','宋诗','song-poetry','','[]','躡屐山行日看花，春前桃李屬誰家。',32,'全唐诗/poet.song.174000.json','["躡屐山行日看花，春前桃李屬誰家。", "千紅萬紫爭妍媚，不似青松耐歲華。"]'),
('d7980b6d-2d44-4845-a9fa-4644cb0138f1','春山吟','金朋說','宋','宋诗','song-poetry','','[]','岧嶢嫩綠間妖紅，碧樹瓊花瀲灧中。',32,'全唐诗/poet.song.174000.json','["岧嶢嫩綠間妖紅，碧樹瓊花瀲灧中。", "一段天機猶織就，宜爲宅畔錦屏風。"]'),
('ad0e6233-04b1-4455-954a-743353df5ef8','海棠吟','金朋說','宋','宋诗','song-poetry','','[]','豔質妖娜放早春，誰教帝主溺初心。',32,'全唐诗/poet.song.174000.json','["豔質妖娜放早春，誰教帝主溺初心。", "椒房一睡纔扶起，徹動漁陽鼙鼓聲。"]'),
('e57229de-3a40-4f11-b0d4-12c9d06cc943','牡丹吟','金朋說','宋','宋诗','song-poetry','','[]','嬌姿豔質號花王，魏砌姚階羨紫黄。',32,'全唐诗/poet.song.174000.json','["嬌姿豔質號花王，魏砌姚階羨紫黄。", "更有一株何處種，天然標格出扶桑。"]'),
('292dd031-3a73-48b8-8cd7-931f6a183f7f','芍藥吟','金朋說','宋','宋诗','song-poetry','','[]','畫闌倚玉對偎紅，娜嬝翻階放艷穠。',32,'全唐诗/poet.song.174000.json','["畫闌倚玉對偎紅，娜嬝翻階放艷穠。", "自笑主人無個事，年年携酒祝東風。"]'),
('f3d5aceb-e1f9-4e20-bba1-b67537a21bf3','薔薇吟','金朋說','宋','宋诗','song-poetry','','[]','塗朱抹粉吐芳馨，倚架依闌承露新。',32,'全唐诗/poet.song.174000.json','["塗朱抹粉吐芳馨，倚架依闌承露新。", "膩白妖紅誰不惜，樽前莫負插花吟。"]'),
('a46cec20-88d8-4dfd-99dd-6b5655f77edb','茉莉吟','金朋說','宋','宋诗','song-poetry','','[]','一種秋容淡素粧，西風吹破幾枝芳。',32,'全唐诗/poet.song.174000.json','["一種秋容淡素粧，西風吹破幾枝芳。", "瓊葩玉蕊金飆夜，疑是梅花入夢香。"]'),
('b8b5de91-4ea5-4a1b-bb07-c200f0a5ab49','木槿花','金朋說','宋','宋诗','song-poetry','','[]','夜合朝開秋露新，幽庭雅稱畫屏清。',32,'全唐诗/poet.song.174000.json','["夜合朝開秋露新，幽庭雅稱畫屏清。", "果然蠲得人間忿，何必當年寵太真。"]'),
('7ba0170a-4202-4eee-80c5-84c49f3b256a','木樨吟','金朋說','宋','宋诗','song-poetry','','[]','月窟移來種異常，金英玉糝散天香。',32,'全唐诗/poet.song.174000.json','["月窟移來種異常，金英玉糝散天香。", "年年八月中秋節，賞盡詩翁酒幾缸。"]'),
('a1fea5da-a2dd-4450-9c4f-1b87d312b02e','菊花吟','金朋說','宋','宋诗','song-poetry','','[]','金葩玉蘂破寒霜，北徑東籬艷吐芳。',32,'全唐诗/poet.song.174000.json','["金葩玉蘂破寒霜，北徑東籬艷吐芳。", "自惜彊腰翁去後，幾人能共對重陽。"]'),
('604c5255-8928-4ce1-aab1-78cbca1ef1ea','梅花吟','金朋說','宋','宋诗','song-poetry','','[]','傲雪含芳破五花，水村山郭傍詩家。',32,'全唐诗/poet.song.174000.json','["傲雪含芳破五花，水村山郭傍詩家。", "本爲金鼎調羹物，寥落山林老歲華。"]'),
('768f76ea-4a0c-435b-8548-d495ac24f1c7','山茶花','金朋說','宋','宋诗','song-poetry','','[]','嚴寒瑞雪正飄飄，布滿乾坤似玉澆。',32,'全唐诗/poet.song.174000.json','["嚴寒瑞雪正飄飄，布滿乾坤似玉澆。", "獨見牆頭傾赤艷，鮮紅幾朶破瓊瑶。"]'),
('c5c08b67-a4f7-4dcd-bea5-ef9d0ffdeba5','蓮花吟','金朋說','宋','宋诗','song-poetry','','[]','夐出漣漪不染泥，濃粧淡抹總相宜。',32,'全唐诗/poet.song.174000.json','["夐出漣漪不染泥，濃粧淡抹總相宜。", "六郎莫恃人憐惜，君子名稱更絕奇。"]'),
('778bbb70-e5e2-4530-8827-75ce2edeaac8','葵花吟','金朋說','宋','宋诗','song-poetry','','[]','絳萼纍纍承曉露，含英藴質並朱雲。',32,'全唐诗/poet.song.174000.json','["絳萼纍纍承曉露，含英藴質並朱雲。", "廟廊忠梗誰堪比，能展丹心向日傾。"]'),
('92b9f92c-a475-4388-a2b4-ff828bfd1f9a','賞桃吟','金朋說','宋','宋诗','song-poetry','','[]','瑶池結實幾千春，曾種河陽花滿城。',32,'全唐诗/poet.song.174000.json','["瑶池結實幾千春，曾種河陽花滿城。", "若問武陵先日事，相逢俱是避秦人。"]'),
('be9ef88f-ebb7-4bf2-ae18-6439b7069fa1','賞李吟','金朋說','宋','宋诗','song-poetry','','[]','雅綴瓊林伴召棠，梨花綜錯影琳瑯。',32,'全唐诗/poet.song.174000.json','["雅綴瓊林伴召棠，梨花綜錯影琳瑯。", "慙無廊廟調羹味，莫惜區區棄路旁。"]'),
('6db15364-d8f2-4961-9919-3b887b2ed5c4','賞柳吟','金朋說','宋','宋诗','song-poetry','','[]','舞翠垂絲夾小橋，春風庭院鳥聲嬌。',32,'全唐诗/poet.song.174000.json','["舞翠垂絲夾小橋，春風庭院鳥聲嬌。", "自從靖節蕭踈後，復許誰人不折腰。"]'),
('c03e4446-7d26-4b8b-a5cc-5e543e07b0a0','賞松吟','金朋說','宋','宋诗','song-poetry','','[]','巖谷雖蕪松尚存，溪門僮僕伺朝昏。',32,'全唐诗/poet.song.174000.json','["巖谷雖蕪松尚存，溪門僮僕伺朝昏。", "林泉清興真飄逸，月滿軒窗酒滿罇。"]'),
('be02eaaa-4414-492f-a859-45ebe9c8da4a','賞竹吟','金朋說','宋','宋诗','song-poetry','','[]','放鶴空庭竹似賓，輕風晴日綠篩金。',32,'全唐诗/poet.song.174000.json','["放鶴空庭竹似賓，輕風晴日綠篩金。", "幽人寧使食無肉，不可軒墀少此君。"]'),
('6f38d35d-3be2-4b14-afce-fc3480a15a3c','幽居吟','金朋說','宋','宋诗','song-poetry','','[]','種竹爲垣護草堂，面山臨水納幽芳。',32,'全唐诗/poet.song.174000.json','["種竹爲垣護草堂，面山臨水納幽芳。", "從容泉石無牽絆，不似從前志廟廊。"]'),
('50765ce8-50d0-458b-b3fe-d734a32ad33f','新秋即事','金朋說','宋','宋诗','song-poetry','','[]','池塘高柳噪新蟬，庭館秋風初入弦。',32,'全唐诗/poet.song.174000.json','["池塘高柳噪新蟬，庭館秋風初入弦。", "撫罷瑶琴金井畔，不堪梧葉落翩翩。"]'),
('1beaf1d2-9669-42fd-9209-9fe02a2ac3e3','秋日書懷','金朋說','宋','宋诗','song-poetry','','[]','夜合花開放曉晴，凉飆新爽小池亭。',32,'全唐诗/poet.song.174000.json','["夜合花開放曉晴，凉飆新爽小池亭。", "幽人雅稱林泉興，弄月吟風樂更清。"]'),
('4acf8991-64cd-46e2-a17e-eebb645fad88','七夕吟','金朋說','宋','宋诗','song-poetry','','[]','銀河東達鵲橋西，織女牛郎會晤時。',32,'全唐诗/poet.song.174000.json','["銀河東達鵲橋西，織女牛郎會晤時。", "纔得歡娛又離別，相逢擬待隔年期。"]'),
('b923228e-b616-42b7-b9a1-f36a65937fa9','中秋夜偕朱表姪題月','金朋說','宋','宋诗','song-poetry','','[]','晴空光溢玉盤鮮，銀漢斕斒斗柄旋。',32,'全唐诗/poet.song.174000.json','["晴空光溢玉盤鮮，銀漢斕斒斗柄旋。", "此夕共爲攀桂問，姮娥著付與誰先。"]'),
('50d810d3-e887-4020-98b7-2647f5b1432d','秋山吟','金朋說','宋','宋诗','song-poetry','','[]','濃淡霜林入望中，天工施巧染秋容。',32,'全唐诗/poet.song.174000.json','["濃淡霜林入望中，天工施巧染秋容。", "秋容猶勝春光好，翠葉燒丹綠樹紅。"]'),
('d3a11e66-013b-4320-8633-7b5a07acf8fc','冬日憶友','金朋說','宋','宋诗','song-poetry','','[]','寥落園林度小春，枝頭橙橘摘黄金。',32,'全唐诗/poet.song.174000.json','["寥落園林度小春，枝頭橙橘摘黄金。", "蟹螯樽俎新豊美，剪燭連宵憶故人。"]'),
('b30c57d6-7fb9-4adf-8e80-8d4a006e8bd3','冬日幽居','金朋說','宋','宋诗','song-poetry','','[]','爐煨榾柮雪煎茶，松竹環居耐歲華。',32,'全唐诗/poet.song.174000.json','["爐煨榾柮雪煎茶，松竹環居耐歲華。", "窗外玉梅疏弄影，助人詩興兩三花。"]'),
('313524df-af04-406b-abe5-c96451357e8c','雪山','金朋說','宋','宋诗','song-poetry','','[]','聳翠摩蒼列畫圖，彤雲作雪滿天鋪。',32,'全唐诗/poet.song.174000.json','["聳翠摩蒼列畫圖，彤雲作雪滿天鋪。", "青山莫謂長無老，一夜飛瓊盡白顱。"]'),
('007481c1-2c58-4317-bfe4-2e4405d87475','詠朱默齋山茶花','金朋說','宋','宋诗','song-poetry','','[]','誰掇孤根牆角栽，天然穠艷襯瑶臺。',32,'全唐诗/poet.song.174000.json','["誰掇孤根牆角栽，天然穠艷襯瑶臺。", "歲寒松柏如相問，一點丹紅雪裏開。"]'),
('12988665-4f4d-4c9b-ab27-77d2310209b5','題吳表兄雪鶴山茶圖','金朋說','宋','宋诗','song-poetry','','[]','飄然六出舞長空，四顧樓臺玉砌中。',32,'全唐诗/poet.song.174000.json','["飄然六出舞長空，四顧樓臺玉砌中。", "却被兩般來點破，鶴呈丹頂樹頭紅。"]'),
('b85097f1-9ef8-45cb-8d5d-8a4f7eaeab72','樂漁吟','金朋說','宋','宋诗','song-poetry','','[]','桃花澗底頻垂釣，蓼子灘頭穩繫舟。',32,'全唐诗/poet.song.174000.json','["桃花澗底頻垂釣，蓼子灘頭穩繫舟。", "取得魚來換美酒，清風明月興悠悠。"]'),
('6e33e3e1-41ca-4762-aacb-a0f68aad6273','樂樵吟','金朋說','宋','宋诗','song-poetry','','[]','木美牛山斤斧息，爛柯林下度長年。',32,'全唐诗/poet.song.174000.json','["木美牛山斤斧息，爛柯林下度長年。", "有時巖底問漁者，利害相論理豁然。"]'),
('2afb5e4e-e00d-4243-abe6-97677e489718','樂耕吟','金朋說','宋','宋诗','song-poetry','','[]','黄鸝語後麥初熟，鴻雁來時稻正香。',32,'全唐诗/poet.song.174000.json','["黄鸝語後麥初熟，鴻雁來時稻正香。", "但獲新倉豐稔足，牀頭新釀酒盈缸。"]'),
('488129c0-1164-4f04-9af4-63cdaee7b5d6','樂牧吟','金朋說','宋','宋诗','song-poetry','','[]','牛背日高方睡熟，橫吹短笛不成腔。',32,'全唐诗/poet.song.174000.json','["牛背日高方睡熟，橫吹短笛不成腔。", "毛球打罷歸來晚，古木寒鴉又夕陽。"]'),
('84f01cab-3b05-4e55-9a30-e8d0cf361128','夏日幽居','金朋說','宋','宋诗','song-poetry','','[]','小隠樓臺綠樹中，藕塘花豔散香風。',32,'全唐诗/poet.song.174000.json','["小隠樓臺綠樹中，藕塘花豔散香風。", "綸巾羽扇薰風坐，逸興飄飄迥不同。"]'),
('54782e29-c315-4aa3-9d18-d4828c0ade41','泰伯虞仲祠','金朋說','宋','宋诗','song-poetry','','[]','閲牆兄弟不相容，尺布猶憐尚可縫。',32,'全唐诗/poet.song.174000.json','["閲牆兄弟不相容，尺布猶憐尚可縫。", "讓位介然如棄屣，盛哉至德厚無窮。"]'),
