('eb57998e-9224-496f-be61-fab38209660d','送劉改之二首  其一','王居安','宋','宋诗','song-poetry','','[]','劉子堂堂七尺軀，高談世事奮髯鬚。',64,'全唐诗/poet.song.174000.json','["劉子堂堂七尺軀，高談世事奮髯鬚。", "觀渠論到前賢處，據我看來近世無。", "出語令人驚辟易，處窮無鬼敢揶揄。", "徜徉閙市渾無畏，要是人間烈丈夫。"]'),
('c708c0be-690a-4e1d-9355-d0c48f6a0cd6','送劉改之二首  其二','王居安','宋','宋诗','song-poetry','','[]','不識劉郎莫便語，酒酣耳熱未全疎。',64,'全唐诗/poet.song.174000.json','["不識劉郎莫便語，酒酣耳熱未全疎。", "士當窮困能無慊，我自斟量愧不如。", "橫槊賦詩俱有分，輕裘緩带特其餘。", "當今四野無塵土，宜有奇才在草廬。"]'),
('7a64aa1e-1a27-4f86-87c1-62b55a3e7e90','游委羽山','王居安','宋','宋诗','song-poetry','','[]','幾日山不到，到山心自清。',24,'全唐诗/poet.song.174000.json','["幾日山不到，到山心自清。", "稜稜有方石，拾得通仙靈。"]'),
('5aa26085-0ece-4a28-8b35-df09e222cf5a','考試當塗次池陽崎嶇山行石多可愛因用袁席之韻','王居安','宋','宋诗','song-poetry','','[]','平生愛奇石，如見古君子。',132,'全唐诗/poet.song.174000.json','["平生愛奇石，如見古君子。", "一卷窗牖間，時復爲隠几。", "茲行池陽路，終日亂山裏。", "道傍石叢生，牛羊亂虎兕。", "中有篆籀文，鼎彝間罍洗。", "縱橫列簨虡，埋沒見追蠡。", "嗟予心好之，愧恨無能徙。", "著手爲摩挲，却立復睥睨。", "有似南陽公，可就不可致。", "是宜米元章，一見輒下拜。", "倘可從予招，安車更加禮。"]'),
('40671ed7-b238-4b73-9487-83bed648d1d9','潘德久有龍眠三馬而失其一俾予賦詩','王居安','宋','宋诗','song-poetry','','[]','三馬往往皆龍駒，神駿肯與凡馬俱。',80,'全唐诗/poet.song.174000.json','["三馬往往皆龍駒，神駿肯與凡馬俱。", "忽不見者其前驅，定應飛上天之衢。", "君得其二已有餘，我欲與君分此圖。", "駑才患多不患無，四十萬疋將何如。", "龍眠已往不可呼，愈少愈貴宜寶儲。"]'),
('d5986d2f-e329-4e0e-97b6-b35f73136415','送劉改之','王居安','宋','宋诗','song-poetry','','[]','名滿江湖劉改之，半生窮困只吟詩。',64,'全唐诗/poet.song.174000.json','["名滿江湖劉改之，半生窮困只吟詩。", "人言季布恐難近，我謂鄭老真吾師。", "試令滿飲至酩酊，愈覺高論生神奇。", "豪家有財不識寶，貧者識之空嗟咨。"]'),
('23a6c44a-8593-4f32-9614-6ea485398590','句  其一','王居安','宋','宋诗','song-poetry','','[]','高下水痕元自定，後先花信不須催。',16,'全唐诗/poet.song.174000.json','["高下水痕元自定，後先花信不須催。"]'),
('9cab6f45-28da-479c-a4a1-a4997505e7ed','句  其二','王居安','宋','宋诗','song-poetry','','[]','祇教人種菜，莫誤客看花。',12,'全唐诗/poet.song.174000.json','["祇教人種菜，莫誤客看花。"]'),
('370ae340-be5c-4ca0-bbd4-90099b0703ae','句  其三','王居安','宋','宋诗','song-poetry','','[]','只爲人前呈顔色，天工罰取不教香。',16,'全唐诗/poet.song.174000.json','["只爲人前呈顔色，天工罰取不教香。"]'),
('8d5a4526-c151-493a-8a54-90be15b6b879','仙水洞','朱慶弼','宋','宋诗','song-poetry','','[]','冰凝石乳寒流竭，霜打孤巖苔髮結。',32,'全唐诗/poet.song.174000.json','["冰凝石乳寒流竭，霜打孤巖苔髮結。", "鮫綃洞底織欲成，颼颼風從洞口出。"]'),
('03f241b3-b889-4ec5-9398-0ef9bb7fff88','一線泉','李志甫','宋','宋诗','song-poetry','','[]','蓬萊頂上幾相逢，常恨山高目力窮。',32,'全唐诗/poet.song.174000.json','["蓬萊頂上幾相逢，常恨山高目力窮。", "此地紆迴泉一線，蓬萊却在有無中。"]'),
('bc762f55-10aa-43db-81c6-7c711f823c78','遇災報應詩','繆瑜','宋','宋诗','song-poetry','','[]','鬰攸屬者潜煽災，蜚廉縱風相與偕。',238,'全唐诗/poet.song.174000.json','["鬰攸屬者潜煽災，蜚廉縱風相與偕。", "林林生齒七萬戶，連甍接棟燒成灰。", "如何老翁一區宅，間不以寸獨不㶼。", "玉石俱焚勢應爾，豈有幻術能然哉。", "聞之翁乃好善者，平時事佛經卷開。", "有餘必以濟貧乏，不以利欲縈其懷。", "倉卒遂蒙鬼神護，萬目注視咸驚猜。", "厥初巨燄爇天起，左顧右盼如燔柴。", "翁知無脫免，委身甘作燼與煨。", "麾兒與婦令亟走，誓死不去無違乖。", "全家酣寢越信宿，如聞大浪聲喧豗。", "及其夢覺火亦息，依然一室當崔嵬。", "微如蒲萄不熏灼，而况梁棟與桷榱。", "蒼蒼表善有如此，餘自作孽何足哀。", "作詩誌往勸來者，勿以斯語同優俳。"]'),
('d405dd0f-5742-4919-8c8e-136f983447ba','釣臺  其一','繆瑜','宋','宋诗','song-poetry','','[]','王陽在位貢公喜，何况故人作天子。',64,'全唐诗/poet.song.174000.json','["王陽在位貢公喜，何况故人作天子。", "掉頭不肯從渠遊，却把絲竿釣江水。", "欲將此意問遺靈，寂寞江山喚不應。", "至今桐江一拳石，留得人間千古名。"]'),
('ce5cf90e-d6df-4b14-af68-b875e9a08a52','釣臺  其二','繆瑜','宋','宋诗','song-poetry','','[]','桐廬江中秋水清，富春山中秋月明。',96,'全唐诗/poet.song.174000.json','["桐廬江中秋水清，富春山中秋月明。", "釣竿千尺無恙在，持竿我欲從先生。", "先生豈是傲當世，鄙夫患失滔滔是。", "狂瀾既倒挽之回，持報故人惟此爾。", "衮衣不博一羊裘，事往臺空江自流。", "遂令千古重名節，於乎先生真漢傑。"]'),
('388234f6-cdb2-49fa-b8ec-f12b58a8e217','句  其一','繆瑜','宋','宋诗','song-poetry','','[]','有客去遊丞相閣，無人來問孝廉船。',16,'全唐诗/poet.song.174000.json','["有客去遊丞相閣，無人來問孝廉船。"]'),
('2decd681-08e6-41ec-ae84-8105598f876c','句  其二','繆瑜','宋','宋诗','song-poetry','','[]','亭臺十二眼雙明，一幅畫圖開水墨。',16,'全唐诗/poet.song.174000.json','["亭臺十二眼雙明，一幅畫圖開水墨。"]'),
('e8937a01-c586-41e1-bf27-1105e5781853','句  其三','繆瑜','宋','宋诗','song-poetry','','[]','棲鴉照日黄。',6,'全唐诗/poet.song.174000.json','["棲鴉照日黄。"]'),
('a1f51477-566b-440d-8e47-fb875c8ce45e','句  其四','繆瑜','宋','宋诗','song-poetry','','[]','勳業轉悠悠。',6,'全唐诗/poet.song.174000.json','["勳業轉悠悠。"]'),
('6f308d15-39f4-415d-974e-b19d6403f776','句  其五','繆瑜','宋','宋诗','song-poetry','','[]','解纜浙江頭。',6,'全唐诗/poet.song.174000.json','["解纜浙江頭。"]'),
('06468a2f-d693-429a-8694-a89c5b39714d','句  其六','繆瑜','宋','宋诗','song-poetry','','[]','寒盟得問鷗。',6,'全唐诗/poet.song.174000.json','["寒盟得問鷗。"]'),
('01ed0b23-766b-439a-97cd-7501998b7d98','句  其七','繆瑜','宋','宋诗','song-poetry','','[]','野田流水濺濺白。',8,'全唐诗/poet.song.174000.json','["野田流水濺濺白。"]'),
('69cf681b-1a87-43e5-a68a-e15b853ce3e5','句  其八','繆瑜','宋','宋诗','song-poetry','','[]','遊人柳葉蹙鞦韆。',8,'全唐诗/poet.song.174000.json','["遊人柳葉蹙鞦韆。"]'),
('09470fef-5478-4e71-84b6-27181ce9733c','水仙王廟辭','袁韶','宋','宋诗','song-poetry','','[]','桂水闊兮仙宮，今何爲兮山之中。',84,'全唐诗/poet.song.174000.json','["桂水闊兮仙宮，今何爲兮山之中。", "羌時俗兮改錯，寄嘉名兮土龍。", "卜中洲兮芷閭，仙歸兮故居。", "旂夫容兮蘭枻，詔馮夷兮先驅。", "杜蘅紛兮旅庭，酌寒泉兮秋英。", "福帝郊兮塵清，終萬古兮揚靈。"]'),
('87c7c5bd-997b-48ef-9b3b-34ec51e4508f','題林和靖像','袁韶','宋','宋诗','song-poetry','','[]','避影林壑，清畏人知。',40,'全唐诗/poet.song.174000.json','["避影林壑，清畏人知。", "爾梅多事，漏吾天機。", "長風孤騫，秋鶴與飛。", "山高水深，無成無虧。"]'),
('b79f800c-f33e-477c-b734-a96b112b999f','句','袁韶','宋','宋诗','song-poetry','','[]','宴堂聯族子，講席後諸生。',12,'全唐诗/poet.song.174000.json','["宴堂聯族子，講席後諸生。"]'),
('24ffc050-740c-41f0-9122-79acdce4edc9','玉笥山','蕭逵','宋','宋诗','song-poetry','','[]','涪翁筆下千鈞重，趙尹胸中萬里寬。',64,'全唐诗/poet.song.174000.json','["涪翁筆下千鈞重，趙尹胸中萬里寬。", "寶墨幾年藏瑞氣，新亭今日敞奇觀。", "翠屏遠带斜陽淡，素練光涵夜月寒。", "苔碧印文公事少，謾尋詩句立欄干。"]'),
('520d4aac-5994-4cd3-b995-fe09b4cd56d9','憶東山','杜思恭','宋','宋诗','song-poetry','','[]','上山月正高，下山月已黑。',56,'全唐诗/poet.song.174000.json','["上山月正高，下山月已黑。", "謝公風流遠，抵掌慨陳迹。", "楸枰一局笑未闌，捷書喜報收河山。", "我今念此幾廢食，諸公都作新亭泣。"]'),
('07a8e23d-e227-4962-ad5e-f4d8b174e1f7','題韓任道寓軒','林宗放','宋','宋诗','song-poetry','','[]','坤作基，天作宇，架以虹霓鼇作柱。',80,'全唐诗/poet.song.174000.json','["坤作基，天作宇，架以虹霓鼇作柱。", "入窗秦雲連楚雨，六合爲鄰誰障堵。", "試問繩床供仰俯，是處江山子作主。", "雲夢胸中著千古，明月清風左右取。", "客來問君此爲寓，莫遣漆園漫無據。"]'),
('6545bfdd-b5f9-4908-90d9-a19088f171c1','錢倅生日','林宗放','宋','宋诗','song-poetry','','[]','煌煌我宋開鼇極，坐攬輿圖朝列辟。',224,'全唐诗/poet.song.174000.json','["煌煌我宋開鼇極，坐攬輿圖朝列辟。", "玉帛爭先萬國趨，吳越歸心天下一。", "聖神論報天與同，富貴不獨昌其躬。", "建隆以來二百載，是家與國方延洪。", "三光五嶽誰言裂，秀氣依然貫吳越。", "荀家苗裔何多龍，蕭氏衣冠知幾葉。", "賢王忠孝橫古今，文采到公仍映人。", "一段清冰出秋壑，笑言滿腹多精神。", "胸中色絲經緯密，華衮政須煩黼黻。", "會看玄髮映貂蟬，豈久銀章佩朱紱。", "轉頭玉樹森琳琅，渥洼之種俱顒昂。", "斑斑久矣伏藝苑，秋風忽起催騰驤。", "黄金鑄印大如斗，世世纍纍還繫肘。", "笑摩銅狄向他年，頗記淮山風月否。"]'),
('ecc329ab-4bbd-4ca3-af27-41f78417a93f','劇暑不可耐戲作冷語排之呈國威同舍兄','林宗放','宋','宋诗','song-poetry','','[]','雲師怒挾風伯狂，排山立海恣披猖。',152,'全唐诗/poet.song.174000.json','["雲師怒挾風伯狂，排山立海恣披猖。", "斯須委雪一丈强，殺氣吞日埋扶桑。", "平時身熱號炎荒，冰山亦復連穹蒼。", "翔風健兒材武良，墮指十五半在亡。", "巖谷不問殲虎狼，凍合瀛海蛟龍僵。", "蒼生似落冰蠶鄉，一氣如縷何可長。", "翻思蹈火勇赴湯，誰能排雲挈太陽，稍與萬物回精光。", "客來徵此疑荒唐，烏有先生投予方。", "端居炎赫汗反漿，試想幻境生清凉。"]'),
('19ea7871-a5ad-466d-8556-8800d981e426','餞使君','林宗放','宋','宋诗','song-poetry','','[]','始聽歌來暮，還聞說去思。',48,'全唐诗/poet.song.174000.json','["始聽歌來暮，還聞說去思。", "但知憂國計，那肯問家爲。", "跨竹兒童集，携書父子隨。", "謝城攀戀處，爭作畫圖披。"]'),
('eec6e704-45ba-486b-891c-d01e7ee03c44','贄奉使總領大卿','林宗放','宋','宋诗','song-poetry','','[]','昔賢兩手并擎天，鼇極功成勢晏然。',64,'全唐诗/poet.song.174000.json','["昔賢兩手并擎天，鼇極功成勢晏然。", "宗廟鼎彜刊祖烈，相門衣鉢付家傳。", "藍田種玉連連好，滄海遺珠顆顆圓。", "六合共知推晝錦，雲來重爲拂青氈。"]'),
('0f87d8c5-57a8-4aca-a0dd-a6e03ce21085','賀俞婺州除左史','林宗放','宋','宋诗','song-poetry','','[]','報政天邊美譽新，十行細札下嚴宸。',64,'全唐诗/poet.song.174000.json','["報政天邊美譽新，十行細札下嚴宸。", "逢人政爾詢司馬，從俗何由借寇恂。", "制勝萬全端有道，折衝一點是精神。", "向來魯國多男子，此日朝家特用真。"]'),
('364a0d6a-41c0-4c16-b4cc-4afc7ea2506d','次宣州太守韻  其一','林宗放','宋','宋诗','song-poetry','','[]','雙旌迎曉指林廬，五馬逢辰政得輿。',64,'全唐诗/poet.song.174000.json','["雙旌迎曉指林廬，五馬逢辰政得輿。", "西掖舊裁天子詔，名山今睹帝王書。", "胸中霽月何明甚，筆底清風更穆如。", "衮職還須補天手，徵黄那復更躊躇。"]'),
('429cf3c0-902b-44e9-a5b3-e31b8a32f7f3','次宣州太守韻  其二','林宗放','宋','宋诗','song-poetry','','[]','肯將苛政削民廬，好把寬仁答乘輿。',64,'全唐诗/poet.song.174000.json','["肯將苛政削民廬，好把寬仁答乘輿。", "襦袴賸誇今日富，春秋欣見有年書。", "門施水薤何須爾，庭卧桁楊只晏如。", "擬頌中和獻天子，鯫生無語却躊躇。"]'),
('9656cc5c-d144-4a9e-9703-65b32eae293a','和龔太守巡江回署之作','林宗放','宋','宋诗','song-poetry','','[]','防秋纔過又防春，帥守憂邊笑亦顰。',64,'全唐诗/poet.song.174000.json','["防秋纔過又防春，帥守憂邊笑亦顰。", "五馬去循江路穩，一帆回带雨潮新。", "知兵儒將功無敵，有道諸侯守在鄰。", "籌勝名樓瞻手澤，阿翁世業肯沉淪。"]'),
('a86d7f81-b720-4497-a4cb-472fafea21f5','食兔','林宗放','宋','宋诗','song-poetry','','[]','弱質司明視，虛名直望舒。',48,'全唐诗/poet.song.174000.json','["弱質司明視，虛名直望舒。", "軼群辭上蔡，能事到中書。", "狡計空多窟，珍盤竟付厨。", "獨將毫末效，曾紀汗青餘。"]'),
('9a5c3779-cdd8-4583-a31a-0f857f46bf58','會文昌宮','林宗放','宋','宋诗','song-poetry','','[]','文曜炳天府，司祿輔時雍。',96,'全唐诗/poet.song.174000.json','["文曜炳天府，司祿輔時雍。", "妥靈儼宮宇，垂光耀詞鋒。", "牲齊蠲穀旦，英髦翕來宗。", "桂旗降剡剡，瑶席瞻顒顒。", "克誠致昭享，受嘏欣滿容。", "賓筵列左右，旅觶歡橫縱。", "美矣席上珍，何異金在鎔。", "聯舉屬茲歲，青雲升九重。"]'),
('c2e0de3c-d3a2-43ef-aa89-1e1f40921c0c','賦應齋卷後','林宗放','宋','宋诗','song-poetry','','[]','軟紅塵裏獨君醒，拂袖歸來醉六經。',64,'全唐诗/poet.song.174000.json','["軟紅塵裏獨君醒，拂袖歸來醉六經。", "白雪陽春真寡和，高山流水要人聽。", "平生藝圃頭將白，依舊昭亭眼最青。", "莫問培風恣鵬運，只須隠几送鴻冥。"]'),
('c30384ce-8270-41c6-b385-9f651cb7856e','和府判給事登疊嶂樓喜雨韻','林宗放','宋','宋诗','song-poetry','','[]','風流不獨占才名，水鏡冰壺表裏清。',64,'全唐诗/poet.song.174000.json','["風流不獨占才名，水鏡冰壺表裏清。", "千里溪山娛暇日，一天風雨送秋聲。", "飽聆玉屑霏談麈，燦覩驪珠出管城。", "卧轍遮留能幾日，捲簾煙景若爲情。"]'),
('629e1869-30bd-4b78-8d60-3ed091dab3d3','陪郡守游西園','林宗放','宋','宋诗','song-poetry','','[]','倒影扶闌印碧溪，玻璃盤上玉東西。',64,'全唐诗/poet.song.174000.json','["倒影扶闌印碧溪，玻璃盤上玉東西。", "落紅那得愁如海，舉白難逃醉似泥。", "郎宿高明香霧起，客星華耀燭花低。", "波心夜半魚龍舞，都轉天風入鼓鼙。"]'),
('cf3e338d-e52c-47c8-86b6-01a9dbef5e89','北樓次韻','林宗放','宋','宋诗','song-poetry','','[]','浮空紫翠撲層臺，謝守吟窗一夜開。',64,'全唐诗/poet.song.174000.json','["浮空紫翠撲層臺，謝守吟窗一夜開。", "雲影四垂高捲□，□痕渾落淺膠杯。", "紅蓮綠水嘉簪盍，白鳥孤雲八句來。", "緩□笙歌下樓去，凉州重聽徹崔嵬。"]'),
('73572330-02e4-4283-a90e-24e5bdd3e9ea','題漱玉軒','楊祖堯','宋','宋诗','song-poetry','','[]','危石欲阽力自支，罅空引溜日夜垂。',160,'全唐诗/poet.song.174000.json','["危石欲阽力自支，罅空引溜日夜垂。", "空階滴雨幽夢覺，孤蓬澎浪驚魂飛。", "直疑丹液閟石骨，飲此合仙壽無期。", "又疑龍宮流潤澤，膏沐萬物皆含滋。", "終古不受一塵涴，六月可逃三伏威。", "濯我塵纓洗兩耳，審聽廣樂音聲希。", "盥頮半生塵俗面，要離仙仗翻雲旗。", "仁智所觀自有感，物理天理常參稽。", "華池神水倘若此，聖功合發天人機。", "湔滌衆生業障盡，更與大地蕩劫灰。"]'),
('e94109c2-d88f-4438-826d-f4992edf5f59','重建神秀樓追和忠定公韻','趙汝遇','宋','宋诗','song-poetry','','[]','峨峨城南樓，締創知幾時。',204,'全唐诗/poet.song.174000.json','["峨峨城南樓，締創知幾時。", "樓前中津水，潮來復潮歸。", "眷此雲海區，襟带東西溪。", "圖牒考往事，杳杳孤鴻飛。", "傳聞昔蕪城，陋若枳棘籬。", "鼎新頼宗衮，欲與千年期。", "紀事屬東萊，字字皆吾師。", "甲子甫一周，孫枝繼成規。", "壁壘訪遺蹟，闌干納餘暉。", "農隙既閒暇，溟波日平夷。", "班春布寬大，諭俗無澆漓。", "喬木有世臣，惟有乃似之。", "此段信奇事，今昨何是非。", "指顧舊觀還，略不煩文移。", "落成當元夜，月華流客衣。", "前作信高韻，新篇實英詞。", "却笑峴山語，登臨何足悲。"]'),
('896ba68d-0a63-4b66-9f89-51248d4c623e','木寂院','葉槐','宋','宋诗','song-poetry','','[]','爲愛蓮塘水石幽，畫橋斜日任遲留。',64,'全唐诗/poet.song.174000.json','["爲愛蓮塘水石幽，畫橋斜日任遲留。", "兩山雲出□□雨，一葉風來斷送秋。", "滾滾流年愁裏度，淒淒明月暗中投。", "何時谷口歸耕去，種得黄粱飽即休。"]'),
('904f3105-c684-45ef-845a-0aac5801f178','漳浦偶成','陳德翔','宋','宋诗','song-poetry','','[]','秋日已過半，林無一葉飛。',48,'全唐诗/poet.song.174000.json','["秋日已過半，林無一葉飛。", "曉嵐須闔戶，夜冷旋添衣。", "陰壑桄榔瘦，陽坡蓽撥肥。", "每傳鄰壤警，行客往來稀。"]'),
('be641e2a-f993-43fa-817f-df0cf7cc3407','和鄰僧韻','陳德翔','宋','宋诗','song-poetry','','[]','七八年來住水心，喜鄰蕭寺共僧吟。',64,'全唐诗/poet.song.174000.json','["七八年來住水心，喜鄰蕭寺共僧吟。", "古池暗有泉相接，春地從教笋自侵。", "興到濃時因坐久，交於淡處見情真。", "極憐對立河梁暮，海月初生日正沉。"]'),
('3b40cfc1-559c-471f-9557-e401bf9a152c','龜山','陳龜年','宋','宋诗','song-poetry','','[]','山是東南第一峰，長淮古汴渺連空。',32,'全唐诗/poet.song.174000.json','["山是東南第一峰，長淮古汴渺連空。", "登臨不是觀泉石，心折神皋指顧中。"]'),
('fa0f1f99-72f3-4d08-ba3a-eccf7ae21021','遊浄社寺','陳龜年','宋','宋诗','song-poetry','','[]','古寺何年斲，山空一片雲。',48,'全唐诗/poet.song.174000.json','["古寺何年斲，山空一片雲。", "喬松含晚翠，修竹洒清陰。", "老衲朝陽綴，雎鳩带雨吟。", "俗緣何日了，借榻浄塵心。"]'),
('798405a3-c22f-4713-8ec0-7004526f3224','浯溪','林伯成','宋','宋诗','song-poetry','','[]','讀時方喜能戡亂，責備猶疑過頌功。',32,'全唐诗/poet.song.174000.json','["讀時方喜能戡亂，責備猶疑過頌功。", "歸美縱來臣子事，誰歌宋德乃心同。"]'),
('5b88e370-e45f-4983-bb5d-63eb37f237d5','乘鸞峰','鄭訪','宋','宋诗','song-poetry','','[]','山形鸞羽族，仙子馭翱翔。',48,'全唐诗/poet.song.174000.json','["山形鸞羽族，仙子馭翱翔。", "琪樹烟霞冷，蓬壺日月長。", "來儀當日瑞，覽德應時祥。", "何處得環佩，乘遊入岳陽。"]'),
('cf54f20b-bf39-4a63-9267-97690bcb1517','元旦','何汝樵','宋','宋诗','song-poetry','','[]','臘盡寒猶厲，春來雪未乾。',48,'全唐诗/poet.song.174000.json','["臘盡寒猶厲，春來雪未乾。", "流年憐易失，爲客敢求安。", "故里屠蘇酒，新年柏葉盤。", "嗟哉老兄弟，誰與共清歡。"]'),
('628c79cc-0cc8-4b1d-bb95-f5fc11baad5f','句','張世英','宋','宋诗','song-poetry','','[]','霅溪深極地根清，四水交流激射聲。',16,'全唐诗/poet.song.174000.json','["霅溪深極地根清，四水交流激射聲。"]'),
('fa9bc4d1-f7e1-42c9-89b1-9e1a0c52faaa','過盱眙','張孝忠','宋','宋诗','song-poetry','','[]','淮海無波塞不塵，題詩因得弔遺民。',32,'全唐诗/poet.song.174000.json','["淮海無波塞不塵，題詩因得弔遺民。", "山河信美今戎索，耆老雖存亦外臣。"]'),
('2abb3621-5b99-4a28-bdb8-551235be556a','過峽','張孝忠','宋','宋诗','song-poetry','','[]','出入黄牛峽，江聲晝夜騰。',24,'全唐诗/poet.song.174000.json','["出入黄牛峽，江聲晝夜騰。", "猿啼愁不住，何日下彝陵。"]'),
('0e7db4c8-1bc5-4a7e-84c8-82f595014b26','輓呂東萊  其一','康文虎','宋','宋诗','song-poetry','','[]','中興以後誰堪數，名滿東南震昔賢。',64,'全唐诗/poet.song.174000.json','["中興以後誰堪數，名滿東南震昔賢。", "舊論當時存喘息，微波今日塞天淵。", "承平格力回全盛，人物風流繼往年。", "太息何人知所自，此心時復一潸然。"]'),
('d3e44b0a-40bd-4661-925c-14adec429f26','輓呂東萊  其二','康文虎','宋','宋诗','song-poetry','','[]','國尚有人悲此老，天其喪我泣吾曹。',64,'全唐诗/poet.song.174000.json','["國尚有人悲此老，天其喪我泣吾曹。", "平生心事知誰與，悵望今人論太高。", "便欲卑心隨故步，豈期中路喪連鼇。", "先生已死吾何望，舉眼猶知有鳳毛。"]'),
('595d0cac-f045-4219-865e-7dd374bc3df3','挽呂東萊  其一','唐季淵','宋','宋诗','song-poetry','','[]','方振河汾業，云胡不假年。',48,'全唐诗/poet.song.174000.json','["方振河汾業，云胡不假年。", "斯文今已喪，此道後誰傳。", "秘館藏新史，門人緝舊編。", "未明修短理，昂首問蒼天。"]'),
('84143edc-21c8-46a6-a5d4-3f0ac77e7344','挽呂東萊  其二','唐季淵','宋','宋诗','song-poetry','','[]','憶昔精藍舍，提撕意頗濃。',48,'全唐诗/poet.song.174000.json','["憶昔精藍舍，提撕意頗濃。", "笑談猶在耳，趨步遽無蹤。", "萬里悲風翮，中宵寤歲龍。", "百身嗟莫贖，涕淚灑寒松。"]'),
('33897764-69fc-4de7-9a9f-7effc0fbe726','挽東萊先生  其一','邵度','宋','宋诗','song-poetry','','[]','雨化三吳士，風行萬古書。',48,'全唐诗/poet.song.174000.json','["雨化三吳士，風行萬古書。", "石渠功不細，鳳閣位方虛。", "梁木何摧地，泉臺欲駕輿。", "來觀自燕者，頑懦亦欷歔。"]'),
('e4446ad8-84a3-4da9-8208-a389119c0219','挽東萊先生  其二','邵度','宋','宋诗','song-poetry','','[]','玉石明胸次，風雲在筆端。',48,'全唐诗/poet.song.174000.json','["玉石明胸次，風雲在筆端。", "教常先慷慨，門不棄蹣跚。", "籍湜疑培植，房陳似羽翰。", "中興依日月，遺像聖王歎。"]'),
('f182498d-18cc-4b9e-a6c0-784c5d175756','挽東萊先生  其三','邵度','宋','宋诗','song-poetry','','[]','岐嶷稱前輩，淵源便老成。',48,'全唐诗/poet.song.174000.json','["岐嶷稱前輩，淵源便老成。", "及門多兌說，在寢已蒙亨。", "麟筆空遺恨，箋詩正用情。", "誰知兩楹夢，湖海哭書生。"]'),
('a8361499-258a-4f9d-bba5-5ed1483f8698','挽東萊先生  其四','邵度','宋','宋诗','song-poetry','','[]','鼻祖雍熙政，三傳壽國醫。',48,'全唐诗/poet.song.174000.json','["鼻祖雍熙政，三傳壽國醫。", "至今稱巨室，有子號宗師。", "白璧埋黄壤，朱門罷素絲。", "脊令臨祖道，無計駐靈輀。"]'),
('8c148f2e-99dd-4569-8c12-8cf46db546ba','挽東萊先生  其五','邵度','宋','宋诗','song-poetry','','[]','名士聞風起，英聲逐電飛。',48,'全唐诗/poet.song.174000.json','["名士聞風起，英聲逐電飛。", "卜鄰譙子至，閑道洛人依。", "共歎斯人疾，何心入揖歸。", "七分書策在，馬鬣向斜暉。"]'),
('6c6d782b-230e-483a-84f1-556ad1d09eef','挽東萊先生  其六','邵度','宋','宋诗','song-poetry','','[]','鼓篋膠庠日，公方屬外艱。',48,'全唐诗/poet.song.174000.json','["鼓篋膠庠日，公方屬外艱。", "摳衣天不遇，攻玉理應難。", "問我好何學，逢人察所安。", "由今無拂士，孤陋入心酸。"]'),
('84c64efd-04e9-43fc-9903-5855804d6203','挽東萊先生','邵津','宋','宋诗','song-poetry','','[]','□□感易極，學成功未施。',48,'全唐诗/poet.song.174000.json','["□□感易極，學成功未施。", "彼蒼胡用問，吾黨竟誰資。", "道在漫今昨，人間忽喜悲。", "百年總埋玉，千古敬豐碑。"]'),
('3d89f3fc-5fdd-47ed-affd-5cc40538b273','挽東萊先生  其一','孟行古','宋','宋诗','song-poetry','','[]','道學方勤績，亨途漸致身。',48,'全唐诗/poet.song.174000.json','["道學方勤績，亨途漸致身。", "蒼天傾我淚，今日喪斯人。", "弟子群經富，先生一語真。", "發揮餘事業，何處不書紳。"]'),
('b64b82bc-fd34-49a5-a14e-4146d4835221','挽東萊先生  其二','孟行古','宋','宋诗','song-poetry','','[]','義路資開拓，愀然驚奠亡。',48,'全唐诗/poet.song.174000.json','["義路資開拓，愀然驚奠亡。", "吾儕自如失，夫子獨何傷。", "往日知鬷蔑，逢人傲子方。", "哭君心欲折，迥立向蒼蒼。"]'),
('b89abbe7-473c-43e5-ac42-4cb77eac4c3b','大滌洞天留題','孟行古','宋','宋诗','song-poetry','','[]','脫略囂塵處，清遊興已先。',48,'全唐诗/poet.song.174000.json','["脫略囂塵處，清遊興已先。", "人行九鎖路，洞引十洲仙。", "雲勢生山石，雷聲發澗泉。", "長吟動尊俎，林影月娟娟。"]'),
('9d4e1729-0a57-413c-bac0-3bdbf21a35e8','挽陳有功','朱黼','宋','宋诗','song-poetry','','[]','生平不肯負所學，高潔清風自凜如。',64,'全唐诗/poet.song.174000.json','["生平不肯負所學，高潔清風自凜如。", "逆孺殿巖辭特薦，暱交戚畹絕私書。", "不矜虜館穿正鵠，甘向蠻溪佩左魚。", "沅芷澧蘭香滿路，萬人慟哭護靈輿。"]'),
('3fd41e33-d94e-4275-b96e-64e28fe8abec','淳熙丁未初伏奉親避暑中巖  其一','楊光','宋','宋诗','song-poetry','','[]','伽陀坐斷碧巖陰，手眼無非利物心。',32,'全唐诗/poet.song.174000.json','["伽陀坐斷碧巖陰，手眼無非利物心。", "借我初庚滌袢暑，泠風美蔭木千尋。"]'),
('61c5132b-d39f-4035-ba3b-abf6d96ba6e6','淳熙丁未初伏奉親避暑中巖  其二','楊光','宋','宋诗','song-poetry','','[]','山下芙蕖雲錦裳，寶瓶浄供坐生涼。',32,'全唐诗/poet.song.174000.json','["山下芙蕖雲錦裳，寶瓶浄供坐生涼。", "南薰真是社中友，清潤時飄衣袂香。"]'),
('a3000204-d718-42a9-9332-c710ad92fe59','淳熙丁未初伏奉親避暑中巖  其三','楊光','宋','宋诗','song-poetry','','[]','禪榻陰森五月秋，井泉甘洌近林幽。',32,'全唐诗/poet.song.174000.json','["禪榻陰森五月秋，井泉甘洌近林幽。", "助翁燕坐清涼境，茶具隨行試一甌。"]'),
('22ef772b-a246-4e07-8e6e-1b977e586e8e','隠居鳳山清明寺  其一','樓淳','宋','宋诗','song-poetry','','[]','鳳鳥久不至，哲人歎已矣。',24,'全唐诗/poet.song.174000.json','["鳳鳥久不至，哲人歎已矣。", "空留千載名，寂寞殘陽裏。"]'),
('a980f762-e03d-46c3-9965-97a6c9c345d1','隠居鳳山清明寺  其二','樓淳','宋','宋诗','song-poetry','','[]','日上鐘未鳴，老僧睡猶熟。',24,'全唐诗/poet.song.174000.json','["日上鐘未鳴，老僧睡猶熟。", "誰是山中人，長享清明福。"]'),
('4c419aea-7a8d-41ae-af02-801a96fca575','清明寺','樓淳','宋','宋诗','song-poetry','','[]','風塵滿天下，此地獨清明。',24,'全唐诗/poet.song.174000.json','["風塵滿天下，此地獨清明。", "神州何處是，有淚落新亭。"]'),
('33c096b4-849a-4dbd-991b-877796ac1b9e','水國','鄭括蒼','宋','宋诗','song-poetry','','["\u897f\u6e56"]','水國煙霞客，春來始定居。',48,'全唐诗/poet.song.174000.json','["水國煙霞客，春來始定居。", "老逢人事懶，貧覺舊交疎。", "隙影窺蟾滴，芸香散篋書。", "西湖風月好，不到一年餘。"]'),
('6c0e7e7f-c02b-44d2-accb-e6950331c8bf','哭大愚呂公','汪大章','宋','宋诗','song-poetry','','[]','一封朝奏夕南遷，抖擻精神笑出關。',192,'全唐诗/poet.song.174000.json','["一封朝奏夕南遷，抖擻精神笑出關。", "只有詩書來眼底，更無儕輩敢通函。", "聖恩寬大時時降，天意難明特地慳。", "鬻藥買田非立異，甘心只作林泉計。", "所求於世如斯爾，造物云何降毒厲。", "嗟哉我公雖下世，萬古千秋未嘗逝。", "家庭學問誠難繼，我公超道獨能詣。", "日月有光還有翳，行人潸然咸出涕。", "嗟哉我公雖下世，萬古千秋未嘗逝。", "往年蒼天夭伯氏，歸咎云發千聖秘。", "遷客蕭寺獨羈寄，未知曷犯蒼天意。", "嗟哉我公雖下世，萬古千秋未嘗逝。"]'),
('62d09993-5b48-4a85-96a8-b16414d644cf','呈徐憲應特','陳應龍','宋','宋诗','song-poetry','','[]','弱冠弄筆硯，恥爲章句儒。',72,'全唐诗/poet.song.174000.json','["弱冠弄筆硯，恥爲章句儒。", "夜半劍氣發，精光射天衢。", "欲分天子憂，張燈閲地圖。", "七閩山水秀，我亦思故廬。", "世事苦齟齬，吾道甯躊躕。", "一官如涕唾，焉能輕重吾。"]'),
('284b45f1-7c64-47c8-a9e3-cbb459478d2b','九日南山','萬某','宋','宋诗','song-poetry','','[]','南山何峩峩，群峰秀色聚。',180,'全唐诗/poet.song.174000.json','["南山何峩峩，群峰秀色聚。", "朝暉與夕靄，無□□去住。", "徘徊九折險，縈曲一川注。", "懸崖置屋少，□穴亦可度。", "蒼然老楠木，幾閲風霜斁。", "孫枝長□許，老幹未肯仆。", "昔年重九日，來者必三顧。", "題詩刻峭壁，皆欲寄□□。", "念我獨何人，今日追故步。", "凌晨出南門，風雨怯行路。", "不憚登涉難，恐失此日故。", "造物亦隨人，晴明送日暮。", "徐行兩柏間，杯盤共草具。", "賓僚不鄙我，笑語露情愫。", "他時儻再來，莫指桃源誤。"]'),
('b4f0c381-d222-4c84-b7be-8eb0c14bc692','鄭氏館中書事','王介','宋','宋诗','song-poetry','','[]','今年移硯席，又上白雲邊。',48,'全唐诗/poet.song.174000.json','["今年移硯席，又上白雲邊。", "夜氣清於水，春愁薄似烟。", "庭前松已腦，門外柳應綿。", "尤喜安牀處，更深無杜鵑。"]'),
('f00dd2c7-90ac-43e9-89f2-5e065df1944a','句','楊介如','宋','宋诗','song-poetry','','[]','酒量春吞海，詩肩夜聳山。',12,'全唐诗/poet.song.174000.json','["酒量春吞海，詩肩夜聳山。"]'),
('79323cf2-8377-4c5c-b661-a70832643997','句','吳景','宋','宋诗','song-poetry','','[]','楚山連白帝，蜀道控烏蠻。',12,'全唐诗/poet.song.174000.json','["楚山連白帝，蜀道控烏蠻。"]'),
('2edbe3c4-d404-472a-a8f0-570d4732bd7f','題吳氏四賢堂  其一','羅鑑','宋','宋诗','song-poetry','','[]','河汾續經罷，洙泗還清風。',48,'全唐诗/poet.song.174000.json','["河汾續經罷，洙泗還清風。", "深衣大带垂，身退道則豐。", "一編通言在，萬古無盲聾。", "遺像今偉然，吾敬環溪公。"]'),
('f8a1e3ec-2cde-4dce-be14-cd10b6826de0','題吳氏四賢堂  其二','羅鑑','宋','宋诗','song-poetry','','[]','經濟學有用，寧與佔畢同。',48,'全唐诗/poet.song.174000.json','["經濟學有用，寧與佔畢同。", "集英晨唱第，夕對蓬萊宮。", "儒林急淵源，不遣朔庭空。", "遺像今偉然，吾敬國子公。"]'),
('33078a2f-cdd6-49ce-9dda-1356ed3ca682','題吳氏四賢堂  其三','羅鑑','宋','宋诗','song-poetry','','[]','中興洪韓呂，文章之鉅工。',48,'全唐诗/poet.song.174000.json','["中興洪韓呂，文章之鉅工。", "密年徧參請，一鏃直箭鋒。", "錦帳與畫戟，稽古似不蒙。", "遺像今偉然，吾敬吏部公。"]'),
('3b188e97-cdb5-4f94-9245-222ce9d914a4','題吳氏四賢堂  其四','羅鑑','宋','宋诗','song-poetry','','[]','敬齋一則話，傳自南軒翁。',48,'全唐诗/poet.song.174000.json','["敬齋一則話，傳自南軒翁。", "于湖金玉之，諸老歸下風。", "不使掌帝制，嗟哉吾道窮。", "遺像今偉然，吾敬司封公。"]'),
('6f8b9196-b502-4d38-8cca-1ca614ed8603','誚陳賈','淳熙太學生','宋','宋诗','song-poetry','','[]','周公大聖猶遭謗，伊洛名賢亦被譏。',32,'全唐诗/poet.song.174000.json','["周公大聖猶遭謗，伊洛名賢亦被譏。", "堪歎古今兩陳賈，如何專把聖賢非。"]'),
('ddf6827d-8c5e-49c0-b0c1-1b865a055613','和楊伯子','左次魏','宋','宋诗','song-poetry','','[]','鑾坡蓬監兩封書，道院東西各付渠。',32,'全唐诗/poet.song.174000.json','["鑾坡蓬監兩封書，道院東西各付渠。", "乾道聖人無固必，是非付與直哉魚。"]'),
('211b76d7-056d-4642-94e0-fbb512c031de','南中題壁','方武子','宋','宋诗','song-poetry','','[]','明月照齊州，玉龍棲欲起。',24,'全唐诗/poet.song.174000.json','["明月照齊州，玉龍棲欲起。", "壯士腸夜回，寒衾潑秋水。"]'),
('5c16242f-a6b7-4230-bd38-cb3064618a8e','題龍津亭','方武子','宋','宋诗','song-poetry','','[]','龍津亭下水漫漫，坐久凝神杳靄間。',32,'全唐诗/poet.song.174000.json','["龍津亭下水漫漫，坐久凝神杳靄間。", "說道浙江人不信，向南全似越州山。"]'),
('29971286-b745-4633-b096-3e04d90f549f','回憩翠蛟亭','孔元忠','宋','宋诗','song-poetry','','[]','引領籃輿上翠微，衆山回首覺平低。',64,'全唐诗/poet.song.174000.json','["引領籃輿上翠微，衆山回首覺平低。", "棲真洞口雲初合，大滌峰頭日未西。", "新笋暗抽穿木葉，古藤虬結跨沙堤。", "蛟亭雨後泉聲急，萬鼓喧豗擁澗蹊。"]'),
('7ce2e3d0-3c2c-408b-bda4-4f60abc5ccc4','春日即事二首  其一','蔡沆','宋','宋诗','song-poetry','','[]','人生何事最爲親，不看春容不識真。',64,'全唐诗/poet.song.174000.json','["人生何事最爲親，不看春容不識真。", "岸柳細摇多意思，野花初破足精神。", "精神識後施爲別，意思到時言語新。", "爲報同儕須急賞，莫教春去始傷春。"]'),
('f4be6224-d6ed-4127-b027-5934b6d5b68d','春日即事二首  其二','蔡沆','宋','宋诗','song-poetry','','[]','樓上從容曉日明，春風隨意動郊坰。',64,'全唐诗/poet.song.174000.json','["樓上從容曉日明，春風隨意動郊坰。", "定知有象根沖漠，未信至精惟杳冥。", "萬化淳時春藹藹，一元亨處雨零零。", "忘言共倚欄干曲，綠滿周原水滿汀。"]'),
('60a19d53-b226-4585-9833-4d72b1a9e86a','登高','蔡沆','宋','宋诗','song-poetry','','[]','九日登高廟閣陰，山間犬吠白雲深。',64,'全唐诗/poet.song.174000.json','["九日登高廟閣陰，山間犬吠白雲深。", "清秋空谷寒侵夜，繞屋幽林翠滿岑。", "佳景隨開陶令興，雅懷猶負遠公心。", "年來名利都拋却，唯有遊觀到處尋。"]'),
('45c8499b-c76d-4c12-ab03-e11dba473113','遊白鹿洞','蔡沆','宋','宋诗','song-poetry','','[]','古洞雲封山正陰，攀藤負石此登臨。',64,'全唐诗/poet.song.174000.json','["古洞雲封山正陰，攀藤負石此登臨。", "雙峰削劍雄中外，五老當頭壯古今。", "入室顒瞻先聖像，登臺慚愧昔時心。", "十年夢寐今方見，終老生涯只處尋。"]'),
('65dfdf68-dbf5-4e02-b4a2-139691e2b48c','坐龍池觀瀑布泉','蔡沆','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','一上巍峰獨枕流，匡山爽氣爲君收。',64,'全唐诗/poet.song.174000.json','["一上巍峰獨枕流，匡山爽氣爲君收。", "泉飛直下三千丈，池噴奔分數百州。", "浄練銀河輝映閣，煙凝碧樹吐成樓。", "先師巨筆懸崖石，文物風光度幾秋。"]'),
('593dab49-b4d9-4f6b-b607-48f9424f585f','遊西山','蔡沆','宋','宋诗','song-poetry','','[]','聞道西山勝，今朝始見山。',48,'全唐诗/poet.song.174000.json','["聞道西山勝，今朝始見山。", "鶴鳴雙劍動，龍噴紫霄寒。", "人去臺空古，墨灰沼未乾。", "紫陽招不作，登眺共誰看。"]'),
('4d58d3b9-b0c6-405b-93e0-145dbcb15506','自詠二首  其一','蔡沆','宋','宋诗','song-poetry','','[]','青春不可再，白髮兩三莖。',48,'全唐诗/poet.song.174000.json','["青春不可再，白髮兩三莖。", "得句非詩史，爲文學雅成。", "愁多憑酒散，老至逐人行。", "開卷無相似，長吁負此生。"]'),
('92a77223-d8e6-43c6-b60b-386245f57a31','自詠二首  其二','蔡沆','宋','宋诗','song-poetry','','[]','一病觀書歇，終朝藥餌親。',48,'全唐诗/poet.song.174000.json','["一病觀書歇，終朝藥餌親。", "焚香葆靜性，咬菜適清神。", "落燕巢低屋，饑烏噪近人。", "覓仙難換骨，貧瘦得吾真。"]'),
('8e19c949-6e79-464d-ac5d-db803cb5c5a0','閑遊','蔡沆','宋','宋诗','song-poetry','','[]','緩步荒郊外，杖藜看耨鋤。',48,'全唐诗/poet.song.174000.json','["緩步荒郊外，杖藜看耨鋤。", "蓑衣蒙短褐，野飯摘殘蔬。", "雨過苗花濕，雲深草樹疏。", "敲門無犬吠，何處覓樵漁。"]'),
('0a00d97c-fa5e-4e9d-8313-6f08df7efb35','夜行舟','蔡沆','宋','宋诗','song-poetry','','[]','霞晚臨江岸，雲深不見星。',48,'全唐诗/poet.song.174000.json','["霞晚臨江岸，雲深不見星。", "鳥棲沙篆暗，山遠暮鐘鳴。", "燃火移村色，號風晚度聲。", "船窗迷漏鼓，獨立向天明。"]'),
('d37805ba-7491-4df3-a078-54b271431131','示兒','洪鉞','宋','宋诗','song-poetry','','[]','豫章實佳木，尋丈早異衆。',240,'全唐诗/poet.song.174000.json','["豫章實佳木，尋丈早異衆。", "匠石雖未顧，終解作梁棟。", "社櫟大蔽牛，不資世所用。", "棄置成散材，歲久即空洞。", "誠由天所産，亦在德者種。", "吾兒豫章流，丱角不好弄。", "經訓雖未通，數過輒成誦。", "只今十五六，舉止頗持重。", "仰頼師友功，綴緝成賦頌。", "積絲未盈尺，粗喜入機綜。", "胡爲不自量，將使應鄉貢。", "文場倍千數，作者豈倖中。", "而子於其間，燕雀雜鸞鳳。", "鉛刀未易割，庶可供一鬨。", "造物果何如，往往形吉夢。", "天其助我心，勿使汝放縱。", "業貴精于勤，耐取曉窗凍。", "文章實公器，妙語世人共。", "歲朝哦此詩，洗醆揭春甕。", "吾家有陰德，行矣光炎宋。"]'),
('38241c1d-3151-4002-95b8-1fe5ead078f2','和兒咨夔夜坐韻','洪鉞','宋','宋诗','song-poetry','','[]','樓底雪千峰，樓頭著寓翁。',48,'全唐诗/poet.song.174000.json','["樓底雪千峰，樓頭著寓翁。", "梅方開萼綠，桃已亞枝紅。", "斟淺偏勞勸，眠遲不受烘。", "錦城春在眼，何暇問蠶叢。"]'),
('55338b4c-d673-4f99-b16b-c1435336ca12','送時漕大卿淮西檢法  其一','崔與之','宋','宋诗','song-poetry','','[]','卿月高華照楚墟，澄清雅意見登車。',64,'全唐诗/poet.song.174000.json','["卿月高華照楚墟，澄清雅意見登車。", "星分屯壘雲中戍，風引艅艎塞下儲。", "十二聚民行惠政，三千議獄謹刑書。", "最聲烜赫流聰纊，聖詔今朝下玉除。"]'),
('309522bc-18b0-4f50-b24e-0b6dfc7af33e','送時漕大卿淮西檢法  其二','崔與之','宋','宋诗','song-poetry','','[]','越山輝映繡衣鮮，屈指重來是幾年。',64,'全唐诗/poet.song.174000.json','["越山輝映繡衣鮮，屈指重來是幾年。", "濡轡按行方易地，追鋒趣召已朝天。", "步趨接武星辰上，獻納依光日月邊。", "到得中流須砥柱，功名事業要雙全。"]'),
('71f87299-263a-4d5f-9829-cfc8d07db506','送時漕大卿淮西檢法  其三','崔與之','宋','宋诗','song-poetry','','[]','十年宦海任飄零，豈料光華伴使星。',64,'全唐诗/poet.song.174000.json','["十年宦海任飄零，豈料光華伴使星。", "落魄半生頭已白，爬沙一見眼長青。", "天涯明月方依樹，淮上長風忽散萍。", "別淚誰能效兒女，不堪官柳暗長亭。"]'),
('df9391d4-97a9-4bc8-a155-47559e7240cb','壽李參政壁','崔與之','宋','宋诗','song-poetry','','[]','青牛老仙紫雲旄，函關西度天風高。',240,'全唐诗/poet.song.174000.json','["青牛老仙紫雲旄，函關西度天風高。", "手携柱下五千卷，來擅一世文章豪。", "玻璃江頭梅欲蕾，蟆頤山麓寒方鏖。", "飈車羽輪下霄漢，從以萬鶴如雲濤。", "參天挺特有喬木，大地負荷須巨鼇。", "百斛篆鼎筆端斡，五色瑞繭胸底繅。", "笑談更化定大計，乾機坤軸回鈞陶。", "蒼生脫險誕登岸，沙觜閑此杭川艘。", "雁湖風物午橋似，滿引鑿落歌離騷。", "酒酣耳熱自擊缶，世閒萬事輕鴻毛。", "塗炭未蘇兵未洗，雲雷可使屯其膏。", "玉堂昨夜進麻草，延英趣對猩紅袍。", "太平事業有所屬，北卷燕薊西臨洮。", "扶持世極壽國脈，突兀一柱擎天牢。", "五羊僊客起爲壽，安期大棗東方桃。"]'),
('3d7968f3-de45-484d-911e-6a59ff8cd3c9','壽邕州趙守','崔與之','宋','宋诗','song-poetry','','[]','大厦開朱明，物態豐且碩。',288,'全唐诗/poet.song.174000.json','["大厦開朱明，物態豐且碩。", "薰絃發新奏，生意轉無極。", "間氣清而和，融結賦有德。", "碧梧挺幽榦，曠度漫九澤。", "富哉學古胸，仁義供服食。", "渾樸希世珍，外溫而內直。", "驊騮開道路，聲光日斯赫。", "九關通籍初，南來墜雙舄。", "片心清徹底，杯水餞泥軾。", "京兆入幕賓，去天不盈尺。", "佳最入聰纊，行行陟文石。", "邕爲五管雄，地控西南域。", "專閫難其人，弄印無以易。", "袖却經綸手，天邊樹牙戟。", "猩獠叢篁中，深棲而屏息。", "夜月照銅柱，警囊聲寂寂。", "邊人解带卧，危地成樂國。", "屏風御墨鮮，早晚來召驛。", "媿我樸樕才，潦霧甘遠役。", "題坐遇知己，孤根費培植。", "崧高生申甫，好語諠井陌。", "碧油塞雲端，阻莫陪賀客。", "歌詠淇奧詩，清脩如圭璧。", "他年玉班頭，蒼髯而赤黻。"]'),
('c2ac1af2-35c3-49f2-be29-dd41e75c67dd','張進武善風鑑謂予豸骨日聳早晚入臺求詩贈之  其一','崔與之','宋','宋诗','song-poetry','','[]','熒熒碧眼照人寒，一別重逢歲又殘。',64,'全唐诗/poet.song.174000.json','["熒熒碧眼照人寒，一別重逢歲又殘。", "老去但求閒處樂，君來尚作向時看。", "誰將伏豸夸顱骨，我有盟鷗託肺肝。", "坎止流行隨所遇，何須覓夢到邯鄲。"]'),
('68afaa47-c31e-4956-81dc-4baed1f537de','張進武善風鑑謂予豸骨日聳早晚入臺求詩贈之  其二','崔與之','宋','宋诗','song-poetry','','[]','瘦插秋山聳兩肩，荒寥不直半文錢。',64,'全唐诗/poet.song.174000.json','["瘦插秋山聳兩肩，荒寥不直半文錢。", "孤山放鶴林和靖，風雪騎馿孟浩然。", "萬事轉頭渾是夢，一身安分總由天。", "煩君束起前途事，我欲滄江買釣船。"]'),
('462b6795-4e5d-4a34-b5fe-cac202cb8b4c','題吉水黿潭李氏仁壽堂','崔與之','宋','宋诗','song-poetry','','[]','拙直多忤物，孤根徒自危。',288,'全唐诗/poet.song.174000.json','["拙直多忤物，孤根徒自危。", "祈閑三扣閽，天遠不我知。", "尺書趣入覲，君命其可違。", "火雲正燒空，短篷氣如炊。", "脩途久困頓，病骨尤支離。", "奄奄尚殘息，艤棹江之湄。", "來登三元山，炎歊頓無威。", "徘徊古亭上，好風吹客衣。", "聊爲三日留，食斯眠於斯。", "澗泉㶁㶁鳴，四山翠屏圍。", "夜深松桂寒，朝瀣生林霏。", "李君亦達士，與我真忘機。", "乃於山之巔，預作佳城基。", "生則此其樂，死則此其歸。", "採藥求長年，華髮世所希。", "荷鍤欲自埋，不以遺體爲。", "要皆非中道，識者之所嗤。", "知命故不憂，李君其庶幾。", "觸目此境界，陡悟昔者非。", "更作首丘想，行色應遲遲。", "還遊仁壽菴，細玩淵明詩。", "寓形復幾時，皇皇欲何之。", "富貴非吾願，帝鄉不可期。", "自憐一身孤，蒲柳先秋衰。"]'),
('70001e04-14d8-4bcd-8580-5c82555a84a8','送聶侍郎子述  其一','崔與之','宋','宋诗','song-poetry','','[]','碧幢紅旆白貂裘，去踏西風萬里秋。',64,'全唐诗/poet.song.175000.json','["碧幢紅旆白貂裘，去踏西風萬里秋。", "要得處方醫壞證，便須投矢負全籌。", "百年機會真難遇，一線光陰更易流。", "早辦出師諸葛表，祁山斜谷鬰綢繆。"]'),
('77c623a8-9754-4c02-8d95-00185c026b8c','送聶侍郎子述  其二','崔與之','宋','宋诗','song-poetry','','[]','吳蜀相通一水長，聞公西土意差彊。',64,'全唐诗/poet.song.175000.json','["吳蜀相通一水長，聞公西土意差彊。", "人謀合處天心順，民力寬時國勢張。", "參井光芒摇戟纛，關河事業耀旂常。", "雪山自是西人重，赤舄歸來早趣裝。"]'),
('f305a096-1cc4-4213-b7f0-238b947f0e1f','揚州官滿辭后土題玉立亭','崔與之','宋','宋诗','song-poetry','','[]','天上人間一樹花，五年於此駐高牙。',64,'全唐诗/poet.song.175000.json','["天上人間一樹花，五年於此駐高牙。", "不隨紅藥矜春色，爲愛霜筠耐歲華。", "四塞風沈天籟寂，半庭月冷市塵賒。", "臨行更致平安祝，一炷清香十萬家。"]'),
('f6955a05-ef71-49af-ba9d-49c822fd9d20','嘉定甲戌正月以金部郎分閫東淮正當金虜棄巢南奔之時人不願往以君命不敢辭首尾五年而不得代戊寅臘月以少蓬召而病且衰矣自知不堪世用决意南歸舟次豫章三疏丐閑而不得請幡然東下艤棹南康重湖閣夜夢人告之曰死於廬山之下覺而識其事并以小詩謝山神','崔與之','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','來到廬山日日陰，斜風細雨亂雲深。',64,'全唐诗/poet.song.175000.json','["來到廬山日日陰，斜風細雨亂雲深。", "移舟夜壑人閒世，荷鍤春郊物外心。", "要把封疆安社稷，誰教軒冕換山林。", "殷勤招隠知深意，五老朝來露玉簪。"]'),
('d022e7e2-4870-4210-bbb7-1d5aa647bcf5','送袁校書赴湖州別駕','崔與之','宋','宋诗','song-poetry','','[]','奎壁光芒久聚東，奏篇入獻大明宮。',192,'全唐诗/poet.song.175000.json','["奎壁光芒久聚東，奏篇入獻大明宮。", "胸中抱負經綸業，筆下鋪張造化功。", "四海高名如日揭，一襟和氣與春融。", "誰知正大傳家學，惟有擎拳體國忠。", "華踐峻登羣玉表，清脩屹立急流中。", "校讐正對青藜月，關陝俄分畫戟風。", "自喜合簪方衮衮，不堪分袂大怱怱。", "送君悵望雲帆別，顧我凋殘雪鬢蓬。", "戢羽孤棲憐鶴病，脫身高舉羨冥鴻。", "星躔已應魁三象，天路須知尺五通。", "箬水臘前新蟻綠，橘洲霜後巨螯紅。", "清談岸幘聊遊戲，獻納歸班萬口同。"]'),
('9d9f940a-c472-4b12-a343-20b5af2db6bd','柴祕書分符章貢同舍餞別用蔡君謨世閒萬事皆塵土留取功名久遠看之句分韻賦詩得世字','崔與之','宋','宋诗','song-poetry','','[]','玉立蓬山巔，聲望高一世。',228,'全唐诗/poet.song.175000.json','["玉立蓬山巔，聲望高一世。", "清秋玉壺露，耿耿無纖翳。", "中流屹砥柱，愈激而愈厲。", "平生學古胸，非爲資身計。", "中邊事方殷，命脈實關繫。", "憂世危明主，誰流洛陽涕。", "直諫逆批鱗，言言皆獻替。", "胡爲厭承明，退飛勇且銳。", "有山鬰而孤，雄踞虎頭勢。", "兆民困科擾，椎剝已無藝。", "猩獠叢篁中，跳梁無虛歲。", "弄印無以易，要起百年弊。", "西風吹馬耳，新涼雨初霽。", "尺劄聞先聲，遠氓已懷惠。", "旌旗簇小隊，畫戟森兵衛。", "一方覆盂安，中原誰共濟。", "顧我亦漫仕，空山老松桂。", "倦悔作歸夢，乞身尚濡滯。", "著鞭公已先，脂秣以相繼。"]'),
('ed7428e5-7a69-4b53-afc3-56b095f71314','陳祕書分符星渚同舍餞別用杜甫老手便劇郡之句分韻賦詩得老字','崔與之','宋','宋诗','song-poetry','','[]','天生一代奇，人瑞國之寶。',144,'全唐诗/poet.song.175000.json','["天生一代奇，人瑞國之寶。", "少游翰墨場，聲譽日杲杲。", "蟠胸三萬卷，致君應有道。", "懷璧掩其光，幾書州縣考。", "翩翩鳳新雛，飛上羣玉島。", "郎星粲光躔，同舍未爲老。", "自詭乘一障，決計何太早。", "分以星子符，廬阜足幽討。", "榮途競奔逐，砥柱迴瀾倒。", "自顧孤危蹤，歸意尤浩浩。", "白頭頻送客，何以慰離抱。", "江頭潮正平，西風一帆好。"]'),
('317d7a5f-2239-479a-9863-df50e2eb86db','危大著出守潮陽同舍餞別用杜工部北風隨爽氣南斗近文星分韻賦詩得北字','崔與之','宋','宋诗','song-poetry','','[]','天地清淑氣，人才隨所得。',192,'全唐诗/poet.song.175000.json','["天地清淑氣，人才隨所得。", "君獨稟其全，濟之以學力。", "蒼皮四十圍，直幹二百尺。", "填胸書萬卷，絢采雲五色。", "清和閒韶濩，勁直沮金石。", "間氣之所鍾，表表才稱德。", "韞藏不自衒，況復耐官職。", "頹波正流靡，不濡而不激。", "平生憂國心，一語三歎息。", "著庭史筆健，寒芒照東壁。", "畫省方翺翔，忽厭青綾直。", "揭陽落天南，自詭何太嗇。", "東風吹馬耳，芻秣甘遠役。", "時事棼如絲，宵衣尚顧北。", "袖藏醫國方，何以壽其脈。", "行行無疾驅，有詔且前席。"]'),
('b59d9147-f756-428c-b01c-81e02816e6e9','張祕書分符星渚同舍餞別用山谷晚風池蓮香度曉日宮槐影西分韻賦詩得晚字','崔與之','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','堂堂間世英，大名赫而烜。',180,'全唐诗/poet.song.175000.json','["堂堂間世英，大名赫而烜。", "全才得之天，學力培其本。", "孤高壁萬仞，清郁蘭九畹。", "胸中富甲兵，馳驟菁華苑。", "文武康濟才，孤忠尤蹇蹇。", "入可運籌幄，出可臨邊閫。", "自許何太廉，一麾江湖遠。", "我來陪雋游，方恨合并晚。", "盍簪遽分袂，此情殊繾綣。", "高牙奉親行，天涼綵輿穩。", "廬山橫几案，道院庶嘉遯。", "金弧夜騰光，三邊兵未偃。", "豈不念王室，罄此忠赤悃。", "當饋屢興歎，追鋒必于反。", "江梅小春時，斑衣照歸衮。"]'),
('82aaf60a-b2b1-478a-bd64-eaa647968be8','李大著赴豫章別駕同舍餞別用杜工部天上秋期近人閒月影清之句分韻賦詩得天字','崔與之','宋','宋诗','song-poetry','','[]','精神烱烱一癯仙，弭筆蓬萊最上顛。',64,'全唐诗/poet.song.175000.json','["精神烱烱一癯仙，弭筆蓬萊最上顛。", "光大聲名揭如日，老臣議論可回天。", "星辰直上亨衢穩，風月平分去意堅。", "愧我衰顔歸未得，兩旬三作送行篇。"]'),
('d51b0b42-f8da-4930-a6cf-34669046b8b8','嘉定庚辰正月二日楊尚書率同年團拜于西湖因爲遊湖之集適湖水四合乘興鑿冰泛舟如所約也杜侍郎賦詩和之','崔與之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雪裏同騎白玉鼇，湖山人物一時高。',64,'全唐诗/poet.song.175000.json','["雪裏同騎白玉鼇，湖山人物一時高。", "銀潢下瀉波千頃，寶鑑旁開水半篙。", "我欲乘風驚老大，誰將翦水戲兒曹。", "梅花紙帳扁舟夢，但覺歸心長羽毛。"]'),
('0140f906-7539-4a48-9ab6-7a444268fe1c','答李侍郎嘉定庚辰冬之官成都至城外驛侍郎亦赴鎮常得相遇于道惠詩答之','崔與之','宋','宋诗','song-poetry','','[]','柏竹老歲寒，梅礬澹春風。',192,'全唐诗/poet.song.175000.json','["柏竹老歲寒，梅礬澹春風。", "邂逅萬里橋，相對雙鬢蓬。", "論心豈無酒，舉盞不忍空。", "恐渠道旁嗤，咄咄醉頰紅。", "送以靜觀頤，答以晦養蒙。", "障塵馬上去，意氣如飛鴻。", "荆州舊分虎，武陵世憑熊。", "所至相勞苦，父老携兒童。", "地偏舞袖長，雞脊牛鼎豐。", "甘棠子孫枝，蒙密成芳叢。", "聞之白玉堂，起草誰其工。", "要爲官擇人，頗牧還禁中。", "胸藏經濟方，醫國收全功。", "世事俱塵土，惟有汗竹公。", "雨足芎茁苗，風暖蒲長茸。", "離索抱孤影，目斷三峽東。"]'),
('fe3b915f-65db-4498-b997-56ff6e8be6a8','寄黄州趙別駕庚辰入蜀舟次黄岡適趙倅奇夫沿檄行邊不遇以詩寄之','崔與之','宋','宋诗','song-poetry','','[]','銅梁玉壘碧雲端，尺舸西風兩鬢殘。',64,'全唐诗/poet.song.175000.json','["銅梁玉壘碧雲端，尺舸西風兩鬢殘。", "世道多岐今已慣，人生一見古來難。", "丈夫不作謀身計，巧匠那能袖手看。", "月白風清雪堂夢，銀波萬頃卧龍寒。"]'),
('c86b3fd1-d9be-4ea8-8ef7-2bfede6164b0','送魏祕書赴召  其一','崔與之','宋','宋诗','song-poetry','','[]','萬里脩門道，誰傳桂子來。',48,'全唐诗/poet.song.175000.json','["萬里脩門道，誰傳桂子來。", "好將真積力，爲作太平媒。", "大易機緘露，中庸氣脈回。", "須知經濟學，元不墮秦灰。"]'),
('0ee690b1-7f38-47f5-a751-8cbbbe9aeaa3','送魏祕書赴召  其二','崔與之','宋','宋诗','song-poetry','','[]','國論參稽定，人材護養成。',48,'全唐诗/poet.song.175000.json','["國論參稽定，人材護養成。", "古來同此恨，老去向誰傾。", "太白雲猶溼，瞿塘水正生。", "掛帆干斗極，屬耳鳳凰鳴。"]'),
('502940a1-1741-4b38-a1ad-b006c61eb6ec','送夔門丁帥赴召  其一','崔與之','宋','宋诗','song-poetry','','[]','憶昔捫三峽，班荆擁暮寒。',48,'全唐诗/poet.song.175000.json','["憶昔捫三峽，班荆擁暮寒。", "宦情雙鬢底，世事兩眉端。", "壞證扶須力，危機發更難。", "胸中經濟學，爲國好加餐。"]'),
('4542449e-8526-4267-b426-0697f874e7d6','送夔門丁帥赴召  其二','崔與之','宋','宋诗','song-poetry','','[]','議論方前席，功名早上坡。',48,'全唐诗/poet.song.175000.json','["議論方前席，功名早上坡。", "去帆瓜蔓水，遺愛竹枝歌。", "同志晨星少，孤愁暮雨多。", "倚風窮望眼，碧色渺平莎。"]'),
('52185e47-f686-4e9b-987b-ec39fe2e3179','送成嘉父','崔與之','宋','宋诗','song-poetry','','[]','諸老不敢吏，我來容友之。',48,'全唐诗/poet.song.175000.json','["諸老不敢吏，我來容友之。", "調高械夏曲，局熟弈秋棋。", "南斗捩船柁，西風吹鬢絲。", "莫將金玉質，膏沐畫長眉。"]'),
('4b2d137e-8c51-4bbc-849b-244bb294ff33','送范漕赴召  其一','崔與之','宋','宋诗','song-poetry','','[]','汲古千尋綆，通今八面窗。',48,'全唐诗/poet.song.175000.json','["汲古千尋綆，通今八面窗。", "相逢俱氣許，未語已心降。", "分鎮中邊蜀，歸途內外江。", "禁城風雨夜，應念鹿門龐。"]'),
('19f7da23-9373-4fe4-a8f8-ba0f0e0500e7','送范漕赴召  其二','崔與之','宋','宋诗','song-poetry','','[]','棋於觀局易，藥到處方難。',48,'全唐诗/poet.song.175000.json','["棋於觀局易，藥到處方難。", "休戚君眉睫，安危我肺肝。", "別來年事晚，病起面華寒。", "東望彊人意，天風送健翰。"]'),
('ff1ea469-dc74-41a0-8816-2b4c80333ae9','送洪暘巖赴班','崔與之','宋','宋诗','song-poetry','','[]','法吏了繁劇，儒生擅文墨。',288,'全唐诗/poet.song.175000.json','["法吏了繁劇，儒生擅文墨。", "世多兼兩長，遠到須器識。", "昔在晉魏公，曾此趨幕職。", "一逢龔莊敏，期以柱天極。", "紫微得夫君，嘉禾乏栽植。", "廣城底山川，融結此英特。", "精神天獨饒，醉盎春可即。", "讀書細妍磨，作文工組織。", "庭隅立兩造，片言分曲直。", "疾頑戒已甚，爭事退如默。", "武庫物兼蓄，滄海蠡莫測。", "同僚總稱好，載路譽聲塞。", "五羊書筵重，濟物多陰德。", "榮通付儻來，薦剡豈求得。", "薰涼快馬耳，汗漫捧鵬翼。", "歸裝可對人，南物毫不殖。", "二同羞著我，握手倒巾幘。", "幽棲泉石邊，喜在文溪側。", "平章詩浩蕩，指點碁黑白。", "此樂竟何如，滿懷春拍拍。", "咳唾落珠璣，襟期重膠漆。", "高誦歸去辭，永守兔園冊。", "焉知暮歲後，苦被功名迫。", "終能幡然起，行矣各努力。"]'),
('e1e0da26-28e6-458c-98fc-7cc0ab5a4ce7','嘉定甲申以禮部尚書得請便道還家作此詩','崔與之','宋','宋诗','song-poetry','','[]','九重天上別龍顔，萬里江南衣錦還。',64,'全唐诗/poet.song.175000.json','["九重天上別龍顔，萬里江南衣錦還。", "聖主有憐雙鬢白，老臣長抱寸心丹。", "短篷疎雨春聽浪，瘦馬輕寒曉度關。", "何處好尋幽隠地，長松流水白雲閒。"]'),
('d4d6f8bd-74b1-4fec-9cfb-9073a68c84bb','金精山','崔與之','宋','宋诗','song-poetry','','[]','翠壁丹崖倚碧穹，一壺天地畫圖中。',64,'全唐诗/poet.song.175000.json','["翠壁丹崖倚碧穹，一壺天地畫圖中。", "青鸞有路三山遠，玉洞無塵萬慮空。", "虛室尚留丹竈冷，靈泉直與海波通。", "客遊到此應忘返，始覺仙凡迥不同。"]'),
('ea514938-22ec-4115-bcb4-0aa81686f094','哭趙清之  其一','崔與之','宋','宋诗','song-poetry','','[]','天南□□□重臨，遺愛猶存蔽□陰。',64,'全唐诗/poet.song.175000.json','["天南□□□重臨，遺愛猶存蔽□陰。", "鼓角三城新令肅，袴襦萬井舊恩深。", "養民但積和平福，涖事常持敬簡心。", "遠業設施殊未老，巨川東逝日西沉。"]'),
('a6eb983e-df2e-473a-a1f0-f815eb05bde7','哭趙清之  其二','崔與之','宋','宋诗','song-poetry','','[]','老來心事向誰論，每見移時話肺肝。',64,'全唐诗/poet.song.175000.json','["老來心事向誰論，每見移時話肺肝。", "黄甲同登今有幾，白頭相對古來難。", "死生轉盼星辰墜，聚散酸心幕雨寒。", "病裏不堪聞楚些，海山望斷淚汍瀾。"]'),
('46f2a07a-8887-4054-8755-0ebff4dd6a9e','峽山飛來寺','崔與之','宋','宋诗','song-poetry','','[]','萬里星槎海上旋，名山今喜得攀援。',64,'全唐诗/poet.song.175000.json','["萬里星槎海上旋，名山今喜得攀援。", "猿揮孫恪千年淚，月照維摩半夜禪。", "磴長荒苔人跡少，崖攢古樹鵲巢懸。", "江流上溯曹溪水，時送鐘聲到寺前。"]'),
('20a4a633-1dfb-4667-b579-40ecaf5e4228','季春','周南','宋','宋诗','song-poetry','','[]','初篁欲迸籜，晚風微過之。',72,'全唐诗/poet.song.175000.json','["初篁欲迸籜，晚風微過之。", "斑苞初委地，永與琅玕辭。", "篁生五丈高，鳳吹鳴參差。", "隕籜膜已朽，不恨見竹遲。", "物成亦大艱，搔絕誰當奇。", "誓同初生竹，長護幽貞姿。"]'),
('98bc7b31-cdf2-439c-8bd1-59b95c9b6286','暮春','周南','宋','宋诗','song-poetry','','[]','茲辰如翻車，其行靡脫轂。',60,'全唐诗/poet.song.175000.json','["茲辰如翻車，其行靡脫轂。", "春無十日妍，見此條蔓綠。", "蒼苔拾落花，天膏尚如沐。", "足身豈不好，反覆看已熟。", "惟有白石子，粲粲菖蒲斛。"]'),
('039aa65d-df8a-4b1b-b14b-8ba01f3b1035','八月七日與吳沈二道人同過書塢時山堂初成','周南','宋','宋诗','song-poetry','','[]','暋陽收晶熒，清舫度林彙。',156,'全唐诗/poet.song.175000.json','["暋陽收晶熒，清舫度林彙。", "坡陀認槿籬，屋角初塗塈。", "入門露蔭竹，走鞭土爲沸。", "橘欒尚小澀，菊柄已幽毅。", "少紓趺坐筋，漸出穹隙味。", "疎叢石貞瘦，密樾塵髣髴。", "成余獨往願，勞我慈親費。", "親年合幾何，倏已近喜畏。", "我髮白滿把，晚食遲下胃。", "一歲能幾來，每來時自慰。", "不雨已經旬，長道熠饑蜚。", "竹檐出山泉，草根坌土氣。", "長願居此勞，州里未爲貴。"]'),
('29e1232a-28fb-4788-9159-6d54d0701dd0','咏史','周南','宋','宋诗','song-poetry','','[]','客嬰義主臣，銷骨事未竟。',96,'全唐诗/poet.song.175000.json','["客嬰義主臣，銷骨事未竟。", "臼友讎諾責，斯義在項領。", "惟臼秉純心，遑恤身後事。", "惟嬰抱遺育，不以後死愧。", "嗟乎古人達，樹德見衷則。", "並驅不同逵，存歿事願畢。", "茲事亦大難，義竭斯近仁。", "孤成死不死，太息難重陳。"]'),
('73cd31e0-4ec4-4ab4-9301-60c4424713e1','博雞','周南','宋','宋诗','song-poetry','','[]','慶元夏四月，所至喧博雞。',288,'全唐诗/poet.song.175000.json','["慶元夏四月，所至喧博雞。", "小市車不通，引首望其逵。", "雞籠三尺高，雞價千錢提。", "苦云輸錢少，取取鬭樣歸。", "小兒博手短，顛走歌呼齊。", "搜携遍村墅，往往空其棲。", "或買鵝代之，亦取雞爲辭。", "僕夫告我言，官人那未知。", "聚呶已跨日，來初知爲誰。", "余無五行學，覺有纖芥疑。", "老距不可臛，利觜長安施。", "更訝十錢片，一博多得之。", "歸尋故老問，始云眼見希。", "因之互猜愕，傳來又夸毗。", "或謂近雞禍，或言雞者饑。", "歲行將在酉，事應恐在茲。", "聖明攸好德，百祲潛光輝。", "蠢茲朱衣者，萬萬不關時。", "但疑一種類，爭雄無兼雌。", "更恐坊市內，相望野雞啼。", "豈將有微沴，神者預啟其。", "乖風感乖氣，朗鑒尚表微。", "人言良過矣，邦禁亦未非。", "我欲效風人，聊賦博雞詩。"]'),
('89f47c3a-0b91-4b4b-b6de-c228f9e3126e','呈趙蹈中','周南','宋','宋诗','song-poetry','','[]','趙子面白如玉傞，定須逃得文儒餓。',160,'全唐诗/poet.song.175000.json','["趙子面白如玉傞，定須逃得文儒餓。", "經年憶破古人心，近日妹夫初病可。", "忽然到門已驚駭，令我失喜多兩拜。", "君來看我還看親，我顧不能君莫怪。", "自云曾見杭州火，說著紅湖先淚墮。", "水衡支散新鑄錢，詔書未御正朝坐。", "向來送我龍泉器，秋色新蔬恰相似。", "且將濁酒慰營魂，多留幾日論文字。", "取詩須取杜正傳，尋到岑參高適邊。", "轉處正須寬一步，只今且向晚唐前。"]'),
('a615126a-5692-4b24-9f48-bb825536f582','卓文君','周南','宋','宋诗','song-poetry','','[]','曠代佳人十六七，膚如凝脂髮抹漆。',192,'全唐诗/poet.song.175000.json','["曠代佳人十六七，膚如凝脂髮抹漆。", "芙蓉爲臉玉爲容，淡拂眉尖遠山色。", "夜梧月落秋夜長，孤鸞三疊傳高堂。", "瑣窗認得琴心怨，直恐韶華不得當。", "瑶環潛送慇懃意，只今猶記來時事。", "殺身不贖父兄羞，圖得歲寒成共蒂。", "陽昌市裏鷫鸘裘，鸞鑑相看未白頭。", "試拈玉軫攏金撥，新聲比似舊聲愁。", "世間恩愛何時盡，流水落花皆往恨。", "不愁歸避茂陵人，羞逢往日臨邛令。", "鴛鴦並翅雙飛宿，欲話衷腸歌不足。", "古來應有白頭吟，誰念妾身今再辱。"]'),
('780c8e96-8a61-4ca3-89f9-a7ab5374f1cb','十月十日立冬','周南','宋','宋诗','song-poetry','','[]','立冬前一夕，聒地起寒風。',48,'全唐诗/poet.song.175000.json','["立冬前一夕，聒地起寒風。", "律呂看交會，衣裳出褚中。", "骭瘍時作尰，懷抱歲將終。", "汗手汙牙筆，晴簷共禿翁。"]'),
('c7eacc49-d005-4a72-93e2-e53a473eca2a','入梅','周南','宋','宋诗','song-poetry','','[]','地濕衣生醭，天涼葛未裁。',48,'全唐诗/poet.song.175000.json','["地濕衣生醭，天涼葛未裁。", "暴暄偏壞藥，微灑似成梅。", "苦筍相將盡，良朋久不來。", "若無書作伴，那得好懷開。"]'),
('8fe9552c-55a7-4e8c-8c9d-f9997dd05ce6','石湖','周南','宋','宋诗','song-poetry','','[]','作者看胸臆，泠然接大荒。',48,'全唐诗/poet.song.175000.json','["作者看胸臆，泠然接大荒。", "雲溪收浩蕩，海觀度滄涼。", "故國餘丘壑，春船落艷陽。", "百年看俯仰，越燕又空梁。"]'),
('51feba2c-eb51-46f6-a847-9b0df186c99c','姑蘇臺','周南','宋','宋诗','song-poetry','','[]','輟杵餘千禩，叢臺此舊都。',48,'全唐诗/poet.song.175000.json','["輟杵餘千禩，叢臺此舊都。", "冰花銷窳瓦，組練入瀰湖。", "浩蕩春風在，荒亡霸業蕪。", "往來吳父老，藉草話城郛。"]'),
('bd3f8a14-3f16-461f-8984-e75acdbeaf28','庭燎','周南','宋','宋诗','song-poetry','','[]','種髮看如約，松明又送寒。',48,'全唐诗/poet.song.175000.json','["種髮看如約，松明又送寒。", "頗哀黧老健，慨我穫薪乾。", "小市街聲沸，明河小霧漫。", "賣癡兒女喚，更作夜來看。"]'),
('ad86d3dc-cd8b-4087-ae2b-189019588cf1','讀史','周南','宋','宋诗','song-poetry','','[]','條綜都遺忘，繙收亂貯儲。',48,'全唐诗/poet.song.175000.json','["條綜都遺忘，繙收亂貯儲。", "據梧甘觝滯，撫卷涉伸歔。", "老去從螢槁，昏來著茗祛。", "緬懷千載上，知讀幾年書。"]'),
('b8dc7614-a456-44d3-ad12-6329c6f673f3','登閶闔城','周南','宋','宋诗','song-poetry','','[]','閶闔開城郭，東南見此州。',48,'全唐诗/poet.song.175000.json','["閶闔開城郭，東南見此州。", "尊安山體奠，柔靜土田收。", "易野曾興國，崩臺早得秋。", "閒民無職事，力食愧鋤耰。"]'),
('f4a3f03d-a69d-478b-b941-f4e9dae13238','秋日步至湖桑埭西','周南','宋','宋诗','song-poetry','','[]','伏枕衰方劇，搘筇氣忽增。',48,'全唐诗/poet.song.175000.json','["伏枕衰方劇，搘筇氣忽增。", "細泉鳴暗竇，疎樹映孤燈。", "斷鴈寒依渚，長魚健脫罾。", "行纏已無用，却作在家僧。"]'),
('4c542680-93c8-4737-9807-10cddcdfd984','賦里人亭前三立石','周南','宋','宋诗','song-poetry','','[]','昔人藏巧拙，收拾老亭雲。',48,'全唐诗/poet.song.175000.json','["昔人藏巧拙，收拾老亭雲。", "雨溜漫天鑿，年侵見石心。", "支撐非爾力，秉執儼如臨。", "亦有渾渾氣，唯嗟骨未任。"]'),
('a9f0c12c-cf53-45c1-be36-0edb700d6a4c','山居晚步  其一','周南','宋','宋诗','song-poetry','','[]','蔬腸消穀暖，拄杖出林深。',48,'全唐诗/poet.song.175000.json','["蔬腸消穀暖，拄杖出林深。", "犢背斜陽在，蛩聲暮氣侵。", "崗巒舒伏脈，松菊會歸心。", "墟落函寒早，山曛日未沉。"]'),
('7e0640ea-464d-4039-80a1-c8a0769fcdef','山居晚步  其二','周南','宋','宋诗','song-poetry','','[]','步擔腰鎌急，平疇瀝稻稀。',48,'全唐诗/poet.song.175000.json','["步擔腰鎌急，平疇瀝稻稀。", "水雲漫白道，烓竈起青霏。", "縫塔隨煙暝，巢烏擇木飛。", "年豐閒正少，乘屋匠人歸。"]'),
('78b02aa1-cfaf-4dc3-9ad3-8c4e956f63f7','山居','周南','宋','宋诗','song-poetry','','[]','燏火燒烏桕，敲冰煮石楠。',48,'全唐诗/poet.song.175000.json','["燏火燒烏桕，敲冰煮石楠。", "烈風冬日夜，短褐野人菴。", "麥地宜秧穀，香欒記接柑。", "山中無槷具，日影漸移南。"]'),
('b9ce271f-2b9b-4fd0-a01c-6b5414172564','山家','周南','宋','宋诗','song-poetry','','[]','小麥連湖熟，黄梅作彈飛。',48,'全唐诗/poet.song.175000.json','["小麥連湖熟，黄梅作彈飛。", "穿林青犢過，觸柁白魚肥。", "子男輸絹急，姑婦插秧歸。", "枳花茶似雪，留客共湘瓷。"]'),
('2ad37193-60ea-4cc5-b306-fbffb7afb48d','驅儺','周南','宋','宋诗','song-poetry','','[]','高明紓鬼責，奧渫費誰何。',48,'全唐诗/poet.song.175000.json','["高明紓鬼責，奧渫費誰何。", "兒女今無恙，街坊又進儺。", "流年熒惑過，隊仗史巫多。", "求福吾能記，門前不用呵。"]'),
('f505e877-5aa1-40ce-a0a4-2b999755b2ba','奉問座主丘侍郎  其一','周南','宋','宋诗','song-poetry','','[]','早歲虛仁鑒，頻年闊素書。',48,'全唐诗/poet.song.175000.json','["早歲虛仁鑒，頻年闊素書。", "斯文誰後死，甲子正安居。", "公館初陽動，江沙海氣淤。", "近傳肝液少，歲晚更何如。"]'),
('f1786621-c7e3-4076-ac0f-f10e0b85e8c9','奉問座主丘侍郎  其二','周南','宋','宋诗','song-poetry','','[]','故老凄其甚，嗟余尚庶幾。',48,'全唐诗/poet.song.175000.json','["故老凄其甚，嗟余尚庶幾。", "勳庸遲琬琰，顧盼有晶威。", "伯氏供爲子，諸生記攝衣。", "凄涼葑菲恨，圖得誨言歸。"]'),
('4fee21fa-a5d1-42d1-b85f-bdc22866fcd8','送鄰守邂逅祭酒李公','周南','宋','宋诗','song-poetry','','[]','早作將吳守，臨分御李侯。',48,'全唐诗/poet.song.175000.json','["早作將吳守，臨分御李侯。", "清醇瞻耈老，省素共晨羞。", "鄉里終全活，人家更小留。", "腐儒疎懶意，白水看行舟。"]'),
('45d0b014-4dc7-43ef-9d62-150794b8c903','懷友人趙蹈中  其一','周南','宋','宋诗','song-poetry','','[]','妙質端能勁，除官正爾遲。',48,'全唐诗/poet.song.175000.json','["妙質端能勁，除官正爾遲。", "和歌誰與共，摻別可無饑。", "俗學訾豪奪，家人怨絕癡。", "相看又秋暮，未敢嘆余衰。"]'),
('8f072d8e-e7ed-4351-9eab-23711ce554b7','懷友人趙蹈中  其二','周南','宋','宋诗','song-poetry','','[]','虛想憐神怒，端頤護暑侵。',48,'全唐诗/poet.song.175000.json','["虛想憐神怒，端頤護暑侵。", "父兄寬衆責，寢飯驗初心。", "夜氣收肝膈，晨窗得笑吟。", "生年推我長，蓺殖可能深。"]'),
('97454382-61c1-4a85-83ec-c98d55f72fac','孟良甫別一歲無書有懷寄之','周南','宋','宋诗','song-poetry','','[]','孟氏好兄弟，相從隣巷居。',48,'全唐诗/poet.song.175000.json','["孟氏好兄弟，相從隣巷居。", "一窮吾得忍，千里意何如。", "夜雨看僵僕，家兒不詈予。", "豐年民瘼少，莫厭故人書。"]'),
('1d2333ce-d066-4dee-8dec-123782edd10f','示子','周南','宋','宋诗','song-poetry','','[]','編軸初黏飾，窗堂略淨蠲。',48,'全唐诗/poet.song.175000.json','["編軸初黏飾，窗堂略淨蠲。", "師前無脫履，弟幼與隨肩。", "苦柰休多食，精絺不耐撋。", "遲明吾語汝，欲睡更來前。"]'),
('0073a809-0a24-4785-a05c-8dcc639ee138','聞館客病侵曉得小馬亟歸','周南','宋','宋诗','song-poetry','','[]','濛濛露氣白，耿耿東方明。',48,'全唐诗/poet.song.175000.json','["濛濛露氣白，耿耿東方明。", "馬捉步猶碎，烏營食又鳴。", "倏過黄峴嶺，遥見闔閭城。", "欲問兒曹懶，前虞祿命輕。"]'),
('0a091e7a-cba4-41c1-ae63-999153e307a9','哭同年友馮校書  其一','周南','宋','宋诗','song-poetry','','[]','叔常雙骭骨，客死漢江中。',48,'全唐诗/poet.song.175000.json','["叔常雙骭骨，客死漢江中。", "憶昨煩憂甚，知吾友道窮。", "遠遊那知已，即願得純終。", "他日論巴産，東西有二馮。"]'),
('f3c1a05e-5757-401d-96d3-1e543858c9ca','哭同年友馮校書  其二','周南','宋','宋诗','song-poetry','','[]','病父沈攣久，扶行未有孫。',48,'全唐诗/poet.song.175000.json','["病父沈攣久，扶行未有孫。", "寡妻持酹酒，巴月旅歸魂。", "摧落收威暑，兢危過峽門。", "銘旌今遠近，到日敗垣存。"]'),
('c55b42c4-a997-4fdf-b798-8daaf4513957','偕蹈中過書塢歸二十韻','周南','宋','宋诗','song-poetry','','[]','我塢須君到，茲行說幾時。',240,'全唐诗/poet.song.175000.json','["我塢須君到，茲行說幾時。", "喜來衣裹少，勇出岸頭維。", "篙節探渠溜，燈籠上酒瓻。", "亂蛙嘈沮洳，警犬候笆籬。", "闕白瞻林罅，排蒼架月規。", "澣絺櫺易透，潔榻帚難施。", "落彈如梅熟，拋簪似筍遺。", "橘包收夕潤，杉彩漾朝曦。", "漆椀湖魚瑩，瓷甌釜粥糜。", "弛肩高木蔭，安膝下亭茨。", "散地今茲見，荒蹊過者誰。", "詭求諸老記，留下故人詩。", "憊幹宵中復，佳眠旦起遲。", "衣篝寬女送，藥劑切兄醫。", "僕點昏來窊，船樁泊定移。", "句材當面逼，天巧古人窺。", "還往楓橋路，低徊泰伯祠。", "比君多數歲，把卷憶吾師。", "八月登秔稻，西風理釣絲。", "未嫌墟曲小，來赴野塘期。"]'),
('e99a7ea4-ffa1-462b-9a38-fe69bb140a50','余杜門兀坐三年壬申六月九日出弔平望歸途阻風第四橋余曰是特偶相值爾不然豈造物者出門即相料理耶舟人曰然因識之','周南','宋','宋诗','song-poetry','','[]','地借沮龍宅，隄橫海蜃樓。',120,'全唐诗/poet.song.175000.json','["地借沮龍宅，隄橫海蜃樓。", "馬蹄翻震雹，沙觜更生洲。", "雲壑懸繩渡，天風激箭抽。", "濕霖平衍沃，暗井滅夫溝。", "蹴起爭橋齒，攛來似海鰌。", "浪花將岸颭，塔影聽桴浮。", "却憶銜枚地，曾驅縞練舟。", "謾云天設險，豈是水爲柔。", "無事人千古，逃榮茗一甌。", "川靈工閲世，翻覆幾時休。"]'),
('980b23fd-dd67-4de4-9917-fc61873e18e3','春日即事','周南','宋','宋诗','song-poetry','','[]','料理清明天氣催，攙先幾日柁船開。',64,'全唐诗/poet.song.175000.json','["料理清明天氣催，攙先幾日柁船開。", "六朝事往餘簪塔，百草春回上舞臺。", "巢燕爭迎華屋去，海潮猶傍故城來。", "主人兩鬢千絲雪，更斸青冥出稚栽。"]'),
('56305192-a726-4bee-bb35-5750ef4b7db0','後過書塢夜坐','周南','宋','宋诗','song-poetry','','[]','下駕官橋黄峴東，二十五里名新豐。',64,'全唐诗/poet.song.175000.json','["下駕官橋黄峴東，二十五里名新豐。", "慈竹色如蘆葦白，石楠頂結櫻朱紅。", "紙灰養火冬將盡，趺坐看書暖漸融。", "且蓄春雷歸地底，放令晴雪滿山中。"]'),
('0eabf494-fb02-48cb-a480-5138affba3f3','九日祁城外','周南','宋','宋诗','song-poetry','','[]','清晨驅馬出重闉，漸有狂花似小春。',64,'全唐诗/poet.song.175000.json','["清晨驅馬出重闉，漸有狂花似小春。", "草市豐年聲洩洩，官河霽色水粼粼。", "山林送老無予罪，物色愁人逐歲新。", "便擬移家去城郭，可無萸菊慰慈親。"]'),
('9d441aff-5e89-4898-b03e-00e342a4ea1c','泛舟游虎丘','周南','宋','宋诗','song-poetry','','[]','水遶朱門宿海槎，山沉海月上晨霞。',64,'全唐诗/poet.song.175000.json','["水遶朱門宿海槎，山沉海月上晨霞。", "鳥啼煙樹雨初歇，鐘度雲楣日未斜。", "僧俯劍池看貝葉，人追寒食衮楊花。", "西子年侵丘谷換，女牆還有舊宮鴉。"]'),
('9387c631-5c35-4aa4-9d27-c2edc8b582d0','過虎丘  其一','周南','宋','宋诗','song-poetry','','[]','勾吳霸業竟誰成，留得崇丘歲一登。',64,'全唐诗/poet.song.175000.json','["勾吳霸業竟誰成，留得崇丘歲一登。", "玉鴈已隨黄壤盡，鐵花空向碧潭凝。", "空中有塔掀鈴語，臺上無僧喚石應。", "踏盡蒼苔春老去，但餘落日與寒藤。"]'),
('18689f90-7cc2-4e9a-b847-49fc94e9d978','過虎丘  其二','周南','宋','宋诗','song-poetry','','[]','狐埋狐搰已無成，春去春來幾度登。',64,'全唐诗/poet.song.175000.json','["狐埋狐搰已無成，春去春來幾度登。", "海湧名山真幻出，酒酣看劍已塵凝。", "鷗陂人遠臺空在，鶑谷聲殘鳥倦應。", "越絕興亡俱一夢，爲君同弔剡溪藤。"]'),
('f9ac5867-2bc3-4537-8375-47fc59e4f82e','晚出至湖桑埭','周南','宋','宋诗','song-poetry','','[]','殘年孤寂不堪言，時喚平頭駕短轅。',64,'全唐诗/poet.song.175000.json','["殘年孤寂不堪言，時喚平頭駕短轅。", "老氣猶能作羆卧，壯懷誰復記鴻軒。", "櫂歌縹緲城西路，烟樹參差埭北村。", "堪笑怪奇消未盡，夜來還夢屬櫜鞬。"]'),
('f4339dea-ec96-41a3-9ae5-1ee446bc2f91','送林潮州','周南','宋','宋诗','song-poetry','','[]','誰把科名誤寘君，不教獻納近華勛。',64,'全唐诗/poet.song.175000.json','["誰把科名誤寘君，不教獻納近華勛。", "一麾暫遠長安日，六月先清瘴海氛。", "馬首喜無瀧吏問，筆端應有鱷魚文。", "明年勝日知無限，還記江東日暮雲。"]'),
('08ff18f0-9dbc-436f-aa16-8276310b349d','乙卯之秋送項秘書倅池陽是時教官之闕尚在來春','周南','宋','宋诗','song-poetry','','[]','諸老紛紛去不留，之人也作翠微遊。',64,'全唐诗/poet.song.175000.json','["諸老紛紛去不留，之人也作翠微遊。", "要看綠字封蒼蘚，須趁黄花插滿頭。", "秋水隔人猶有恨，春山得伴更何求。", "九華樓上新風月，不學詩人賦隠憂。"]'),
('0a75e8b2-f282-4a95-89c1-d51930bf7d11','送項倅  其一','周南','宋','宋诗','song-poetry','','[]','衡嶽山頭喚下來，高人不肯住蓬萊。',64,'全唐诗/poet.song.175000.json','["衡嶽山頭喚下來，高人不肯住蓬萊。", "先秋手得平分月，當暑身無半點埃。", "世事相逢休掛口，吾儕一見且銜杯。", "夜闌約立銀河表，閶闔天門次第開。"]'),
('a85f81cb-c47c-43d0-9765-3eb6acaef5fb','送項倅  其二','周南','宋','宋诗','song-poetry','','[]','昨者搜賢詔下來，旌蒲紛遝起蒿萊。',62,'全唐诗/poet.song.175000.json','["昨者搜賢詔下來，旌蒲紛遝起蒿萊。", "誰人肯厭承明直，我輩世俗埃。", "天近須回宣室召，時難倍愴渭城杯。", "殷勤爲誦江湖句，少立斜陽舟未開。"]'),
('73a990c9-9150-4a90-b705-0bcb64ef96ec','送江陵牧次對貳卿','周南','宋','宋诗','song-poetry','','[]','夢斷江湖絕寄聲，不圖猶見老成人。',64,'全唐诗/poet.song.175000.json','["夢斷江湖絕寄聲，不圖猶見老成人。", "白頭未覺相從晚，青眼何繇此會頻。", "自古荆襄俱重鎮，今公羊陸是前身。", "六千里地無非郢，寬著恩波浸遠人。"]'),
('9268614e-2268-49fe-b09a-a8d3401c62bf','歲杪送同官趨朝','周南','宋','宋诗','song-poetry','','[]','異縣飄零興已闌，更來樓上說加餐。',64,'全唐诗/poet.song.175000.json','["異縣飄零興已闌，更來樓上說加餐。", "不知壯日消磨已，也似中年賦別難。", "酒盡沙頭悲夜永，書來日脚是春殘。", "人生塗轍嗟何限，好在分携恰歲寒。"]'),
('20cd978f-7ca1-48db-8b86-2b3d0956b1c6','謝友人見過','周南','宋','宋诗','song-poetry','','[]','歲暮寒風易中人，對床誰與話情真。',64,'全唐诗/poet.song.175000.json','["歲暮寒風易中人，對床誰與話情真。", "平生知我無如子，此度相看又隔旬。", "世味慣看如嚼蠟，寒窗癡坐正癡塵。", "只今便擬高軒過，飲水毋嫌仲叔貧。"]'),
('4aef9cd2-fb12-43c3-b7e6-d5ba1e7e7059','和史君喜雨  其一','周南','宋','宋诗','song-poetry','','[]','通宵奠玉乞移災，閶闔天門午夜開。',64,'全唐诗/poet.song.175000.json','["通宵奠玉乞移災，閶闔天門午夜開。", "屏翳不隨風伯住，雷車爭逐阿香來。", "送神曲奏爭加額，喜雨詩成巧奪胎。", "聞說阪田猶未插，更須精意斡天囘。"]'),
('8fc47f21-e531-428d-a743-7d2754cf484d','和史君喜雨  其二','周南','宋','宋诗','song-poetry','','[]','蠶筐無葉不成眠，瞇眼黄沙障麥天。',64,'全唐诗/poet.song.175000.json','["蠶筐無葉不成眠，瞇眼黄沙障麥天。", "誰遣爐煙生濕霧，立翻江水沃桑田。", "雹飛鄰壤同時事，春入民襦頼吏賢。", "欲把豐年占覆斗，寸心應向碧霄懸。"]'),
('ff633255-9741-4ba9-91fd-cc48bf14533d','和史君喜雨  其三','周南','宋','宋诗','song-poetry','','[]','百萬疲氓饑欲啼，陰靈一夕靡雲旗。',64,'全唐诗/poet.song.175000.json','["百萬疲氓饑欲啼，陰靈一夕靡雲旗。", "穀芒綠潤沾天澤，梅子黄肥带雨時。", "薄宦經時誰舉手，豐年重見且信眉。", "諸生未用歌華黍，得熟民貧未可知。"]'),
('80b0706e-3ff1-4aed-8449-eb38b4c512b0','挽耿侍郎','周南','宋','宋诗','song-poetry','','[]','給事初爲畿縣令，姓名直徹阜陵前。',64,'全唐诗/poet.song.175000.json','["給事初爲畿縣令，姓名直徹阜陵前。", "後來佩盡名藩印，死去家無數頃田。", "留與道塗歌長者，未調鼎鉉合長年。", "龔黄只取優稱去，更有雲臺論百篇。"]'),
('6357b6da-c4c2-4a3a-a14a-bb9194371cd5','同年葛簽挽章  其一','周南','宋','宋诗','song-poetry','','[]','杏園張飲上晴湖，憶在團司識面初。',64,'全唐诗/poet.song.175000.json','["杏園張飲上晴湖，憶在團司識面初。", "二紀年光何忽忽，五更春夢已蘧蘧。", "彯纓曾識飛鳬舄，折獄爭馳薦鶚書。", "可惜佳城縈蔓草，只教綠水泛紅蕖。"]'),
('f1fcb61e-a1d6-4c5f-a8a3-98d342f58ca9','同年葛簽挽章  其二','周南','宋','宋诗','song-poetry','','[]','少年並馬曲江遊，曾到慈恩塔上頭。',64,'全唐诗/poet.song.175000.json','["少年並馬曲江遊，曾到慈恩塔上頭。", "過眼流光真露電，驚心宦海半沉浮。", "君今又隔重泉夢，世事嗟傷逝水流。", "獨立東風數華髮，不堪春草起離愁。"]'),
('aa8af67a-161a-46f8-8510-098f1f4d96ae','挽秘撰趙郡運子固','周南','宋','宋诗','song-poetry','','[]','舊學虛蒙一字褒，暮年曾得拜江臯。',64,'全唐诗/poet.song.175000.json','["舊學虛蒙一字褒，暮年曾得拜江臯。", "丹砂雅意成前約，玩印連章避左曹。", "事業略曾隨手見，死生應嘆有身勞。", "只今蛻迹西林去，始得先生蚤退高。"]'),
('538ad618-c436-4cd1-b3d8-bc116bd52e03','闕題  其一','周南','宋','宋诗','song-poetry','','[]','天憐羈迹寄諸侯，付與危欄早得秋。',64,'全唐诗/poet.song.175000.json','["天憐羈迹寄諸侯，付與危欄早得秋。", "相見便知懸榻意，闞亡時得挾書遊。", "山容老去蒼崖在，水潦痕存淺碧收。", "高我儒冠無用世，不應更躡九華樓。"]'),
('f645d527-74ec-46cc-8517-6f47fe3c6242','闕題  其二','周南','宋','宋诗','song-poetry','','[]','天憐羈迹寄諸侯，差近危欄付與秋。',64,'全唐诗/poet.song.175000.json','["天憐羈迹寄諸侯，差近危欄付與秋。", "風物捲簾都在眼，湖山如畫恰當頭。", "征鴻已作隨陽計，社燕能爲幾日留。", "頼有楚天涼夜月，二年相伴上譙樓。"]'),
('edff8eec-9ca2-4498-a7cc-80a6b5a01c3c','皇帝閤春帖子  其一','周南','宋','宋诗','song-poetry','','[]','路寢朝元早，條風應律初。',24,'全唐诗/poet.song.175000.json','["路寢朝元早，條風應律初。", "八荒躋壽域，一札下寬書。"]'),
('7c561a8b-6f32-4071-9366-fa49580da472','皇帝閤春帖子  其二','周南','宋','宋诗','song-poetry','','[]','玉燭天時正，金穰歲兆豐。',24,'全唐诗/poet.song.175000.json','["玉燭天時正，金穰歲兆豐。", "華封遥上祝，聖德與天通。"]'),
('8e1fd01a-de41-48f4-ac9f-789d2dd57804','皇帝閤春帖子  其三','周南','宋','宋诗','song-poetry','','[]','禁籞希臨幸，宵衣戒未明。',24,'全唐诗/poet.song.175000.json','["禁籞希臨幸，宵衣戒未明。", "餘閒寓弧矢，勸講只儒生。"]'),
