('e43d95fe-fa33-4fbb-8227-a53fb87ee371','寄友人','周南','宋','宋诗','song-poetry','','["\u592a\u6e56"]','生前何事苦收身，身後浮名底樣榮。',32,'全唐诗/poet.song.175000.json','["生前何事苦收身，身後浮名底樣榮。", "只得太湖三萬頃，與君亭下作真清。"]'),
('24dc97cf-410c-4ca3-b29c-73c04b22d175','懷友人趙蹈中','周南','宋','宋诗','song-poetry','','[]','水宿山行可煞勞，山川應是怕才豪。',32,'全唐诗/poet.song.175000.json','["水宿山行可煞勞，山川應是怕才豪。", "詩人只好遊湘水，上却巴陵恐是騷。"]'),
('d8ba644a-f104-4d4e-b65b-2873a330edca','讀信州趙昌甫詩','周南','宋','宋诗','song-poetry','','[]','斯文世不收，未絕僅如縷。',48,'全唐诗/poet.song.175000.json','["斯文世不收，未絕僅如縷。", "哦君古律詩，思君用心苦。", "廩錢能幾何，茅舍月有取。", "懷哉斯人歟，被褐止衡堵。"]'),
('88968d31-fe88-47e9-98a9-69aa5016daca','蠶婦怨','周南','宋','宋诗','song-poetry','','[]','去年蹉却漚麻時，寒女卒歲號無衣。',96,'全唐诗/poet.song.175000.json','["去年蹉却漚麻時，寒女卒歲號無衣。", "今年無葉蠶眠遲，五月簇繭方繰絲。", "絲成那望衣兒女，且織霜縑了官賦。", "不愁織盡杼軸空，只恐精麤不中度。", "寒女寒女無重歎，且將敗縷縫新綻。", "願得明年蠶葉平，剜肉醫瘡爲汝辦。"]'),
('f193e1d4-91fd-4342-98d3-48c578d235de','呈南安孟使君','周南','宋','宋诗','song-poetry','','[]','使君四十銅虎符，一矢曾識金僕姑。',307,'全唐诗/poet.song.175000.json','["使君四十銅虎符，一矢曾識金僕姑。", "唐三百年進士舉，不再鼓之終非夫。", "西風籠槐桂扶疎，筆勢洶如濤江驅。", "知君三昧等游戲，我欲一言口囁嚅。", "元凱登庸用譜系，稷契雖賢名第無。", "當時未有明光賦，致君大略到唐虞。", "君家六戟聯椒塗，身無一點薰香汙。", "頗疑膏粱逼寒畯，顧欲場屋爭分銖。", "高山深林百年餘，大夏生殖雨露濡。", "其間吾疑有栝柏，根蟠擬作輪囷株。", "尚能爾雅注蟲魚，下同年少爭得途。", "極知文章君之餘，何愛漏刻收桑榆。", "但疑入山見成鐻，可惜彈雀煩明珠。", "大夫當據要地居，仕宦須作執金吾。", "治經博士苟無命，不妨餓死同侏儒。", "君不見德裕生無不讀書，死不肯與諸生俱。", "期君事業如韓呂，何嫌門地用崔盧。", "我嘗一擲色得盧，盤中雙陸萬人呼。", "只今欲學支離疏，徒嗟七十戰匈奴。"]'),
('21e55cac-49bf-48da-b48d-e2e903c543d2','過田家','周南','宋','宋诗','song-poetry','','[]','得麥兒今喜，無梅雨又愆。',48,'全唐诗/poet.song.175000.json','["得麥兒今喜，無梅雨又愆。", "翁身今七十，眼見幾般年。", "連年增口數，再世種人田。", "機上畸零絹，今當數百錢。"]'),
('e95f2eae-2af3-44cb-b242-4648cb180c39','掃地','周南','宋','宋诗','song-poetry','','[]','滑几懸游氣，磨磚出寸光。',48,'全唐诗/poet.song.175000.json','["滑几懸游氣，磨磚出寸光。", "及時須敝帚，措影見胡床。", "拱揖延書入，澄收得慮莊。", "蒼頭擁箕袂，持禮老夫旁。"]'),
('c5c88da5-e45a-4cb6-b27b-f057f65690c9','追送友人李季允歸蜀三首併寄所懷  其一','周南','宋','宋诗','song-poetry','','[]','獨往知心在，晨風憶纜開。',48,'全唐诗/poet.song.175000.json','["獨往知心在，晨風憶纜開。", "江濤寬屢涉，山鬼訊重來。", "甲子悲麟去，林廬有鴈囘。", "贈言吾豈敢，遺藥可無猜。"]'),
('1ae9da80-7ade-42b0-88e5-8d922036cdec','追送友人李季允歸蜀三首併寄所懷  其二','周南','宋','宋诗','song-poetry','','[]','保終無智力，麗澤慨重湖。',48,'全唐诗/poet.song.175000.json','["保終無智力，麗澤慨重湖。", "白水當門戶，清秋送舳艫。", "他山藏實錄，稚子狎長途。", "自古多零落，空悲永夜徂。"]'),
('64547aff-a898-48f6-ae48-160a203ed9c0','追送友人李季允歸蜀三首併寄所懷  其三','周南','宋','宋诗','song-poetry','','[]','西州餘一老，六月上窮山。',48,'全唐诗/poet.song.175000.json','["西州餘一老，六月上窮山。", "仲子何時到，三吳說鬢斑。", "土風添藥費，聖代有生還。", "歸夢商於近，音書報是間。"]'),
('b20c00ad-ee78-4f13-97f6-b3c5a213c46f','伍相廟','周南','宋','宋诗','song-poetry','','[]','封域依神保，遺哀記屬鏤。',48,'全唐诗/poet.song.175000.json','["封域依神保，遺哀記屬鏤。", "荒庭垂白露，古屋換爰烏。", "配食虛神果，除壇欠闔閭。", "向來存二廟，猶得慰三吳。"]'),
('33f0fc0b-068f-414b-93f5-11126dd1d036','又題伍相廟','周南','宋','宋诗','song-poetry','','[]','廢堞披榛舊，羈臣畢命心。',48,'全唐诗/poet.song.175000.json','["廢堞披榛舊，羈臣畢命心。", "江湖吞故壑，貌相匪斯今。", "激烈功名在，低徊歲月深。", "胥門沙衍淺，碑首未應沉。"]'),
('b322f7c2-9d65-44b8-9546-f3bb142bd260','夏中兄病關心復了一二小書稍凉薾然有白髮坐念力衰而學晚慨然有感','周南','宋','宋诗','song-poetry','','[]','凉颸侵病榻，鬒髮減玄膏。',48,'全唐诗/poet.song.175000.json','["凉颸侵病榻，鬒髮減玄膏。", "長得承親健，寧辭煮藥勞。", "書程貪晝永，心量怯年高。", "艾耋猶知禮，昏明在所操。"]'),
('6477c40d-e26a-4056-9c0e-1f5b4d66274a','刮釜','周南','宋','宋诗','song-poetry','','[]','刮釜嗟鄰母，經旬值濕薪。',48,'全唐诗/poet.song.175000.json','["刮釜嗟鄰母，經旬值濕薪。", "煎磨知物性，豐大轉民貧。", "康食心知愧，哀囂聽頗親。", "稻花傷晝雨，愁殺看書人。"]'),
('69786a2e-62a3-4746-8fc0-ff5b29922e0f','夏日游太湖  其一','周南','宋','宋诗','song-poetry','','["\u592a\u6e56"]','荒莽殘唐寺，前通霸越江。',48,'全唐诗/poet.song.175000.json','["荒莽殘唐寺，前通霸越江。", "茭蘆私井稅，鐘鼓助舂撞。", "大壑容漁戶，殘碑寄石幢。", "好山三四十，浮入兩僧窗。"]'),
('3e0e438a-5e17-4ad5-b9a7-e49e1ff967e6','夏日游太湖  其二','周南','宋','宋诗','song-poetry','','["\u592a\u6e56"]','氣逼梅天溽，衣霑溜雨篷。',48,'全唐诗/poet.song.175000.json','["氣逼梅天溽，衣霑溜雨篷。", "暗潮留地灢，闊水架天風。", "黯黑初星出，顛狂一瓠空。", "孫翁無片紙，說得五湖同。"]'),
('27a08bb6-ec83-4557-879e-cc4eb360c9ab','隨太守送神歸而有感','周南','宋','宋诗','song-poetry','','[]','泌水洋洋可樂饑，强尋囊粟止兒啼。',64,'全唐诗/poet.song.175000.json','["泌水洋洋可樂饑，强尋囊粟止兒啼。", "自憐蠹簡爲儒誤，也逐鳴笳到佛祠。", "文字不堪供吏役，姓名漸喜少人知。", "一廛未辦歸耕計，坐看槐堂綠蔭移。"]'),
('04abf260-4842-43c2-944f-c17ef753a3dc','太平州陳大監挽章  其一','周南','宋','宋诗','song-poetry','','[]','老去無成久索居，尚能林下聽除書。',64,'全唐诗/poet.song.175000.json','["老去無成久索居，尚能林下聽除書。", "百年門地推鴻緒，三月春江照隼旟。", "雲路脩程驚折軸，昔遊風誼記囘車。", "綠陰春草佳城暮，無計親陳野客蔬。"]'),
('dacb6b91-f220-4885-800e-1326309d6e9c','太平州陳大監挽章  其二','周南','宋','宋诗','song-poetry','','[]','人稱扁畫更傳詩，飛到青冥却自遲。',64,'全唐诗/poet.song.175000.json','["人稱扁畫更傳詩，飛到青冥却自遲。", "今代人門能有幾，傷心年壽遽如斯。", "百年喬木虬枝在，千里棠陰曉角悲。", "日暮佳城春草碧，生芻遥奠野人巵。"]'),
('2b63e690-ea1e-4466-a685-0b661132e1a3','丘都督樞密挽章  其一','周南','宋','宋诗','song-poetry','','[]','曩時威鳳覽輝初，獨對丹霄聳萬夫。',64,'全唐诗/poet.song.175000.json','["曩時威鳳覽輝初，獨對丹霄聳萬夫。", "千載阜陵嗟見晚，百年喬木有神扶。", "只將囊底安江左，不見天中運斗樞。", "聖主恩深臣命薄，悔今强敵尚逋誅。"]'),
('534ab522-7048-4233-93b3-14c66ebad20c','丘都督樞密挽章  其二','周南','宋','宋诗','song-poetry','','[]','淮水塵清小使歸，壞梁俄嘆哲人萎。',64,'全唐诗/poet.song.175000.json','["淮水塵清小使歸，壞梁俄嘆哲人萎。", "江山收淚還風景，草木知名怖鼓旗。", "生惜勳庸專管葛，死餘忠信壓邊陲。", "南州十月停砧杵，料得聞喪處處悲。"]'),
('8071da89-54d8-45e6-9a95-4d3090654b4d','二月五日發舟','周南','宋','宋诗','song-poetry','','[]','此行休羨得閒高，也莫徘徊過二毛。',32,'全唐诗/poet.song.175000.json','["此行休羨得閒高，也莫徘徊過二毛。", "破硯無由賒一飯，且携黄牒拜南曹。"]'),
('9dbbf259-0487-4268-81b9-18ec188ff4a2','春日迓新使君  其一','周南','宋','宋诗','song-poetry','','[]','半生窮巷抱遺經，多謝諸公說姓名。',32,'全唐诗/poet.song.175000.json','["半生窮巷抱遺經，多謝諸公說姓名。", "四十頭顱成底事，五更炊黍學將迎。"]'),
('a8b0830c-9388-46e6-b250-898104d2e2b9','春日迓新使君  其二','周南','宋','宋诗','song-poetry','','[]','雲幕初收未肯晴，又將風雨做清明。',32,'全唐诗/poet.song.175000.json','["雲幕初收未肯晴，又將風雨做清明。", "陰沉天氣渾無頼，更兀籃輿夢裏行。"]'),
('4cbb230a-f97f-4cb0-bdd2-2c1218772eb7','池陽春日迓新使君','周南','宋','宋诗','song-poetry','','[]','東風捲地滾塵沙，扶起垂楊損盡花。',32,'全唐诗/poet.song.175000.json','["東風捲地滾塵沙，扶起垂楊損盡花。", "留意野棠無意度，淡紅疎蕾當年華。"]'),
('464745aa-a16c-4e0a-8158-96035d7c4aa8','讀唐詩  其一','周南','宋','宋诗','song-poetry','','[]','一日勾消兩卷詩，趁忙抄得是燈時。',32,'全唐诗/poet.song.175000.json','["一日勾消兩卷詩，趁忙抄得是燈時。", "隔窗一鬨狂風雨，無數啁啾凍雀兒。"]'),
('1f9e6097-3996-4469-80ea-5a62e1ddd637','讀唐詩  其二','周南','宋','宋诗','song-poetry','','[]','自分餘工督小兒，更抄兩卷晚唐詩。',32,'全唐诗/poet.song.175000.json','["自分餘工督小兒，更抄兩卷晚唐詩。", "勾消日力跏趺坐，欲寫凄涼神已疲。"]'),
('e835d258-7864-4e32-a2d7-ed5344a083f7','讀唐詩  其三','周南','宋','宋诗','song-poetry','','[]','一般生態幾人描，砑盡吳牋禿盡毫。',32,'全唐诗/poet.song.175000.json','["一般生態幾人描，砑盡吳牋禿盡毫。", "却是晚唐工狀物，手調煙露染天膏。"]'),
('ce4a3516-9ec2-4ee0-bdcb-0f3d1801ec31','聽湖州歌','周南','宋','宋诗','song-poetry','','[]','十五隣家女末行，棹歌端的訴衷情。',32,'全唐诗/poet.song.175000.json','["十五隣家女末行，棹歌端的訴衷情。", "試將月出株林比，應有齊風檃未成。"]'),
('9ef51b43-3791-4609-a9c6-0e9b6b7f479a','柬龔立道','周南','宋','宋诗','song-poetry','','[]','不課木奴千樹入，却夸蠹簡百年餘。',32,'全唐诗/poet.song.175000.json','["不課木奴千樹入，却夸蠹簡百年餘。", "先生不要金花帖，只借耕田覓飯書。"]'),
('7a57670b-f0a8-45ed-aea2-7827de3c261b','筇竹杖','周南','宋','宋诗','song-poetry','','[]','四十龍鍾欠一年，不應鶴骨會乘軒。',32,'全唐诗/poet.song.175000.json','["四十龍鍾欠一年，不應鶴骨會乘軒。", "杖頭無用燃藜燭，倚向荒畦印屐痕。"]'),
('3fa416ca-36bb-4870-b477-206408733e2e','答靜翁并以筇竹杖一枝贈行頌  其一','周南','宋','宋诗','song-poetry','','[]','南鴻北鴈年年客，有箇生涯主不知。',32,'全唐诗/poet.song.175000.json','["南鴻北鴈年年客，有箇生涯主不知。", "撼動從來憂樂事，夜窗風葉響棠梨。"]'),
('51e66ccf-3ed4-417b-9d81-86ed9b9bb21b','答靜翁并以筇竹杖一枝贈行頌  其二','周南','宋','宋诗','song-poetry','','[]','栽松道者身先老，放下鋤頭好再來。',32,'全唐诗/poet.song.175000.json','["栽松道者身先老，放下鋤頭好再來。", "八萬四千關捩子，與公一箇鎖匙開。"]'),
('c9bbfff7-5aac-423e-bf23-12ead15bb015','答靜翁并以筇竹杖一枝贈行頌  其三','周南','宋','宋诗','song-poetry','','[]','一筇九節添行李，用得人間處處尊。',32,'全唐诗/poet.song.175000.json','["一筇九節添行李，用得人間處處尊。", "只要上山行飽飯，莫將風雪打人門。"]'),
('c65ee3b8-ecc7-4639-8336-5d5ed5f9ea97','答靜翁并以筇竹杖一枝贈行頌  其四','周南','宋','宋诗','song-poetry','','[]','萬事實頭方穩當，十分足陌莫蹺除。',32,'全唐诗/poet.song.175000.json','["萬事實頭方穩當，十分足陌莫蹺除。", "困來展席日裏睡，讀盡空中鳥跡書。"]'),
('5f986dfc-797f-4ee3-a38b-cc195476c6a5','途中賦落梅','周南','宋','宋诗','song-poetry','','[]','一段幽奇破臘忙，只將遲暮了年光。',32,'全唐诗/poet.song.175000.json','["一段幽奇破臘忙，只將遲暮了年光。", "從教籬落飄零盡，也勝房櫳半面粧。"]'),
('d91d44f4-9f53-4550-b31c-fb57434d81cf','凍藕','周南','宋','宋诗','song-poetry','','[]','雪藕前身玉井蓮，與泥俱出又經年。',32,'全唐诗/poet.song.175000.json','["雪藕前身玉井蓮，與泥俱出又經年。", "長卿渴殺郫筒釀，乞與春塘范堰船。"]'),
('f1d292d7-0c9b-4ad6-8a70-b2c25296c698','遊山寺','周南','宋','宋诗','song-poetry','','[]','山寺清明蛺蝶飛，中庭古佛供琉璃。',32,'全唐诗/poet.song.175000.json','["山寺清明蛺蝶飛，中庭古佛供琉璃。", "僧房也有追遊市，瓦狗泥車誑小兒。"]'),
('e0ea421e-9fd6-4e11-8fc5-3142e2af3bc3','喜鵲  其一','周南','宋','宋诗','song-poetry','','[]','簷牙喚起前時夢，遠信憑君便有期。',32,'全唐诗/poet.song.175000.json','["簷牙喚起前時夢，遠信憑君便有期。", "歲暮柴門今事少，寒暄音問不須知。"]'),
('ea74f1fb-e1fd-4904-a54d-2991db8a1228','喜鵲  其二','周南','宋','宋诗','song-poetry','','[]','火龜已食幽貞墨，乾鵲猶將吉語傳。',32,'全唐诗/poet.song.175000.json','["火龜已食幽貞墨，乾鵲猶將吉語傳。", "高處營巢君自好，張羅門外爾徒喧。"]'),
('ff56440b-bc95-44eb-b9dd-c6e6efb495a5','瓶中花','周南','宋','宋诗','song-poetry','','[]','清曉銅瓶沃井華，青葱綠玉紫蘭芽。',32,'全唐诗/poet.song.175000.json','["清曉銅瓶沃井華，青葱綠玉紫蘭芽。", "鬢毛白盡心情在，不分看花學養花。"]'),
('c83153e0-7daa-49b2-bdc0-23ea59851fb7','詠史 郭汾陽女許橋神','周南','宋','宋诗','song-poetry','','[]','汾陽蒲鎮造浮橋，女許橋神水患消。',32,'全唐诗/poet.song.175000.json','["汾陽蒲鎮造浮橋，女許橋神水患消。", "河瀆親家從此號，正人夫豈自興妖。"]'),
('b44fd5ae-f27f-412e-9041-711722fb9a96','詠史 陳茂呵水神','周南','宋','宋诗','song-poetry','','[]','東都陳茂航海時，藐爾陽侯敢肆欺。',32,'全唐诗/poet.song.175000.json','["東都陳茂航海時，藐爾陽侯敢肆欺。", "拔劍一呼風浪息，大賢行處有天隨。"]'),
('9016810d-32e6-4c52-9012-84dfdccb93d1','孔村','周南','宋','宋诗','song-poetry','','[]','轍環死只欠居夷，此地傳訛且闕疑。',32,'全唐诗/poet.song.175000.json','["轍環死只欠居夷，此地傳訛且闕疑。", "壞屋無烟桑柘少，絕憐猶似厄陳時。"]'),
('b40f9c21-7689-416e-8af3-c7a21880e0e4','千金村','周南','宋','宋诗','song-poetry','','[]','種豆燃萁地力勞，更將菜甲壓豨膏。',32,'全唐诗/poet.song.175000.json','["種豆燃萁地力勞，更將菜甲壓豨膏。", "豪家粔籹消多少，切莫煎熬到老饕。"]'),
('78d30e19-f203-44ad-b766-5c440c11ef7d','行役','裘萬頃','宋','宋诗','song-poetry','','[]','宿霧鎖山椒，落月挂林側。',48,'全唐诗/poet.song.175000.json','["宿霧鎖山椒，落月挂林側。", "崎嶇歷岡巒，彷彿辨阡陌。", "秋高風露寒，道遠時序迫。", "安得歸故園，篝燈理書冊。"]'),
('b7eba44a-1be7-4c2c-9a0a-a1c5fbc9c8fa','武陽渡','裘萬頃','宋','宋诗','song-poetry','','[]','一舟小如葉，橫在波濤中。',48,'全唐诗/poet.song.175000.json','["一舟小如葉，橫在波濤中。", "紛紛川上人，欲渡愁北風。", "有帆天際來，漸近葭葦叢。", "寄聲與問訊，恐是陶朱公。"]'),
('81f08354-540e-4035-8c4d-0547521ebb64','宿佛頭塔','裘萬頃','宋','宋诗','song-poetry','','[]','孤村三四家，籬下盡禾忝。',48,'全唐诗/poet.song.175000.json','["孤村三四家，籬下盡禾忝。", "主人慣入市，能作市井語。", "開窗對竹山，揖客治尊俎。", "白雲忽在眼，客淚墮如雨。"]'),
('ccfb878f-5f6e-493e-a10a-6cb325be6d20','羅溪橋','裘萬頃','宋','宋诗','song-poetry','','[]','我來從西昌，日日困塵土。',48,'全唐诗/poet.song.175000.json','["我來從西昌，日日困塵土。", "誰知羅溪橋，淨若初過雨。", "長松列左右，清風奏宮羽。", "薄暮舍籃輿，扁舟渡溪去。"]'),
('bf590d67-57f7-4c28-8153-051e60511542','別友','裘萬頃','宋','宋诗','song-poetry','','[]','清宵月滿梁，相思幾搔首。',48,'全唐诗/poet.song.175000.json','["清宵月滿梁，相思幾搔首。", "不圖塵土中，得共一尊酒。", "人事好乖甚，隨復而分手。", "惟有管鮑心，明明若箕斗。"]'),
('4ac7dcdf-02a7-4a4b-a583-5890ad330782','次許秀才韻二首  其一','裘萬頃','宋','宋诗','song-poetry','','[]','癡兒欲了事，事竟莫之了。',48,'全唐诗/poet.song.175000.json','["癡兒欲了事，事竟莫之了。", "崇朝弄朱墨，校勘是與否。", "徐觀鴈鶩行，大半落渠手。", "敗羣雖已去，考牧未有道。"]'),
('e520ab23-e948-48e5-adbe-bc1b78424d28','次許秀才韻二首  其二','裘萬頃','宋','宋诗','song-poetry','','[]','拙工不量力，自謂中了了。',48,'全唐诗/poet.song.175000.json','["拙工不量力，自謂中了了。", "高談蓋一座，衆可己獨否。", "斯須臨斧斤，汗背血兩手。", "旁觀信善斲，莫肯告以道。"]'),
('791a40d5-55e7-4c67-8342-115c3cb4b01d','病中聞伯量相訪寄之二首  其一','裘萬頃','宋','宋诗','song-poetry','','[]','我屋修竹根，身閒境逾靜。',48,'全唐诗/poet.song.175000.json','["我屋修竹根，身閒境逾靜。", "維摩本無心，誰令示人病。", "夕陽耿疎林，影落莓苔徑。", "佇立有所懷，高人儻乘興。"]'),
('b4644b34-580f-4584-9ca6-633f5b439b9c','病中聞伯量相訪寄之二首  其二','裘萬頃','宋','宋诗','song-poetry','','[]','高人在城郭，應酬頗紛如。',48,'全唐诗/poet.song.175000.json','["高人在城郭，應酬頗紛如。", "憶我煙霞栖，遺我一紙書。", "雨餘窗戶凉，蛩聲滿階除。", "相過有成言，何時命巾車。"]'),
('224eb69c-1472-4a60-9c9f-f6ec44d95b97','次范光伯泛江韻','裘萬頃','宋','宋诗','song-poetry','','[]','夫君陶阮徒，俗子所不快。',48,'全唐诗/poet.song.175000.json','["夫君陶阮徒，俗子所不快。", "屹然頹其中，特立蓋甚介。", "平生江湖樂，欲去不得邁。", "何當從君遊，漁釣寄吾解。"]'),
('36db49f1-3c1b-43bc-ae02-6b43f66c885e','螘運','裘萬頃','宋','宋诗','song-poetry','','[]','知戰不能損，檀氏所以亡。',48,'全唐诗/poet.song.175000.json','["知戰不能損，檀氏所以亡。", "吾媿與敵槐，將何固封疆。", "及此閒暇時，相與積乃倉。", "不須更他騖，富國兵自强。"]'),
('b0564546-49e2-4fa5-9214-284e8ba1e804','次伯仁善利閣小室韻','裘萬頃','宋','宋诗','song-poetry','','[]','山林吾所廬，夜月但對影。',48,'全唐诗/poet.song.175000.json','["山林吾所廬，夜月但對影。", "焉知江上人，一日了萬境。", "褰裳步崇臺，有室妍且靜。", "徘徊不能去，坐見四山暝。"]'),
('419bb216-dd98-4e9b-99ac-4a4426b6a21f','見雪','裘萬頃','宋','宋诗','song-poetry','','[]','玄冥當語誰，餉我一簷雪。',48,'全唐诗/poet.song.175000.json','["玄冥當語誰，餉我一簷雪。", "吾廬本來靜，得此更清絕。", "遥憐北海上，往往已盈尺。", "齧氈人在否，毋凌漢臣節。"]'),
('513833b3-f4ce-4e6b-9e59-48e62c3ba1b7','出門','裘萬頃','宋','宋诗','song-poetry','','[]','出門復入門，吾行竟安之。',108,'全唐诗/poet.song.175000.json','["出門復入門，吾行竟安之。", "携書北窗下，翻閲聊自怡。", "有懷千載人，掩卷還歔欷。", "采采首陽薇，戀戀商山芝。", "一裘或終身，欣然釣江湄。", "斯人不可作，斯道日湮微。", "目前稻梁謀，鳧鴈方齊飛。", "青田寂無音，歲晚將疇依。", "慎勿出門去，塵埃染人衣。"]'),
('e65c79df-4a13-4bb7-8f21-767815bbfd3e','菖蒲','裘萬頃','宋','宋诗','song-poetry','','[]','康廬入吾懷，十載馳夢魂。',108,'全唐诗/poet.song.175000.json','["康廬入吾懷，十載馳夢魂。", "踵門者何人，遺予以芳蓀。", "歡然得其趣，如對五老言。", "幽姿出巖谷，常带冰雪痕。", "塵容爲一洗，兩目不復昏。", "忽思三峽流，褰衣涉潺湲。", "因仍一寸石，浸潤九節根。", "人言可扶老，歲月須其蕃。", "茲理諒不誣，吾將從綺園。"]'),
('d6626d33-8e20-41a3-b618-12a5cad84fa9','宿田家竹亭','裘萬頃','宋','宋诗','song-poetry','','[]','我家西山巔，四壁皆此君。',84,'全唐诗/poet.song.175000.json','["我家西山巔，四壁皆此君。", "朅來事奔馳，日與茅葦親。", "方思坡仙詩，恐入俗士羣。", "止我宿者誰，此君滿其門。", "頎然千百夫，一見若故人。", "夜深清風來，好音夢中聞。", "呼童啟北窗，爲渠炷爐芬。"]'),
('65841f8a-3c7b-422d-b424-4d0a1bb992f3','送詩僧如師西游','裘萬頃','宋','宋诗','song-poetry','','[]','鄉來詩壇上，權可聲籍籍。',72,'全唐诗/poet.song.175000.json','["鄉來詩壇上，權可聲籍籍。", "君雖後兩翁，而已分半席。", "主人龍門高，宜有如此客。", "橫行翰墨場，往往一當百。", "挾是今西遊，吐談取雙璧。", "要須早歸來，成就法王宅。"]'),
('1b0e3e09-d427-42c1-9558-695b69ee19e4','從人覓墨梅','裘萬頃','宋','宋诗','song-poetry','','[]','熏爐束詩魂，茗碗驅睡思。',72,'全唐诗/poet.song.175000.json','["熏爐束詩魂，茗碗驅睡思。", "掩關寂無營，翰墨自娛戲。", "山寒溪正清，月澹雪初霽。", "橫斜兩三枝，見說可人意。", "天機如胸中，出手特餘事。", "何時翦冰紈，來對病居士。"]'),
('2e5933fd-c19b-432d-9402-0163989ba064','睡起','裘萬頃','宋','宋诗','song-poetry','','[]','疾去得安卧，寒宵不知長。',108,'全唐诗/poet.song.175000.json','["疾去得安卧，寒宵不知長。", "鄰雞忽聞聲，曙色侵我牀。", "人生孰無營，晨興固其常。", "奈何以一身，投之百憂場。", "吾方休吾心，與世長相忘。", "適逢希夷翁，授我枕中方。", "意行到華胥，日昃猶徜徉。", "回觀一世人，擾擾良可傷。", "誰能從我遊，要須留春皇。"]'),
('c4c11332-d4ac-49a9-83a8-17438ce0fdd1','讀邸報','裘萬頃','宋','宋诗','song-poetry','','[]','紛紛天下事，翻覆良難期。',144,'全唐诗/poet.song.175000.json','["紛紛天下事，翻覆良難期。", "不知窈冥中，主張者云誰。", "工拙判兩塗，人謀豈容施。", "得非欲平治，機緘遂潛移。", "目前三四公，並用無一遺。", "毋嫌滯一州，民實邦之基。", "鄉來番江頭，親見國子師。", "德行淵與騫，千載如同時。", "斯人使臨民，兒不頼母慈。", "人言致泰和，須索登臯夔。", "位崇澤斯均，否則失所宜。", "天乎儻人從，何時可臻茲。"]'),
('1808ad78-f22b-49b4-87c4-ab5f0901b4e8','次伯量贈別詩韻','裘萬頃','宋','宋诗','song-poetry','','[]','我生既駑下，且復寡見聞。',144,'全唐诗/poet.song.175000.json','["我生既駑下，且復寡見聞。", "時時警其愚，姻黨頼有君。", "自慚將且疲，不足張此軍。", "君乃不我棄，歡然與同羣。", "願學如之何，此志亦已勤。", "正坐未知方，所得不足云。", "人生所好雜，其力用是分。", "詞章末技耳，安能媲皇墳。", "而況字書學，兀兀纂說文。", "曷若鞭吾心，或有汗馬勳。", "請益恨未能，別君大江濆。", "長吟昌黎詩，安得身登雲。"]'),
('9cd9b571-fa73-4ba7-b03e-6827c0e3c00e','老農歎','裘萬頃','宋','宋诗','song-poetry','','[]','霜耕冰在趾，雨種泥沒膝。',132,'全唐诗/poet.song.175000.json','["霜耕冰在趾，雨種泥沒膝。", "旱魃忽爲虐，耕種謾勞力。", "去年幸一稔，今歲免艱食。", "細聽老農語，令我三歎息。", "但願從此去，龍骨長挂壁。", "大田多黍稌，高廩若山積。", "或云穀大豐，則恐錢轉嗇。", "夏租星火急，處此未有策。", "細民一錢稅，往往亦追索。", "穀賤反傷農，此語傳自昔。", "語客且勿憂，新絲尚堪質。"]'),
('e164ce9c-918c-4089-b58a-c38ea2e0483f','送范光伯北行','裘萬頃','宋','宋诗','song-poetry','','[]','玄冥將歸休，勾芒已促裝。',180,'全唐诗/poet.song.175000.json','["玄冥將歸休，勾芒已促裝。", "江邊疎柳青，江上寒梅香。", "有客當此時，中流駕風檣。", "欲學太史公，窮汶泗沅湘。", "吾聞帝王州，雄麗幾錢塘。", "疇昔駐六龍，至今繪未央。", "鷺洲橫渺瀰，鳳臺摩青蒼。", "名山與大川，往往遥相望。", "是間或小留，不妨月徜徉。", "平生學屠龍，袖手五字章。", "茲逢賢主人，定知奏宮商。", "追李逐杜陵，相與升其堂。", "要令千萬篇，金薤垂琳琅。", "秋風鴻鴈來，因之東南翔。", "寫君磊磈胸，慰我離別腸。"]'),
('935311e0-4530-4ff5-bfa8-db83e51a41f8','安樂窩示元德弟二首  其一','裘萬頃','宋','宋诗','song-poetry','','[]','往時病僧寮，今爲安樂窩。',168,'全唐诗/poet.song.175000.json','["往時病僧寮，今爲安樂窩。", "昔病而今安，所得良已多。", "百年直須臾，一丘且婆娑。", "倦翼棲茂林，潛鱗渺重波。", "方欣隨所願，豈復知其他。", "朝來啟南窗，羣山鬰嵯峨。", "上有無心雲，乘風遠相過。", "却觀聲利場，紛紛正橫戈。", "到頭蠻與觸，勝負能幾何。", "曷若休吾心，考槃依澗阿。", "孟夏草木繁，雨餘氣清和。", "四壁環斷碑，經史星宿羅。", "幅巾據胡牀，翛然自吟哦。", "因之成此詩，要使兒童歌。"]'),
('8488eb53-9695-40bc-aeef-68939d340f31','安樂窩示元德弟二首  其二','裘萬頃','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','清泉出石竇，白雲卧山窩。',168,'全唐诗/poet.song.175000.json','["清泉出石竇，白雲卧山窩。", "淋淫乍開霽，原野歡聲多。", "吾廬近西峰，其下林婆娑。", "解衣坐磐石，持竿釣清波。", "主人忘機心，鷗鳥亦無他。", "東魯與南郭，泰山等峩峩。", "周子何人哉，自許不啻過。", "一朝離草堂，山英遂橫戈。", "折轅不得還，如此俗駕何。", "仰視前修翁，鉛刀比太阿。", "予弟山林人，心平氣自和。", "懽然樂簞瓢，笑彼葷羶羅。", "好書不厭觀，佳句時一哦。", "煩賡紫芝曲，爲我醉時歌。"]'),
('9684185a-6901-4cdc-8c59-706a6feb9c0c','題余仲祥松齋','裘萬頃','宋','宋诗','song-poetry','','[]','芳妍桃李場，紛趨欻成蹊。',144,'全唐诗/poet.song.175000.json','["芳妍桃李場，紛趨欻成蹊。", "長松坐偃蹇，遂爾不見知。", "平生異時人，不與俗轉移。", "蕭然塵埃中，擅此丘壑奇。", "窗空境逾清，四壁風來吹。", "抱琴揖蒼髯，喜氣掀兩眉。", "臭味既與同，相親不相違。", "直期閲歲寒，可但忘朝饑。", "斯正如乃翁，過處更過之。", "直比千丈幹，歷落不受羈。", "只恐大厦成，梁棟各有施。", "出處初何心，山靈勿疑渠。"]'),
('62145530-6637-4368-b4cf-761f974539f8','題伯量春風堂','裘萬頃','宋','宋诗','song-poetry','','[]','未登春風堂，嘗讀春風詩。',192,'全唐诗/poet.song.175000.json','["未登春風堂，嘗讀春風詩。", "春風不易得，令人每懷思。", "一堂誰獨無，所至皆有之。", "奈何堂中人，此意多背馳。", "聽雨不對牀，煮豆先燃萁。", "寧賡粟布歌，不肯吹塤箎。", "和氣自此傷，怨怒無休時。", "遂令君家堂，獨立修江湄。", "昔我嘗宦遊，兄弟輕別離。", "自從失予季，憂悶鬢成絲。", "仲叔幸無他，相從日怡怡。", "數榻松竹間，頗與我輩宜。", "濁醪無獨斟，陳編有同披。", "從今當杜門，共試春風詞。", "燕谷恐尚寒，暖律冀一吹。", "君能不靳否，春風元不私。"]'),
('add4de89-f609-40c8-982e-08e909e5bf9c','錢塘別吳長文司理','裘萬頃','宋','宋诗','song-poetry','','[]','同心而異鄉，既見復輕別。',144,'全唐诗/poet.song.175000.json','["同心而異鄉，既見復輕別。", "豈終無會期，南北渺難必。", "郵亭君與我，强飯再三說。", "此意非不領，欲話聲已咽。", "肩輿使前驅，分手大江側。", "升高輒回首，猶擬望顔色。", "予家古南州，勝友固不乏。", "如君相知深，千百未見一。", "君才十倍我，君德更剛直。", "贈行詩滿紙，字字良有益。", "誰與趣我去，胡不緩旬浹。", "噬臍悵弗及，寫心寄愁絕。"]'),
('ebebd779-732f-46ab-bf23-bf1ec7f21c73','咨咨草根蟲','裘萬頃','宋','宋诗','song-poetry','','[]','咨咨草根蟲，瑟瑟葉上雨。',96,'全唐诗/poet.song.175000.json','["咨咨草根蟲，瑟瑟葉上雨。", "休休退食人，落落誰與語。", "陳編竟日披，陋室隨時處。", "此心苟自樂，貧賤亦得所。", "夷齊雖餓死，清風冠千古。", "顔子瓢屢空，宣父極稱許。", "但當守吾仁，晉楚何足數。", "試看松與柏，矯矯傲寒暑。"]'),
('6d6e6702-f4b5-46c2-938f-81e697efea76','夜坐薦福寺次王成之韻','裘萬頃','宋','宋诗','song-poetry','','[]','鞭鸞未暇相追逐，且向祇園止君宿。',64,'全唐诗/poet.song.175000.json','["鞭鸞未暇相追逐，且向祇園止君宿。", "清談待得月華生，窗戶明明耿殘燭。", "誰令泉石墮吾前，洗淨人間絲與竹。", "風帆明發君不留，此樂只應吾所獨。"]'),
('45637d8a-1626-4982-b318-955d77d8d058','厭原山中曉行','裘萬頃','宋','宋诗','song-poetry','','[]','碧雞夜半聲啁哳，喚起幽人步林樾。',64,'全唐诗/poet.song.175000.json','["碧雞夜半聲啁哳，喚起幽人步林樾。", "秋高風露著羣木，無數寒花泣明月。", "松篁一徑宛如畫，石溜涓涓更清絕。", "山巔便好結茅廬，莫待他年鬢成雪。"]'),
('fbb954ca-a330-4257-8dd2-2c522e77d805','秋試示諸兒','裘萬頃','宋','宋诗','song-poetry','','[]','漠漠輕雲弄寒影，霏霏小雨生秋興。',64,'全唐诗/poet.song.175000.json','["漠漠輕雲弄寒影，霏霏小雨生秋興。", "黄槐開盡舉子心，丹桂喜傳仙籍信。", "竹齋雙手縮袖間，坐看羣兒鏖一戰。", "春風躍馬不爲難，此去毋言日邊遠。"]'),
('32b10b7a-4fc8-480d-8b1b-6df9ee919932','十二月大雨','裘萬頃','宋','宋诗','song-poetry','','[]','一冬都無五日寒，赤日杲杲后土乾。',64,'全唐诗/poet.song.175000.json','["一冬都無五日寒，赤日杲杲后土乾。", "水官丐歸帝弗許，詰朝不雨吾戮汝。", "斯須便放大瓢傾，一洗萬里塵埃清。", "不妨更作尺深雪，桑榆之功尚堪說。"]'),
('26eec91b-d876-46c5-839b-2b84ce63dc90','燈下偶次前韻','裘萬頃','宋','宋诗','song-poetry','','[]','北風吹雨夜正寒，北窗吟詩舌欲乾。',64,'全唐诗/poet.song.175000.json','["北風吹雨夜正寒，北窗吟詩舌欲乾。", "千辛萬苦浪如許，飯顆山頭誰著汝。", "何如一尊隨意傾，酒酣不問濁與清。", "明朝縱有三尺雪，灞陵詩句無庸說。"]'),
('7a8afd24-4898-4276-a592-30df80d5bae6','贈拂雲主人','裘萬頃','宋','宋诗','song-poetry','','[]','十年作計須種木，一日不可使無竹。',64,'全唐诗/poet.song.175000.json','["十年作計須種木，一日不可使無竹。", "道人於此得三昧，綠霧中間著蒼玉。", "拂雲誰爲名其居，我亦心同雲卷舒。", "相期直覓飛霞佩，不用重拈種樹書。"]'),
('d3e640e7-c19f-40a9-80a1-65c7819fb918','次余主簿仲庸梅韻','裘萬頃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春醪欲冰木欲折，急雨風吹不成雪。',96,'全唐诗/poet.song.175000.json','["春醪欲冰木欲折，急雨風吹不成雪。", "玉妃夜墮廣寒宮，開作寒花賽清絕。", "未須千樹插山巔，且要幾枝橫水邊。", "暗香疎影尚無恙，憑誰喚起西湖仙。", "不妨琢句更馳送，一洗十年塵土夢。", "鐵心元不爲渠回，眼底珠璣聊簸弄。"]'),
('11a9894b-b4d3-4d78-9863-7796b9d3d9c6','再呈仲庸','裘萬頃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','芳枝莫遣風吹折，要看枝頭千點雪。',96,'全唐诗/poet.song.175000.json','["芳枝莫遣風吹折，要看枝頭千點雪。", "孤山疇昔盛開時，十里香颸飛不絕。", "蹇馿烏帽照霜顛，長吟竟日溪橋邊。", "自從和靖收聲後，一時翰墨歸坡仙。", "只今往事飛鴻送，寂寞西湖投老夢。", "花開花落謾傷心，明月清湍誰與弄。"]'),
('fbd012c4-7f8a-4c4c-a697-4bbb78b4b9c8','贈仙茅道士','裘萬頃','宋','宋诗','song-poetry','','[]','茅齋高卧日將午，自起鈎簾試香縷。',96,'全唐诗/poet.song.175000.json','["茅齋高卧日將午，自起鈎簾試香縷。", "門前剝啄誰叩門，杖履蕭然顔貌古。", "亟呼兒童延入座，餉以清風滌袢暑。", "論醫說相俱第一，觸熱遠來尋我語。", "嗟哉人生浪辛苦，到頭事事皆塵土。", "萬錢鼎食吾無取，君有仙茅幸分與。"]'),
('1d02bd3a-07d6-453c-84fb-67d7f32205a1','寄題胡穡齋盆池','裘萬頃','宋','宋诗','song-poetry','','[]','穡齋主人嗜泉石，一舸來家楚江側。',128,'全唐诗/poet.song.175000.json','["穡齋主人嗜泉石，一舸來家楚江側。", "水光山色晴逼人，中有軒窗更清絕。", "汲泉爲池良不惡，坐見漣漪照金碧。", "匳開寶鑑大如許，月墮冰輪光欲溢。", "何須泰華尋玉井，謾說仇池有仙穴。", "箇中風露無處著，長爲昭華洗炎熱。", "嗟予疎懶真成癖，想像哦詩竟何益。", "安得身爲穡齋客，醉卧池邊聽錦瑟。"]'),
('25fac07c-ea43-4451-9e40-d4b3583701e6','雨後','裘萬頃','宋','宋诗','song-poetry','','[]','秋事雨已畢，秋容晴爲妍。',48,'全唐诗/poet.song.175000.json','["秋事雨已畢，秋容晴爲妍。", "新香浮䆉䅉，餘潤溢潺湲。", "機杼蛩聲裏，犁鋤鷺影邊。", "吾生一何幸，田里又豐年。"]'),
('78e2644d-8e34-4797-bd87-0906bc285ebf','凉風','裘萬頃','宋','宋诗','song-poetry','','[]','凉風幾時動，日暮已秋聲。',48,'全唐诗/poet.song.175000.json','["凉風幾時動，日暮已秋聲。", "稍稍月華白，紛紛林影清。", "予懷元不惡，世事巧相攖。", "所願西成後，邊頭息戍兵。"]'),
('4d2ab1ed-bb3d-46f3-bc26-10ad6693a449','用鄭浮梁韻簡圜師二首  其一','裘萬頃','宋','宋诗','song-poetry','','[]','杖屨山蹊窄，鐘魚佛界深。',48,'全唐诗/poet.song.175000.json','["杖屨山蹊窄，鐘魚佛界深。", "寒梅殘屋角，春薺老牆陰。", "一水元無恙，扁舟尚可尋。", "煩師掬清溜，爲我洗塵心。"]'),
('890ecac5-5ce9-4ec6-9dc8-72511260a1d9','用鄭浮梁韻簡圜師二首  其二','裘萬頃','宋','宋诗','song-poetry','','[]','古寺規模壯，空山歲月深。',48,'全唐诗/poet.song.175000.json','["古寺規模壯，空山歲月深。", "春排千樹綠，雲墮一溪陰。", "地僻人稀到，官閑我得尋。", "歸來詫清賞，未覺負初心。"]'),
('c5cd0bd5-8ecf-43d3-91f8-b7875c4449d2','次黄存之韻','裘萬頃','宋','宋诗','song-poetry','','[]','客宦何時了，官居又歲餘。',48,'全唐诗/poet.song.175000.json','["客宦何時了，官居又歲餘。", "歸心五湖夢，病眼一牀書。", "近作君能富，新功我略無。", "不妨賦遊獵，會有薦相如。"]'),
('39303264-2ac7-4a2c-9a77-72eb78057a1c','暘谷偶成','裘萬頃','宋','宋诗','song-poetry','','[]','愛日袪愁霧，微和散積陰。',48,'全唐诗/poet.song.175000.json','["愛日袪愁霧，微和散積陰。", "一窗塵外趣，萬竹歲寒心。", "士要崇清節，吾將老故林。", "抱琴聊一醉，何用覓知音。"]'),
('bc7d4322-3fdd-4d24-8de7-9dbea3fab66f','書率更西林碑','裘萬頃','宋','宋诗','song-poetry','','[]','冉冉老將至，區區心已疲。',48,'全唐诗/poet.song.175000.json','["冉冉老將至，區區心已疲。", "文章非世用，字畫謾兒嬉。", "廬阜多名剎，隋人有斷碑。", "驪黄雖易辯，堂奧未容窺。"]'),
('2a4d81fc-2a6c-4d4d-ab42-46de5209b8b3','晚歲送館人歸省','裘萬頃','宋','宋诗','song-poetry','','[]','不厭冰霜路，衝寒辦一歸。',48,'全唐诗/poet.song.175000.json','["不厭冰霜路，衝寒辦一歸。", "晨雞戒鞍馬，春酒壽庭闈。", "燈火知辛苦，雲霄會奮飛。", "相期紆綠綬，非但戲斑衣。"]'),
('9c1a34f5-d3f2-4bd0-a950-8df6f148477b','別敬叔','裘萬頃','宋','宋诗','song-poetry','','[]','筆硯君無間，冰霜歲又除。',48,'全唐诗/poet.song.175000.json','["筆硯君無間，冰霜歲又除。", "諸生得模範，六藝共耕鋤。", "松菊淵明宅，蓬蒿仲蔚居。", "相望儻相憶，時寄數行書。"]'),
('ab482ea3-f9a8-4402-af3b-f62cc0263508','贈畫工','裘萬頃','宋','宋诗','song-poetry','','[]','綵筆三生夢，春蓮萬葉花。',48,'全唐诗/poet.song.175000.json','["綵筆三生夢，春蓮萬葉花。", "笑人爲市道，隨分足生涯。", "山路淨如水，溪流淺見沙。", "能來良不惡，看我傲煙霞。"]'),
('f842c61e-df45-4db5-9d8f-b5be82f8c82f','次胡伯仁韻','裘萬頃','宋','宋诗','song-poetry','','[]','山長飛鳥急，江闊去帆微。',48,'全唐诗/poet.song.175000.json','["山長飛鳥急，江闊去帆微。", "唱晚幾漁笛，憑高一釣磯。", "從君濯冰雪，滿袖得珠璣。", "三歎不能已，歸來吟夕暉。"]'),
('35cdedab-49c5-4604-875d-5e3a27c3c4d6','書晁文元道院集','裘萬頃','宋','宋诗','song-poetry','','[]','華屋金狨座，雕鞍駟馬車。',48,'全唐诗/poet.song.175000.json','["華屋金狨座，雕鞍駟馬車。", "才堪誇世俗，早已落丘墟。", "此病久沈痼，無人解掃除。", "千年子晁子，道院有遺書。"]'),
('c57e73e1-60c9-48b1-b4ec-f90203eb0884','送范二丈入藍田書院二首  其一','裘萬頃','宋','宋诗','song-poetry','','[]','今代崔斯立，才高不負丞。',48,'全唐诗/poet.song.175000.json','["今代崔斯立，才高不負丞。", "君方爲重客，人謂得良朋。", "敏捷朝千字，辛勤夜一燈。", "明年冠秋試，萬里看飛騰。"]'),
('adcadcf5-a740-494b-a5cb-1c35ef5260c4','送范二丈入藍田書院二首  其二','裘萬頃','宋','宋诗','song-poetry','','[]','君在淳熙日，嘗師陸監丞。',48,'全唐诗/poet.song.175000.json','["君在淳熙日，嘗師陸監丞。", "今爲後死者，樂有遠來朋。", "此道未墜地，他時要續燈。", "病夫力不足，拱立看鶱騰。"]'),
('2f36719a-704f-4927-900d-b56c23dd5d9c','夜坐再用韻二首  其一','裘萬頃','宋','宋诗','song-poetry','','[]','洪井今真隠，長沙昔謾丞。',48,'全唐诗/poet.song.175000.json','["洪井今真隠，長沙昔謾丞。", "餘生付巖壑，拙宦愧交朋。", "飯菜渾忘肉，囊螢足代燈。", "詩成夜將半，雲際月騰騰。"]'),
('25c5d52b-5f1a-4bb9-aab0-a3929596697f','夜坐再用韻二首  其二','裘萬頃','宋','宋诗','song-poetry','','[]','家有輞川集，人如王右丞。',48,'全唐诗/poet.song.175000.json','["家有輞川集，人如王右丞。", "琴書多暇日，觴咏盡高朋。", "擬脫雲山屐，來分夜案燈。", "新詩要傳寫，病眼任瞢騰。"]'),
('a6326fc3-4968-4dfd-9fda-88811a2df7a5','送胡仲立入京','裘萬頃','宋','宋诗','song-poetry','','[]','昔對延英日，諸公歎弗如。',48,'全唐诗/poet.song.175000.json','["昔對延英日，諸公歎弗如。", "敢言天下事，不負案頭書。", "此去朝雙闕，懸知有異除。", "榮途方著脚，未用曳長裾。"]'),
('a23138e5-563a-47fe-96b4-37f870e16c1f','次施真人韻','裘萬頃','宋','宋诗','song-poetry','','[]','素韠方多難，丹砂儻一逢。',48,'全唐诗/poet.song.175000.json','["素韠方多難，丹砂儻一逢。", "勿疑蕉覆鹿，會見竹成龍。", "澗水遠仍潔，巖花幽更濃。", "行行望仙宇，知在最高峰。"]'),
('64e4ca1b-da5b-437d-a1a5-7e7e13ae08f4','偶成','裘萬頃','宋','宋诗','song-poetry','','[]','松徑煩風掃，柴門爲雨扃。',48,'全唐诗/poet.song.175000.json','["松徑煩風掃，柴門爲雨扃。", "行携道院集，坐對敬齋銘。", "好事心常記，閑談耳不聽。", "觀空爲時悞，無異醉初醒。"]'),
('8a10c657-d0cb-499d-ac21-7f3dd72f9294','老屋','裘萬頃','宋','宋诗','song-poetry','','[]','老屋久欹側，隨宜聊拄撐。',48,'全唐诗/poet.song.175000.json','["老屋久欹側，隨宜聊拄撐。", "吾今且共住，緣盡會須行。", "雨打從教壞，風摇不用驚。", "世間虛幻相，聚散本無情。"]'),
('6b50630d-4b1e-4bf5-aa05-e0c0c449be58','留淺沙','裘萬頃','宋','宋诗','song-poetry','','[]','故山豈不好，蕭寺亦堪居。',48,'全唐诗/poet.song.175000.json','["故山豈不好，蕭寺亦堪居。", "作意多成礙，無心始自如。", "鐘魚飽香積，枕簟熟華胥。", "但惜詩成後，旁無阿買書。"]'),
('511f2d61-28eb-4fbd-b0e5-a68bd1d45f77','寄題喻高士澹軒','裘萬頃','宋','宋诗','song-poetry','','[]','世事邯鄲枕，生涯老子書。',48,'全唐诗/poet.song.175000.json','["世事邯鄲枕，生涯老子書。", "能知澹中味，雅稱竹間居。", "石徑排雲入，霜根带月鋤。", "紛華不到眼，贏得玩清虛。"]'),
('217db787-fcad-4d35-8578-d18e238cb6a6','晚步','裘萬頃','宋','宋诗','song-poetry','','[]','日落欲閉戶，風清聊杖藜。',48,'全唐诗/poet.song.175000.json','["日落欲閉戶，風清聊杖藜。", "千山猶带雨，一徑已無泥。", "㶁㶁水聲急，悠悠雲影低。", "催歸緣底事，著意旁人啼。"]'),
('94bc879b-06e6-45a6-a3c6-27bf17f89cb1','榮姪試周','裘萬頃','宋','宋诗','song-poetry','','[]','汝生方滿歲，伯髮已星星。',48,'全唐诗/poet.song.175000.json','["汝生方滿歲，伯髮已星星。", "桑苧甘投老，蘭蓀喜向榮。", "席間無一印，帷下有諸經。", "莫學魚兒戲，來年快聚螢。"]'),
('290a1bde-d088-4762-9bb5-a255ce08b388','題洪內翰爽榭','裘萬頃','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','霧閣雲窗天外安，懸知幽趣勝人間。',64,'全唐诗/poet.song.175000.json','["霧閣雲窗天外安，懸知幽趣勝人間。", "簾櫳夜月浮銀海，桃李春風醉玉山。", "自笑紅塵無暇日，浪憑清夢覓商顔。", "何如飛佩隨君後，細看匡廬紫翠鬟。"]'),
('4f1c6a22-1bbc-4cef-a03c-089b6e405905','次元德弟示從龍入學','裘萬頃','宋','宋诗','song-poetry','','[]','生兒雖小莫憐渠，學問工夫在謹初。',64,'全唐诗/poet.song.175000.json','["生兒雖小莫憐渠，學問工夫在謹初。", "今日從師良不惡，他年閉戶反成疎。", "雙親未老身無事，諸父能文家有書。", "好與汝兄俱努力，後生叢裏試羣居。"]'),
('2e63339b-55d0-49f1-9d0a-d6c9a419fc75','次洪內相菊亭','裘萬頃','宋','宋诗','song-poetry','','[]','詩僊種菊未多時，因菊名亭早有詩。',64,'全唐诗/poet.song.175000.json','["詩僊種菊未多時，因菊名亭早有詩。", "欲爲寒花標晚節，故將新句寄東籬。", "平生未省翻三峽，高處那能贊一辭。", "便得從容侍公側，回頭已是十年遲。"]'),
('5477b99e-a613-410a-a1ea-b5fc35a59d47','次洪內相梅亭','裘萬頃','宋','宋诗','song-poetry','','[]','人間多是梅開後，旋踵東籬事故常。',64,'全唐诗/poet.song.175000.json','["人間多是梅開後，旋踵東籬事故常。", "那得紅簾卷朱戶，細看素質傲清霜。", "一生寄興雲山外，幾度搔頭江路傍。", "咫尺名園身未到，夜窗羞對返魂香。"]'),
('253426bd-dd8c-4180-a4e3-af161324e163','夜坐','裘萬頃','宋','宋诗','song-poetry','','[]','爐火篝燈孰與同，此心吾欲付冥鴻。',64,'全唐诗/poet.song.175000.json','["爐火篝燈孰與同，此心吾欲付冥鴻。", "茅簷已作十旬雨，蕙帳不禁連夜風。", "一段清愁詩句裏，十分寒事酒杯中。", "溪雲未用安排雪，且聽梅花試小紅。"]'),
('81e1a2bb-ccbd-4e32-a289-82893d7f2bc6','雪','裘萬頃','宋','宋诗','song-poetry','','[]','天花一夜泄春機，飛墜人間片片奇。',64,'全唐诗/poet.song.175000.json','["天花一夜泄春機，飛墜人間片片奇。", "有色有光欺柳絮，無聲無臭點梅枝。", "縱橫萬舞風回處，表裏雙清月霽時。", "此景惟詩可摹寫，却憐老去不工詩。"]'),
('be55f43a-4ead-4363-a723-b46277dc2da0','寄高菊磵謝惠詩集','裘萬頃','宋','宋诗','song-poetry','','[]','高名如斗夜垂天，無地追思每自憐。',64,'全唐诗/poet.song.175000.json','["高名如斗夜垂天，無地追思每自憐。", "正欲爲君尋五老，乃蒙因我到雙泉。", "新詩妙絕閒方就，稚子携歸喜欲顛。", "此去湖邊不多遠，秋風當覓釣魚船。"]'),
('6e455879-3762-4f59-b785-ed53f2707979','寄元齡弟','裘萬頃','宋','宋诗','song-poetry','','[]','夜牀風雨夢到處，東湖西山如接連。',64,'全唐诗/poet.song.175000.json','["夜牀風雨夢到處，東湖西山如接連。", "安信喜隨烏鵲後，雅懷知寄白鷗邊。", "軒窗春動花陰滿，圖史香浮墨色鮮。", "個裏詩書應有味，不妨兼讀養生篇。"]'),
('02d4b221-cf55-4dfd-9df0-a120acf8c133','次元德弟','裘萬頃','宋','宋诗','song-poetry','','[]','寧逐春風上下狂，懶從桃李借恩光。',64,'全唐诗/poet.song.175000.json','["寧逐春風上下狂，懶從桃李借恩光。", "只應朝市風波惡，不似山林氣味長。", "莫惜舉杯邀太白，要看騎馬似知章。", "南征他日如相憶，詩句還須付革囊。"]'),
('b90a597a-367d-46aa-becd-0e22f6a9070e','玉山道中時赴掌故之命','裘萬頃','宋','宋诗','song-poetry','','[]','麥苗堆綠菜花黄，一簇人家古道傍。',64,'全唐诗/poet.song.175000.json','["麥苗堆綠菜花黄，一簇人家古道傍。", "酒熟不妨邀里巷，年豐贏得事農桑。", "世情只說宦游好，客裏那知歸興長。", "我有平生蓑笠在，釣絲何日理斜陽。"]'),
('eb8938ab-aacb-4424-8b2f-32821272b2c1','端午上饒道中','裘萬頃','宋','宋诗','song-poetry','','[]','一春留滯在京華，午日依前未到家。',64,'全唐诗/poet.song.175000.json','["一春留滯在京華，午日依前未到家。", "細葛香羅素無望，黄塵烏帽亦堪嗟。", "爭舟野渡人如簇，立馬郵亭日欲斜。", "遥想塤箎獻親壽，綵衣羅拜酌流霞。"]'),
('4928c517-10ea-4238-9420-1805185b6847','臨安別余求之','裘萬頃','宋','宋诗','song-poetry','','[]','長安車蓋喜如雲，邂逅惟君是故人。',64,'全唐诗/poet.song.175000.json','["長安車蓋喜如雲，邂逅惟君是故人。", "風月滿懷情灑落，珠璣撒紙句清新。", "携來客裏一尊酒，洗盡湖邊十里塵。", "富貴功名丈夫事，別離無用淚沾巾。"]'),
('7ddf5371-19ad-49f8-ab27-0faadd7d7cf8','鄉人羅朝宗與兵部尚書京公有舊將往見之遇予於樂平因餞別','裘萬頃','宋','宋诗','song-poetry','','[]','四時成歲秋云暮，九月肅霜天漸寒。',64,'全唐诗/poet.song.175000.json','["四時成歲秋云暮，九月肅霜天漸寒。", "有客褰裳涉鄱水，逢人劇口話長安。", "懸知欲聽星辰履，厭見從來苜蓿盤。", "姑舉一觴餞行色，無魚長鋏切休彈。"]'),
('af8bc085-ecf4-4c53-8e2d-9aec82501f0c','暘谷偶成','裘萬頃','宋','宋诗','song-poetry','','[]','竹近頗忻衣袂爽，苔深長恐履痕侵。',64,'全唐诗/poet.song.175000.json','["竹近頗忻衣袂爽，苔深長恐履痕侵。", "夜燈四壁圖書影，曉日一牀花木陰。", "載酒只今誰好事，絕弦從昔爲知音。", "區區外物成何用，慎勿緣渠愁此心。"]'),
('79493671-985b-4ee8-bfb7-ef46c516552b','入京道中風雨因賦此遂退休','裘萬頃','宋','宋诗','song-poetry','','[]','新築書堂壁未乾，馬蹄催我上長安。',64,'全唐诗/poet.song.175000.json','["新築書堂壁未乾，馬蹄催我上長安。", "兒時只道爲官好，老去方知行路難。", "千里關山千里夢，一番風雨一番寒。", "何如靜坐茅齋下，翠竹蒼梧仔細看。"]'),
('86e742a9-fcf2-4890-925e-7cfb1603095e','閑居','裘萬頃','宋','宋诗','song-poetry','','[]','閑居最與性相便，勤即繙書懶即眠。',64,'全唐诗/poet.song.175000.json','["閑居最與性相便，勤即繙書懶即眠。", "終日閉門真省事，有時面壁似耽禪。", "大椿歲籥祈親壽，斷簡生涯聽子傳。", "待問洪崖覓丹訣，白雲深處引寒泉。"]'),
('197be58d-02bb-43e7-9f52-9672b5ddeeb2','松花開竹笋茂喜而詠之','裘萬頃','宋','宋诗','song-poetry','','[]','繁花密笋暮春時，妝點園林一段奇。',64,'全唐诗/poet.song.175000.json','["繁花密笋暮春時，妝點園林一段奇。", "金粉生香風細細，斑衣留潤露垂垂。", "品高宜入神僊藥，節勁終全冰雪姿。", "笑彼杏桃兒女態，謾爭豔冶媚山歧。"]'),
('0b979d86-aab2-4a85-9ac9-d2163b9fa818','睡起書懷時諸公相勉再出','裘萬頃','宋','宋诗','song-poetry','','[]','北窗終日廢書眠，一枕清風直萬錢。',64,'全唐诗/poet.song.175000.json','["北窗終日廢書眠，一枕清風直萬錢。", "雲度茅簷輕冉冉，泉生石砌淨涓涓。", "不嫌雨脚花間注，要聽秋聲屋外傳。", "三徑初成吾欲老，幕中何用泛紅蓮。"]'),
('46b578d3-a703-42ca-8734-a801549bbf2c','有感時與李弘齋有約','裘萬頃','宋','宋诗','song-poetry','','[]','去年今日西歸客，曝背茅簷又一冬。',64,'全唐诗/poet.song.175000.json','["去年今日西歸客，曝背茅簷又一冬。", "歲月催人雖迅速，簡編於我却從容。", "知名焉用詩千首，養病聊須酒一鍾。", "早晚杖藜修水去，故人有約許相從。"]'),
('00c2c3fb-c58a-4be4-9ec1-afeaea82f7c6','用前韻謝伯量過訪山中','裘萬頃','宋','宋诗','song-poetry','','[]','勝遊千里笑談中，雪片梅花正仲冬。',64,'全唐诗/poet.song.175000.json','["勝遊千里笑談中，雪片梅花正仲冬。", "肯向席門尋孺子，更能草具重茅容。", "春風頓覺生寒谷，夜榻惟愁聽曉鍾。", "半世坡梅門下客，乃今何幸得過從。"]'),
('61610fca-2090-408f-9668-7e53e1956191','送胡仲衡','裘萬頃','宋','宋诗','song-poetry','','[]','憶昔樵江一見君，喜君吃吃善談文。',64,'全唐诗/poet.song.175000.json','["憶昔樵江一見君，喜君吃吃善談文。", "別來歲月今如許，書裏工夫想得勤。", "近世起家多白屋，幾人馳志在青雲。", "穡齋已踏賢關路，更有諸孫策異勳。"]'),
('a5b084b9-7ffa-4ca8-b439-338858ed27df','喜范光伯相過','裘萬頃','宋','宋诗','song-poetry','','[]','章江東下幾灣洄，誰伴臞僊夜探梅。',64,'全唐诗/poet.song.175000.json','["章江東下幾灣洄，誰伴臞僊夜探梅。", "離別不禁詩社冷，遭逢莫放酒船回。", "冰霜滿眼歲將換，花柳轉頭春又來。", "安得飛騰九霄外，鞭鸞笞鳳日相陪。"]'),
('ed3dfc5f-d2da-4879-a9f6-a86045a6e68f','懷范光伯再用韻','裘萬頃','宋','宋诗','song-poetry','','[]','梅邊流水碧洄洄，都把相思付折梅。',64,'全唐诗/poet.song.175000.json','["梅邊流水碧洄洄，都把相思付折梅。", "十載不禁雙淚落，一尊期慰九腸回。", "驚殘蝶夢鵲空喜，望斷馬蹄人不來。", "咫尺雲山尚如此，天涯那解得追陪。"]'),
('ffc0e714-e915-47ce-afc0-4c0223f65106','次光伯韻','裘萬頃','宋','宋诗','song-poetry','','[]','竹逕當年手自開，只今無處著莓苔。',64,'全唐诗/poet.song.175000.json','["竹逕當年手自開，只今無處著莓苔。", "絕憐此地過從少，頼有高人時復來。", "籬下久霜猶有菊，水邊近臘正多梅。", "我云眷眷三年別，君莫怱怱一夕回。"]'),
('ad4370c5-f321-4112-ae59-d8e75f06c33f','錢塘次孫教南韻','裘萬頃','宋','宋诗','song-poetry','','[]','簿領歸來得泮宮，一時衮衮任諸公。',64,'全唐诗/poet.song.175000.json','["簿領歸來得泮宮，一時衮衮任諸公。", "市朝競逐利名走，草木誰爲臭味同。", "霅水不妨披宿霧，蓬山正要挹清風。", "塵埃不得從君後，豈但他時媿兩翁。"]'),
('99ada68d-f076-4992-bc41-a6e64fae6189','次朱震遠韻','裘萬頃','宋','宋诗','song-poetry','','[]','芳池綠水自生肥，上有軒窗隠翠微。',64,'全唐诗/poet.song.175000.json','["芳池綠水自生肥，上有軒窗隠翠微。", "花竹舊嘗開小逕，門闌今又啟重扉。", "直須閶闔排雲去，要看長安躍馬歸。", "詞賦合魁天下士，春光端不負劉煇。"]'),
('3eeb43c7-91e6-43fc-8120-64da6fe5f0d0','次王成之咏梅','裘萬頃','宋','宋诗','song-poetry','','[]','誰遣冰魂照夕陽，摇摇一任北風凉。',64,'全唐诗/poet.song.175000.json','["誰遣冰魂照夕陽，摇摇一任北風凉。", "眼前共有幾多蕊，鼻觀胡爲如此香。", "佳實會須歸列鼎，孤標已自壓羣芳。", "濡毫我欲從君賦，未害平生鐵石腸。"]'),
('c86d4462-67ab-4725-9e02-aa626ef57ab7','讀伯仁詩卷','裘萬頃','宋','宋诗','song-poetry','','[]','憶昔從君漁釣時，小舟行徧楚江湄。',64,'全唐诗/poet.song.175000.json','["憶昔從君漁釣時，小舟行徧楚江湄。", "僧房夜月琴三疊，客舍秋風酒一巵。", "別後相思梅折盡，書成欲寄鴈來遲。", "蛩聲驚覺寒窗夢，自起挑燈讀舊詩。"]'),
('f7d8377b-77fb-4b3a-9066-44ce541792d6','不雨','裘萬頃','宋','宋诗','song-poetry','','[]','農時閲月天不雨，嘉穀叢中龜兆生。',64,'全唐诗/poet.song.175000.json','["農時閲月天不雨，嘉穀叢中龜兆生。", "雲勢只隨風聚散，鳩聲空報客陰晴。", "半生憂國髮欲白，一飽無期心屢驚。", "尚願秋陽化甘澍，稍甦枯槁望西成。"]'),
('fec291cb-f184-4c70-9acc-d76d00ec550b','乙亥六月鄉民祈雨壽春祠下嘉澍既降槁苗盡興萬口一辭頌神之德予喜聊成俚語以書祠壁','裘萬頃','宋','宋诗','song-poetry','','[]','憂時曾上天庭疏，憫物今爲旱歲霖。',64,'全唐诗/poet.song.175000.json','["憂時曾上天庭疏，憫物今爲旱歲霖。", "一夕風霆百川水，四郊香火萬民心。", "山巔定有煙霞宅，夜半常聞鐘磬音。", "儻許塵蹤拜仙馭，願營茅屋老雲岑。"]'),
('73d6c5b5-e044-42c0-8951-6be3859f581e','郊行即事','裘萬頃','宋','宋诗','song-poetry','','[]','病來多日廢將迎，試命巾車作此行。',64,'全唐诗/poet.song.175000.json','["病來多日廢將迎，試命巾車作此行。", "稻實滿田秋事了，松陰堆徑午凉生。", "數山見我爭傾蓋，一水邀人請濯纓。", "却憶吾廬南浦外，何時得與白鷗盟。"]'),
('8ff1fa93-e6a0-48b3-bbe2-447ac4f034ee','兀坐有感','裘萬頃','宋','宋诗','song-poetry','','[]','忘言編簡倦三復，適意絲桐聊再行。',64,'全唐诗/poet.song.175000.json','["忘言編簡倦三復，適意絲桐聊再行。", "已共白雲論久要，更尋青鳥問長生。", "按行泉石苔侵屨，披拂松篁露濕纓。", "此事洪崖知我舊，歸與端合與同盟。"]'),
('4c75960f-58e1-49c8-b682-ba1db3cf25a5','有感','裘萬頃','宋','宋诗','song-poetry','','[]','政爾雙泉憶舊游，柳江聞又有歸舟。',64,'全唐诗/poet.song.175000.json','["政爾雙泉憶舊游，柳江聞又有歸舟。", "誰能不作千年調，夢斷真成萬事休。", "傾蓋向來情莫逆，奠芻無計淚空流。", "重雲已失鵾鵬影，愁絕滄浪一白鷗。"]'),
('421af976-159d-4c60-81a4-13362dc107c8','送張高安入京','裘萬頃','宋','宋诗','song-poetry','','[]','青衫十載蟾宮客，黑綬三年鳳嶺頭。',64,'全唐诗/poet.song.175000.json','["青衫十載蟾宮客，黑綬三年鳳嶺頭。", "循吏聲名武陽令，故家風味富平侯。", "江邊休歎雙鳬去，天上行看一網收。", "八簉鵷班立仙仗，莫忘回首顧沙鷗。"]'),
('e7a43e07-3386-4196-a013-c7f37b24cde7','用黄子益韻二首  其一','裘萬頃','宋','宋诗','song-poetry','','[]','青衫日日困塵沙，安用浮名與世誇。',64,'全唐诗/poet.song.175000.json','["青衫日日困塵沙，安用浮名與世誇。", "已過半生真似夢，未荒三徑且還家。", "恨無沈水紆香穗，喜有寒泉瀹茗花。", "袖却西歸遮日手，園林幽處看桑麻。"]'),
('bae88582-0b58-45b8-bd57-faef1d164109','用黄子益韻二首  其二','裘萬頃','宋','宋诗','song-poetry','','[]','睡起忻然思慮少，病餘猶覺應酬艱。',64,'全唐诗/poet.song.175000.json','["睡起忻然思慮少，病餘猶覺應酬艱。", "招摇風月聊須竹，收拾雲煙幸有山。", "但要世緣隨手斷，莫憂詩債幾時還。", "追奔富貴非吾事，且占林泉一味閑。"]'),
('3ae16266-370c-41d9-ae43-537e602f5169','寄劉擇之新居成','裘萬頃','宋','宋诗','song-poetry','','[]','西風吹鴈過吾廬，特地傳君一紙書。',64,'全唐诗/poet.song.175000.json','["西風吹鴈過吾廬，特地傳君一紙書。", "九載不須論舊事，萬金良喜得新居。", "春回院落花侵座，雨過池塘水遶除。", "我欲退之門下去，却愁無處覓金魚。"]'),
('d942aa98-0a13-4b9d-844f-bd612ce4ec9f','題懷秀堂','裘萬頃','宋','宋诗','song-poetry','','[]','莫教滿地長莓苔，杖屨從今日日來。',64,'全唐诗/poet.song.175000.json','["莫教滿地長莓苔，杖屨從今日日來。", "曲徑要隨松巷轉，柴門須對石橋開。", "牆頭花木因時種，案上圖書任意堆。", "幸有林泉可投老，忍將雙脚踏塵埃。"]'),
('c6eec8db-12b2-49a0-815d-751e90af2085','竹齋述事','裘萬頃','宋','宋诗','song-poetry','','[]','夢魂驚斷渺難續，卧聽竹裏風泠泠。',64,'全唐诗/poet.song.175000.json','["夢魂驚斷渺難續，卧聽竹裏風泠泠。", "寒蛩爭鳴遶四壁，缺月半墮橫疎櫺。", "平生細字髮欲白，午夜短檠燈尚青。", "稻粱作計吾不願，願學滄海鴻飛冥。"]'),
('37aa9809-4969-4c98-8ddb-08532a3dbcd7','大雪用前韻五首  其一','裘萬頃','宋','宋诗','song-poetry','','[]','雨師風伯妙天機，幻出乾坤一段奇。',64,'全唐诗/poet.song.175000.json','["雨師風伯妙天機，幻出乾坤一段奇。", "晚對青山渾似畫，夜看黄卷可忘饑。", "金貂換酒非吾事，鐵甲屯邊正此時。", "失國殘胡應凍死，書生猶賦采薇詩。"]'),
('d9a5f684-be3d-4f52-ad01-161ace5888d3','大雪用前韻五首  其二','裘萬頃','宋','宋诗','song-poetry','','[]','天孫雲裏散支機，飛墜人間分外奇。',64,'全唐诗/poet.song.175000.json','["天孫雲裏散支機，飛墜人間分外奇。", "勾引芳尊留客醉，栽培玉粒療民饑。", "幅巾籬落尋梅處，一舸江湖釣月時。", "妙處惟詩可摹寫，却憐老去不工詩。"]'),
('2f23e5da-1e0f-4e1a-9199-eca32675c75f','大雪用前韻五首  其三','裘萬頃','宋','宋诗','song-poetry','','[]','誰扶天女下冰機，翦水成花片片奇。',64,'全唐诗/poet.song.175000.json','["誰扶天女下冰機，翦水成花片片奇。", "影落池塘波不動，寒侵鷗鷺色皆饑。", "縱橫萬舞風回處，表裏雙清月霽時。", "浪戰未能無寸鐵，對人羞誦醉翁詩。"]'),
('52deb43e-678b-45dc-9f13-86fbcd2880a4','大雪用前韻五首  其四','裘萬頃','宋','宋诗','song-poetry','','[]','伊人元不墮危機，踏凍衝寒正自奇。',64,'全唐诗/poet.song.175000.json','["伊人元不墮危機，踏凍衝寒正自奇。", "只怪飛花無處避，都忘炊玉有時饑。", "月明剡水回舟夜，歲暮梁園作賦時。", "一段風流誰得似，只今王謝却能詩。"]'),
('f7f9b790-ee0a-45fa-941c-156479471936','大雪用前韻五首  其五','裘萬頃','宋','宋诗','song-poetry','','[]','誰知天巧出玄機，但怪飛璚過眼奇。',64,'全唐诗/poet.song.175000.json','["誰知天巧出玄機，但怪飛璚過眼奇。", "暝立風枝寒雀倦，愁吟冰谷曉猨饑。", "蘆花洲渚月明夜，柳絮池塘春暮時。", "此景人間不長有，寫真傳影正須詩。"]'),
('03da3714-2499-4b40-a305-1d580fed89b4','題小桃源','裘萬頃','宋','宋诗','song-poetry','','[]','半月池邊倚瘦藤，望仙臺上岸烏巾。',64,'全唐诗/poet.song.175000.json','["半月池邊倚瘦藤，望仙臺上岸烏巾。", "塵埃一點不到地，花木四時長是春。", "載酒豈無好事者，爛柯應有著棋人。", "請君更種桃千樹，準擬漁郎來問津。"]'),
('a0e0f601-b824-44fd-a831-a15d764b1257','次伯仁善利閣','裘萬頃','宋','宋诗','song-poetry','','[]','看經堂中鐘磬鳴，看經堂外水雲清。',64,'全唐诗/poet.song.175000.json','["看經堂中鐘磬鳴，看經堂外水雲清。", "山連遠渚鳥飛急，風入輕帆舟去平。", "煙樹不妨留夕照，塵纓正欲濯寒泓。", "憑誰爲我問造物，乞與少陵常眼明。"]'),
('f9ea56a2-a4e1-444d-af26-6397a8f90dff','輓霞溪高縣丞二首  其一','裘萬頃','宋','宋诗','song-poetry','','[]','少年挾策上金鑾，三拜郎官鬢未斑。',64,'全唐诗/poet.song.175000.json','["少年挾策上金鑾，三拜郎官鬢未斑。", "不說知音在霄漢，但知投老向雲山。", "柳絲陰裏陶潛樂，花錦香中潘岳閑。", "逝者不堪人事異，洪崖亭下水潺潺。"]'),
('7eeb18d5-4c55-4c50-ad84-4e1256caba6f','輓霞溪高縣丞二首  其二','裘萬頃','宋','宋诗','song-poetry','','[]','公家原在洪崖宅，自是洪崖向上人。',64,'全唐诗/poet.song.175000.json','["公家原在洪崖宅，自是洪崖向上人。", "嗜酒一生真簡淡，風標八袠更精神。", "紛紛偶厭人間事，去去歸尋洞裏春。", "朱紱只今無覓處，但餘佳句鎮長新。"]'),
('d1fd1347-796f-4a19-82d7-1ec268855a20','善利閣次伯仁所題趙子良畫四首  其一','裘萬頃','宋','宋诗','song-poetry','','[]','箜篌君鄉來，分明記江樹。',24,'全唐诗/poet.song.175000.json','["箜篌君鄉來，分明記江樹。", "想君詩成時，夢作白鷗去。"]'),
('d68450d5-4411-441e-9f29-bb0ccc9047b1','善利閣次伯仁所題趙子良畫四首  其二','裘萬頃','宋','宋诗','song-poetry','','[]','平生交游間，吾幘蓋屢岸。',24,'全唐诗/poet.song.175000.json','["平生交游間，吾幘蓋屢岸。", "區區稻粱謀，君亦逐鴻鴈。"]'),
('1bbfa66a-6af6-4afa-bc86-1b6f803212c5','善利閣次伯仁所題趙子良畫四首  其三','裘萬頃','宋','宋诗','song-poetry','','[]','風簷手君詩，心迹已清絕。',24,'全唐诗/poet.song.175000.json','["風簷手君詩，心迹已清絕。", "何當更長吟，坐對澄江雪。"]'),
('ce06b386-7005-4582-ba16-2a85b8915878','善利閣次伯仁所題趙子良畫四首  其四','裘萬頃','宋','宋诗','song-poetry','','[]','扁舟兩漁翁，清唱發日暮。',24,'全唐诗/poet.song.175000.json','["扁舟兩漁翁，清唱發日暮。", "安得如鴟夷，相與五湖去。"]'),
('653e5115-775c-4872-8243-9029f13da21a','餞吳長文司理用脩持賢業教無欠爲韻  其一','裘萬頃','宋','宋诗','song-poetry','','[]','平生不量力，妄意希前脩。',24,'全唐诗/poet.song.175000.json','["平生不量力，妄意希前脩。", "懵懵雖無見，拳拳未敢休。"]'),
('e5ceae62-5193-4e4b-a6aa-f7fcf79e94e7','餞吳長文司理用脩持賢業教無欠爲韻  其二','裘萬頃','宋','宋诗','song-poetry','','[]','狂瀾湧如此，砥柱其誰爲。',24,'全唐诗/poet.song.175000.json','["狂瀾湧如此，砥柱其誰爲。", "天意必有在，吾身姑自持。"]'),
('e233dfb0-13c0-4c9b-91a9-9114ba0915dd','餞吳長文司理用脩持賢業教無欠爲韻  其三','裘萬頃','宋','宋诗','song-poetry','','[]','考亭無恙時，從游孰非賢。',24,'全唐诗/poet.song.175000.json','["考亭無恙時，從游孰非賢。", "歲寒萬木彫，松柏始傑然。"]'),
('4dc5dcc2-5e1e-49fd-86d3-903db3f1e50d','餞吳長文司理用脩持賢業教無欠爲韻  其四','裘萬頃','宋','宋诗','song-poetry','','[]','聖賢去我遠，何者名事業。',24,'全唐诗/poet.song.175000.json','["聖賢去我遠，何者名事業。", "吾欲到彼岸，須君借舟楫。"]'),
('4d47464b-e4cf-4bda-a319-741a2c52ce8a','餞吳長文司理用脩持賢業教無欠爲韻  其五','裘萬頃','宋','宋诗','song-poetry','','[]','過從資直諒，夫豈勢利交。',24,'全唐诗/poet.song.175000.json','["過從資直諒，夫豈勢利交。", "謂朋黨者誰，仁人姑聽教。"]'),
('d00de809-1dca-41c5-8f41-91c5f4365dc3','餞吳長文司理用脩持賢業教無欠爲韻  其六','裘萬頃','宋','宋诗','song-poetry','','[]','人生天地間，離別安能無。',24,'全唐诗/poet.song.175000.json','["人生天地間，離別安能無。", "莫作兒女態，相期烈丈夫。"]'),
('6a5ea2fc-71e9-4f87-84a7-ace7a12ead27','餞吳長文司理用脩持賢業教無欠爲韻  其七','裘萬頃','宋','宋诗','song-poetry','','[]','君姿正而剛，名節非所欠。',24,'全唐诗/poet.song.175000.json','["君姿正而剛，名節非所欠。", "臨歧贈一言，惟有學不厭。"]'),
('323aa69f-2d7c-46b9-a36f-99255d049d2a','自警','裘萬頃','宋','宋诗','song-poetry','','[]','俗塵易污人，胸次須自潔。',24,'全唐诗/poet.song.175000.json','["俗塵易污人，胸次須自潔。", "君看四明老，冰壺浸秋月。"]'),
('1c6f7089-65aa-4018-aba0-3a8aebeb423c','題蘇希亮畫','裘萬頃','宋','宋诗','song-poetry','','[]','石梁渡山澗，上有秦人居。',24,'全唐诗/poet.song.175000.json','["石梁渡山澗，上有秦人居。", "歲寒不種桃，汲泉灌佳蔬。"]'),
('c725fad2-1147-4807-b42c-0cbe6299802b','兀坐','裘萬頃','宋','宋诗','song-poetry','','[]','息綿綿而不絕，心了了以常明。',28,'全唐诗/poet.song.175000.json','["息綿綿而不絕，心了了以常明。", "靜室我方燕坐，傍人喚作修行。"]'),
('d652983b-ef6d-4b7f-b3df-91dac47dff3c','保福寺對橙菊有感','裘萬頃','宋','宋诗','song-poetry','','[]','平生愛菊陶彭澤，清夜移橙杜草堂。',32,'全唐诗/poet.song.175000.json','["平生愛菊陶彭澤，清夜移橙杜草堂。", "千載詩魂招不得，獨留風味在僧房。"]'),
('a797f095-cf61-404a-8955-97d9aa8ee206','兀坐有感','裘萬頃','宋','宋诗','song-poetry','','[]','意行曾到楚江臯，占得雙泉第一寮。',32,'全唐诗/poet.song.175000.json','["意行曾到楚江臯，占得雙泉第一寮。", "窗戶邃深鐘磬遠，客塵都向靜中消。"]'),
('cb9a20fa-b085-481b-844a-bcbdf9d8a499','癸亥夜夢','裘萬頃','宋','宋诗','song-poetry','','[]','丙夜清眠正熟時，夢魂飛去拜丹墀。',32,'全唐诗/poet.song.175000.json','["丙夜清眠正熟時，夢魂飛去拜丹墀。", "小臣乍得披肝膽，感慨分明涕淚垂。"]'),
('a663cdbe-a145-4d41-a7bd-bcb48a8fec0d','次洪內翰十月桃韻三首  其一','裘萬頃','宋','宋诗','song-poetry','','[]','千紅萬蕊彫零盡，安得枝頭數點紅。',32,'全唐诗/poet.song.175000.json','["千紅萬蕊彫零盡，安得枝頭數點紅。", "疑是神人寫春色，鎮長留影在屏風。"]'),
