('1dc2625d-3acf-492a-b8a2-17c408def582','窗前古槐二首  其一','裘萬頃','宋','宋诗','song-poetry','','[]','密葉繁陰畫不成，捲簾雙眼爲渠明。',32,'全唐诗/poet.song.175000.json','["密葉繁陰畫不成，捲簾雙眼爲渠明。", "人間炎熱無來處，贏得軒窗分外清。"]'),
('1d3444f0-8107-47eb-8c85-b4e1b76498c3','窗前古槐二首  其二','裘萬頃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','去歲西湖避暑來，藕花無數眼慵開。',32,'全唐诗/poet.song.175000.json','["去歲西湖避暑來，藕花無數眼慵開。", "而今歸卧洪崖側，看盡飛泉看古槐。"]'),
('a11f3672-7a0c-45da-a553-395f0bc23a4c','題針出羹字韻','裘萬頃','宋','宋诗','song-poetry','','[]','一寸堅剛鐵琢成，綺羅叢裏度平生。',32,'全唐诗/poet.song.175000.json','["一寸堅剛鐵琢成，綺羅叢裏度平生。", "有時稚子敲成釣，釣得魚兒便作羹。"]'),
('991d5f91-0201-4215-aab0-6603fcb0778e','題箋','裘萬頃','宋','宋诗','song-poetry','','[]','六七葉蘆秋雨裏，兩三箇鴈夕陽邊。',32,'全唐诗/poet.song.175000.json','["六七葉蘆秋雨裏，兩三箇鴈夕陽邊。", "青天萬里渾無礙，衝破寒潭一抹煙。"]'),
('48661ded-c326-47b9-9fc7-db8abaa96ac6','簡瑄上人','裘萬頃','宋','宋诗','song-poetry','','[]','千里歸來覓故林，朱弦雖在少知音。',32,'全唐诗/poet.song.175000.json','["千里歸來覓故林，朱弦雖在少知音。", "春風玉几山前路，忍負平生一片心。"]'),
('da016273-433a-4fb6-8555-731de6a4e1be','簡瑄上人借楞嚴經','裘萬頃','宋','宋诗','song-poetry','','[]','石室雲山鎮日扃，午雞啼處睡初醒。',32,'全唐诗/poet.song.175000.json','["石室雲山鎮日扃，午雞啼處睡初醒。", "案頭上有爐熏在，試讀楞嚴一卷經。"]'),
('0b32097b-8ad0-4226-86f3-c6bd29c51648','題隠室','裘萬頃','宋','宋诗','song-poetry','','[]','閩浙相望兩道場，上人曾炷室中香。',32,'全唐诗/poet.song.175000.json','["閩浙相望兩道場，上人曾炷室中香。", "直須了却舊公案，莫向空山便隠藏。"]'),
('f1b93df1-12b5-433b-b845-9f64acd2a784','題破塵讀經所','裘萬頃','宋','宋诗','song-poetry','','[]','試爲衆生破一塵，出經爲筏度滄溟。',32,'全唐诗/poet.song.175000.json','["試爲衆生破一塵，出經爲筏度滄溟。", "待渠到岸無驚畏，復破微塵納此經。"]'),
('34a6cd20-e21c-4c5e-95db-9d358b009328','句','裘萬頃','宋','宋诗','song-poetry','','[]','雲歸青嶂雨初歇，花卧碧苔春已休。',16,'全唐诗/poet.song.175000.json','["雲歸青嶂雨初歇，花卧碧苔春已休。"]'),
('2fad056a-31d1-4bdb-9f67-80fefdd2571b','使金詩','李壁','宋','宋诗','song-poetry','','[]','天連海岱壓中州，暖翠浮嵐夜不收。',32,'全唐诗/poet.song.175000.json','["天連海岱壓中州，暖翠浮嵐夜不收。", "如此山河落人手，西風殘照懶回頭。"]'),
('61681360-ad90-4c4a-8813-c86d00824ae0','石中二首  其一','李壁','宋','宋诗','song-poetry','','[]','雲影沈沈玉一方，倚欄人意似濠梁。',32,'全唐诗/poet.song.175000.json','["雲影沈沈玉一方，倚欄人意似濠梁。", "獨憐雪裏山茶樹，也向春風伴海棠。"]'),
('54b6e03e-2e20-4ea7-831b-51feba622758','石中二首  其二','李壁','宋','宋诗','song-poetry','','[]','梅陰漸密雨晴時，靜看花磚日影稀。',32,'全唐诗/poet.song.175000.json','["梅陰漸密雨晴時，靜看花磚日影稀。", "向晚啼鴉來又去，上林知占那邊枝。"]'),
('eaa0a6a3-c5d5-4b6d-ab87-56e6bbb814dd','酬曾景建','李壁','宋','宋诗','song-poetry','','[]','新有千絲明曉鏡，舊無一畫贊宵衣。',32,'全唐诗/poet.song.175000.json','["新有千絲明曉鏡，舊無一畫贊宵衣。", "閒吟此外惟須飲，老覺人間萬事非。"]'),
('3fd5a4b4-8d45-41ab-9779-8c3fc31abfed','臨川節中寄季和弟  其一','李壁','宋','宋诗','song-poetry','','[]','敕使傳宣泛食時，去年今日侍龍墀。',32,'全唐诗/poet.song.175000.json','["敕使傳宣泛食時，去年今日侍龍墀。", "江城牢落追前事，一寸丹心只自知。"]'),
('9fe79725-97e4-492d-9b0b-6c3b8298f5ca','臨川節中寄季和弟  其二','李壁','宋','宋诗','song-poetry','','[]','平生曠達慕莊周，老覺悲來不自由。',32,'全唐诗/poet.song.175000.json','["平生曠達慕莊周，老覺悲來不自由。", "節裏憶君頻夢見，遥傳掬淚過江州。"]'),
('abb6d68d-46dd-4632-b21e-60a5454262ac','籠鵠山房','李壁','宋','宋诗','song-poetry','','[]','蕭條白石閉嚴扃，留作遊人萬古情。',32,'全唐诗/poet.song.175000.json','["蕭條白石閉嚴扃，留作遊人萬古情。", "猶有山中舊麋鹿，舉頭如聽讀書聲。"]'),
('a6e485d9-3ee9-42c3-b7dd-1eb10cacf842','六月十八日作','李壁','宋','宋诗','song-poetry','','[]','三伏已過二，九夏欲賓秋。',156,'全唐诗/poet.song.175000.json','["三伏已過二，九夏欲賓秋。", "月林疏梧響，露圃幽花稠。", "故人有晁子，高諠今前脩。", "勝地能館我，衰疾於焉瘳。", "山寂便午憇，井冽共晨滫。", "墳素共偃蹇，几杖亦夷猶。", "嗟哉作田苦，斛水車輪抽。", "暮歌宛如笑，達旦不肯休。", "新穀幸稍登，懼貽晚禾憂。", "安得盪塵𡏖，倒卷天河流。", "生意浹萬物，仁風扇九州。", "老餘亦蘇醒，翛然脫籠囚。", "眷言南山曲，仙袂追浮丘。"]'),
('571e8774-bec8-4886-bb25-3d3024c2b7e6','六月十四日二首  其一','李壁','宋','宋诗','song-poetry','','[]','山色朝尤爽，溪聲夏亦寒。',48,'全唐诗/poet.song.175000.json','["山色朝尤爽，溪聲夏亦寒。", "蹇予資固陋，所得是平寬。", "庭日荒苔蘚，林風老蕙蘭。", "石牀聊可借，白月在松端。"]'),
('00bc42ce-2e7a-4003-8fbe-2f591d659ec6','六月十四日二首  其二','李壁','宋','宋诗','song-poetry','','[]','爲問微園綺，何如喚孔賓。',48,'全唐诗/poet.song.175000.json','["爲問微園綺，何如喚孔賓。", "好山時步屧，幽澗或垂綸。", "塵遠知仙近，人疎覺道親。", "晚來微雨過，翠色媚松筠。"]'),
('863a986d-ce7f-4dd8-92bb-12eee697cb86','嚴泰伯出示誠齋五詩屬予繼聲奉呈一首','李壁','宋','宋诗','song-poetry','','[]','爲愛比隣好，誅茅試結廬。',48,'全唐诗/poet.song.175000.json','["爲愛比隣好，誅茅試結廬。", "地臨平楚迴，堂枕一峰孤。", "乞予青霞珮，斟吾白玉腴。", "行行對金馬，謹莫戲侏儒。"]'),
('6c2fafd7-0f2b-459c-8ca0-db5bb00634b2','戲題','李壁','宋','宋诗','song-poetry','','[]','深院鎖蛾眉，黄花一兩枝。',24,'全唐诗/poet.song.175000.json','["深院鎖蛾眉，黄花一兩枝。", "晚來天氣好，渾似早春時。"]'),
('8dfd4630-a343-48cb-89c9-b079e0d43ead','又口占小詩五首  其一','李壁','宋','宋诗','song-poetry','','[]','歸傳匆匆一過家，驛亭回首見梅花。',32,'全唐诗/poet.song.175000.json','["歸傳匆匆一過家，驛亭回首見梅花。", "絕知天漢朝宗近，去去方乘犯斗槎。"]'),
('0b75871a-4319-4c47-8d31-2d1eb473cf3a','又口占小詩五首  其二','李壁','宋','宋诗','song-poetry','','[]','蟬連夜語不勝清，欹枕僧窗蠟炬明。',32,'全唐诗/poet.song.175000.json','["蟬連夜語不勝清，欹枕僧窗蠟炬明。", "早是宋公懷抱惡，更禁庭樹作離聲。"]'),
('8f310715-14a1-4656-b4da-ee2cf2f58dcb','又口占小詩五首  其三','李壁','宋','宋诗','song-poetry','','[]','歲月翩翩比擲梭，從公能幾別離多。',32,'全唐诗/poet.song.175000.json','["歲月翩翩比擲梭，從公能幾別離多。", "梁州此去千山阻，病鶴無因借一柯。"]'),
('a036f4cc-cba8-48a6-9d60-ea9d0a75a463','又口占小詩五首  其四','李壁','宋','宋诗','song-poetry','','[]','四海同心閻貳卿，兩公相對眼長青。',32,'全唐诗/poet.song.175000.json','["四海同心閻貳卿，兩公相對眼長青。", "從今太史靈臺夜，定奏梁州聚德星。"]'),
('b055825d-e726-410c-9d2a-acd902fa39b2','又口占小詩五首  其五','李壁','宋','宋诗','song-poetry','','[]','少年繆許憂時策，萬里空懷報主心。',32,'全唐诗/poet.song.175000.json','["少年繆許憂時策，萬里空懷報主心。", "畢竟窮通吾有命，鷗盟未冷且重尋。"]'),
('6927d264-1560-4826-b640-b263098ad8ab','投壺','李壁','宋','宋诗','song-poetry','','[]','彎弧力不任，棋局思慮費。',108,'全唐诗/poet.song.175000.json','["彎弧力不任，棋局思慮費。", "不如習投壺，閑暇可觀禮。", "心精手斯應，古謂射之細。", "無寧貴巧得，近取直如矢。", "瀛洲遠塵霧，永日但書几。", "相携千步廊，百發皆貫耳。", "兢兢圖克終，一瞬有成毀。", "昔賢著新裕，取正斥奇詭。", "造次垂令儀，高山勞仰止。"]'),
('94a0e146-1757-402c-b9fe-ab3ccaa11e2f','遊西湖分韻得棲字','李壁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','深居獨癡坐，愁聽鵯鴂啼。',120,'全唐诗/poet.song.175000.json','["深居獨癡坐，愁聽鵯鴂啼。", "起尋塵外游，綠陰已連畦。", "撐舟泛湖去，萬頃青玻瓈。", "天風振雲杪，飛步凌丹梯。", "同遊金玉人，曠蕩追阮嵇。", "更摛江鮑思，傑句競吐霓。", "劉侯冥鴻侶，松菊思故棲。", "豈爲稻粱謀，如彼鳬與脩。", "維之永今夕，勝遊共攀躋。", "行將著清班，奇字從君稽。"]'),
('b3442a07-45cc-4943-8676-5509f45a8297','詩一首','李壁','宋','宋诗','song-poetry','','[]','沙上翩翩兩白鷗，西風想見芰荷秋。',32,'全唐诗/poet.song.175000.json','["沙上翩翩兩白鷗，西風想見芰荷秋。", "晚來十幅冰紈淨，斷取瀟湘一片愁。"]'),
('f9806b81-cc03-481e-ab2d-98e1f167cc5d','雁湖二首  其一','李壁','宋','宋诗','song-poetry','','[]','藻荇連延十畝餘，從來佳致與人俱。',64,'全唐诗/poet.song.175000.json','["藻荇連延十畝餘，從來佳致與人俱。", "水禽撲碌時驚枕，城月朦朧當畫圖。", "莫去渚蘭留作珮，剩栽洲橘遣爲奴。", "從今杖屨頻來往，乞與嘉名喚雁湖。"]'),
('5b77047f-bd2d-47df-b718-aab0ca4feadf','雁湖二首  其二','李壁','宋','宋诗','song-poetry','','[]','新結方橋跨兩間，更渠清溜作潺潺。',64,'全唐诗/poet.song.175000.json','["新結方橋跨兩間，更渠清溜作潺潺。", "春來得句因池草，病起無端減带環。", "樓迥却愁多見月，城高元不礙看山。", "銷憂況有詩書在，贏得湖邊日日閒。"]'),
('50592bb5-d10a-4aff-8676-ffb1b2894dd3','再和雁湖十首  其一','李壁','宋','宋诗','song-poetry','','[]','觀物年來等腐餘，已甘事與衆人俱。',64,'全唐诗/poet.song.175000.json','["觀物年來等腐餘，已甘事與衆人俱。", "園林得地須頻賞，冕紱關天莫浪圖。", "好事難陪金谷友，窮居祇辨玉川奴。", "親逢聖世生非晚，不比當年孺子湖。"]'),
('f0a63d6a-0bf9-4a61-bd67-3ee12020dbe0','再和雁湖十首  其二','李壁','宋','宋诗','song-poetry','','[]','畦逕生癡筆墨間，洗心聊欲近潺潺。',64,'全唐诗/poet.song.175000.json','["畦逕生癡筆墨間，洗心聊欲近潺潺。", "干時輒莫談商鞅，枉道渠寧主瘠環。", "無事捲簾消白日，有時支枕夢青山。", "湖光莫笑無多子，印却中天象緯閒。"]'),
('3c92437e-0872-4062-96c4-e22dea0cf531','再和雁湖十首  其三','李壁','宋','宋诗','song-poetry','','[]','翠華南度幾千餘，始見中原與閏俱。',64,'全唐诗/poet.song.175000.json','["翠華南度幾千餘，始見中原與閏俱。", "千載一時周曆數，兩河百郡漢輿圖。", "平南上策歸諸葛，伐北奇功屬寄奴。", "安得忠良負雄略，一清關洛到江湖。"]'),
('f66712bc-0a9d-4fb6-a9ae-4a5a2476df21','再和雁湖十首  其四','李壁','宋','宋诗','song-poetry','','[]','夢回簷溜響潺潺，斷送群芳一夕間。',64,'全唐诗/poet.song.175000.json','["夢回簷溜響潺潺，斷送群芳一夕間。", "靜見蜂鬚拈筆架，細看蛛網度窗環。", "數行古篆留科斗，一穗沉烟起博山。", "終歲掩關非避俗，自緣多病愛清閒。"]'),
('64eec8b1-a2e0-4beb-a7ee-709b6f411723','再和雁湖十首  其五','李壁','宋','宋诗','song-poetry','','[]','總角趨庭得緒餘，詩書元自與生俱。',64,'全唐诗/poet.song.175000.json','["總角趨庭得緒餘，詩書元自與生俱。", "詞林教誦鷦鷯賦，畫苑嗔傳蛺蝶圖。", "千古凌煙思鄭國，一時偃月怨哥奴。", "情和顔蹠均爲寄，忍絜新樽上鏡湖。"]'),
('0ea76265-4f66-4711-b69e-d51ad2c02fe5','再和雁湖十首  其六','李壁','宋','宋诗','song-poetry','','[]','流光匆匆淚潺潺，又報清明瞬息間。',64,'全唐诗/poet.song.175000.json','["流光匆匆淚潺潺，又報清明瞬息間。", "暖日陂塘空荇带，薰風時節近瓜環。", "謀非爲食寧忘世，懶不從人但愛山。", "想見長安五陵道，少年袍馬逐寬閒。"]'),
('125492ed-cc97-4c20-84f6-36f712b16300','再和雁湖十首  其七','李壁','宋','宋诗','song-poetry','','[]','作詩真是學文餘，餘力猶將鮑謝俱。',64,'全唐诗/poet.song.175000.json','["作詩真是學文餘，餘力猶將鮑謝俱。", "流俗是非何足算，古人出處要良圖。", "閑來籍草須尋侶，自起澆花不倩奴。", "著却綸巾披鶴氅，中郎元住曲阿湖。"]'),
('5b4ad065-d29c-4e9e-bdb2-d72d3c43a5c8','再和雁湖十首  其八','李壁','宋','宋诗','song-poetry','','[]','繞城流水碧潺潺，好是芳菲一月間。',64,'全唐诗/poet.song.175000.json','["繞城流水碧潺潺，好是芳菲一月間。", "詩陣不收疑破竹，談圍未解遞連環。", "健如俊鶻秋翻野，壯似驚龍夜擘山。", "傳後化今當有待，百年距幾可今閒。"]'),
('faf717a8-5d6f-4d22-8e08-8b6096ba363f','再和雁湖十首  其九','李壁','宋','宋诗','song-poetry','','[]','夢鏡紛紜擾棄餘，尚連許國守心俱。',64,'全唐诗/poet.song.175000.json','["夢鏡紛紜擾棄餘，尚連許國守心俱。", "投鞭絕笑保邊策，聚米重尋破隴圖。", "天外悠悠回雁使，眼前擾擾牧豬奴。", "移床試向春風坐，面旋飛霙卷一湖。"]'),
('971f8a9e-3b08-48e3-a384-541c431bc3c0','再和雁湖十首  其一○','李壁','宋','宋诗','song-poetry','','[]','景色隨生指顧間，踏翻香雪弄潺潺。',64,'全唐诗/poet.song.175000.json','["景色隨生指顧間，踏翻香雪弄潺潺。", "奏編誰上三千牘，寶带爭拖十二環。", "有底窮愁惟甔石，無多遠意但盆山。", "何時萬頃滄波去，乞我扁舟自在閒。"]'),
('59cfb2df-13ee-4ea2-ab5c-66d6670fdc5a','予賦雁湖詩蒙友社諸文繼聲不一輒復自和四首  其一','李壁','宋','宋诗','song-poetry','','[]','少年努力在三餘，暇日那無水石俱。',64,'全唐诗/poet.song.175000.json','["少年努力在三餘，暇日那無水石俱。", "自昔空傳盤谷引，祇今何似輞川圖。", "伴人寂寞爲鷴客，登俎橫斜有蟹奴。", "便學天隨君信否，夜來春漲欲平湖。"]'),
('ea74a5b1-445f-40e3-955d-a8a63d49e1a2','予賦雁湖詩蒙友社諸文繼聲不一輒復自和四首  其二','李壁','宋','宋诗','song-poetry','','[]','比屋弦歌說此間，詩來清似玉潺潺。',64,'全唐诗/poet.song.175000.json','["比屋弦歌說此間，詩來清似玉潺潺。", "論交有道須簪盍，經世無才敢輒環。", "剡上最憐分一曲，海邊空自說三山。", "誰能伴我湖亭宿，夜靜遥占斗柄閒。"]'),
('f9147826-6354-4f92-ba68-5cedde44064c','予賦雁湖詩蒙友社諸文繼聲不一輒復自和四首  其三','李壁','宋','宋诗','song-poetry','','[]','閑來日日理荒餘，剩引漣漪一派俱。',64,'全唐诗/poet.song.175000.json','["閑來日日理荒餘，剩引漣漪一派俱。", "試把漁竿臨斷岸，從教畫手貌成圖。", "啼春不到鶑無友，警夜誰知雁有奴。", "出處須將時運看，莫分廊廟與江湖。"]'),
('221e29d3-9bbe-444b-9e5f-f9342fd86a31','予賦雁湖詩蒙友社諸文繼聲不一輒復自和四首  其四','李壁','宋','宋诗','song-poetry','','[]','欄楯相望咫尺間，翻溝送水助潺潺。',64,'全唐诗/poet.song.175000.json','["欄楯相望咫尺間，翻溝送水助潺潺。", "王家傳裏烏衣巷，夢得詩中碧玉環。", "好看畫船來泛月，何須蠟屐去尋山。", "時人不解開湖意，便道渠儂苦愛閒。"]'),
('289d4294-727c-44c5-ba74-b3eb072bd4de','季允用韻各賦兩章予亦再賦四首  其一','李壁','宋','宋诗','song-poetry','','[]','新阡淚葉記霜餘，早見春風萬壑俱。',64,'全唐诗/poet.song.175000.json','["新阡淚葉記霜餘，早見春風萬壑俱。", "姱節當時誰鶚立，故人今日半鵬圖。", "清談我不如平子，下策君元笑阿奴。", "此地對床先有約，莫教風雨隔重湖。"]'),
('5f1d351e-f22e-48cd-afb1-8b6025648f0e','季允用韻各賦兩章予亦再賦四首  其二','李壁','宋','宋诗','song-poetry','','[]','碧瓦城中一萬間，溜渠無處不潺潺。',64,'全唐诗/poet.song.175000.json','["碧瓦城中一萬間，溜渠無處不潺潺。", "鳬眠落日沙留篆，魚蹙輕冰玉破環。", "細草爭春空滿路，孤雲未雨莫歸山。", "寓言聊以忘憂耳，進德渠教一刻閒。"]'),
('8a6ff307-0bb2-4d60-a231-20a0559d71e9','季允用韻各賦兩章予亦再賦四首  其三','李壁','宋','宋诗','song-poetry','','[]','囊空那復冀贏餘，但有巍樓百尺俱。',64,'全唐诗/poet.song.175000.json','["囊空那復冀贏餘，但有巍樓百尺俱。", "匣鏡頻開聊自玩，庭蕪不掃欲何圖。", "少緣多病辭歡伯，長更貪眠謝酪奴。", "生世所資能幾許，一竿好在石魚湖。"]'),
('65c31104-bbea-4b11-8831-83fdd9a48150','季允用韻各賦兩章予亦再賦四首  其四','李壁','宋','宋诗','song-poetry','','[]','春至題詩滿竹間，晚風窗影漾潺潺。',64,'全唐诗/poet.song.175000.json','["春至題詩滿竹間，晚風窗影漾潺潺。", "水花未放紅千葉，岸柳先教綠四環。", "陶令當年惟北牖，謝公早日便東山。", "古來豪傑非無意，盡把功名付等閒。"]'),
('fb1f43e4-fd50-49eb-b3b5-e4b2ab10487d','子金舅出示雁湖和章走筆爲謝三首  其一','李壁','宋','宋诗','song-poetry','','[]','運數從來略相似，人人總道疾堪憂。',32,'全唐诗/poet.song.175000.json','["運數從來略相似，人人總道疾堪憂。", "豈知不死還相對，更把新詩互唱酬。"]'),
('5aacf59d-067c-40f8-ae9b-236ef0391c75','子金舅出示雁湖和章走筆爲謝三首  其二','李壁','宋','宋诗','song-poetry','','[]','詞源病起不全枯，一滴猶堪漲雁湖。',32,'全唐诗/poet.song.175000.json','["詞源病起不全枯，一滴猶堪漲雁湖。", "祇我少强宜末減，老人筆力更敷腴。"]'),
('9f2ad88e-1197-4d19-aab4-c610e2891b68','子金舅出示雁湖和章走筆爲謝三首  其三','李壁','宋','宋诗','song-poetry','','[]','龍山仙去參謀死，縱有奇文欲似誰。',32,'全唐诗/poet.song.175000.json','["龍山仙去參謀死，縱有奇文欲似誰。", "前輩風流只公在，不才我定愧牢之。"]'),
('bb9361fc-2219-4713-b557-5ffb49fe7863','距建德縣十里絕一小湖濱湖小山多可愛作詩記作見三首  其一','李壁','宋','宋诗','song-poetry','','[]','肩輿觸熱汗沾衣，晚渡呼舟去若飛。',32,'全唐诗/poet.song.175000.json','["肩輿觸熱汗沾衣，晚渡呼舟去若飛。", "兩腋颼颼清鏡裏，分明列子御風歸。"]'),
('0436ce9f-b4ec-4b7f-a753-32a87dca5544','距建德縣十里絕一小湖濱湖小山多可愛作詩記作見三首  其二','李壁','宋','宋诗','song-poetry','','[]','小山低映碧璘珣，十頃平湖蹙簟紋。',32,'全唐诗/poet.song.175000.json','["小山低映碧璘珣，十頃平湖蹙簟紋。", "可惜地偏人到少，西風白烏自成群。"]'),
('97d49265-e3b7-42b6-a035-0ec716a3f307','距建德縣十里絕一小湖濱湖小山多可愛作詩記作見三首  其三','李壁','宋','宋诗','song-poetry','','[]','蒼崖古木插奫淪，薄暮叢祠亦恐人。',32,'全唐诗/poet.song.175000.json','["蒼崖古木插奫淪，薄暮叢祠亦恐人。", "波面時聞聲撲碌，祇應神物是遊鱗。"]'),
('ea293eaa-75ee-4a34-8bb2-8c7abe0fc712','劉子澄約遊漢陽郎官湖子澄風雨中絕江先去余泊舟黄鶴樓下風大不可進因成七言爲寄','李壁','宋','宋诗','song-poetry','','[]','沔水悠悠下武昌，向來風物未凄涼。',64,'全唐诗/poet.song.175000.json','["沔水悠悠下武昌，向來風物未凄涼。", "江樓還對遼天月，湖草猶分漢署香。", "信筆題詩輸李白，開樽一笑後劉郎。", "蹇余終日憑高望，弔古懷人幾度傷。"]'),
('79d46dc0-02bf-4300-b3df-3957d974bcac','過漢州留房公湖一日戲和少陵韻二首  其一','李壁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖天下勝，賢相古來稀。',48,'全唐诗/poet.song.175000.json','["西湖天下勝，賢相古來稀。", "汛掃邀明月，徜徉逗落暉。", "蒲深鸂鶒響，林靜鷓鴣飛。", "脚力應難徧，雕欄幸可依。"]'),
('74fe7fda-97b4-4c18-a5cc-c377c6af90e4','過漢州留房公湖一日戲和少陵韻二首  其二','李壁','宋','宋诗','song-poetry','','[]','子美來湖上，篇篇只愛鵝。',48,'全唐诗/poet.song.175000.json','["子美來湖上，篇篇只愛鵝。", "昔年惟有此，佳處總無多。", "竹徑縈新築，荷池引舊波。", "不應慳五字，共和有陰何。"]'),
('6b05f339-edb4-4df1-9de4-79b5e50bf103','觀雁湖經行留題','李壁','宋','宋诗','song-poetry','','[]','溪作玉膏色，洞如天琢成。',24,'全唐诗/poet.song.175000.json','["溪作玉膏色，洞如天琢成。", "倩誰呼白鹿，將我上瑶京。"]'),
('555e6671-eacb-4f8b-a406-8bf89a8fe385','格齋','李壁','宋','宋诗','song-poetry','','[]','一物具一理，皆有極則處。',24,'全唐诗/poet.song.175000.json','["一物具一理，皆有極則處。", "索焉而不精，於德何所據。"]'),
('c918b4ad-8a45-40bf-9f79-ecc6ac827b49','莊敬日强齋二首  其一','李壁','宋','宋诗','song-poetry','','[]','人情樂安肆，晝夜物欲嬰。',24,'全唐诗/poet.song.175000.json','["人情樂安肆，晝夜物欲嬰。", "惟敬以直之，山立而川行。"]'),
('5daa2259-1649-4f4b-8398-5ffe02fb5377','莊敬日强齋二首  其二','李壁','宋','宋诗','song-poetry','','[]','居人晏猶眠，行子夕未宿。',24,'全唐诗/poet.song.175000.json','["居人晏猶眠，行子夕未宿。", "此心從何生，却道力不足。"]'),
('be5a100f-5d9e-459c-9076-f1abe3c3a08e','爲劉漫翁老人賦雲月高齋詩','李壁','宋','宋诗','song-poetry','','[]','嵇康遇王烈，幽憤竟莫攄。',240,'全唐诗/poet.song.175000.json','["嵇康遇王烈，幽憤竟莫攄。", "我今識漫翁，轉欲與世疏。", "況聞高齋勝，雲月隨卷舒。", "息深固以踵，道集其惟虛。", "一朝破生死，直到心地初。", "嗟我覺既晚，尚收廢棄餘。", "疑翁乃真契，百里紆柴車。", "謂我骨本好，誤落塵寰居。", "已障不自解，顧遣他人除。", "稽首謝至言，田荒始知畬。", "雖微跪履敬，脫粟薦霜蔬。", "翁早涉文史，雅意追嚴徐。", "中睹世路惡，紛紛臭如帤。", "回光述鴻寶，妙解超堪輿。", "啟鑰借我讀，怳夢猶華胥。", "匪惟見異人，乃復得異書。", "窮途有良遇，喜極還欷歔。", "居然困韁鎖，阻造焦生廬。", "後會豈無日，碧霄攬霞裾。", "不見垂天翼，變化本鯤魚。"]'),
('f36a8f02-2784-45f1-8d15-977a7cedb99e','邢臺','李壁','宋','宋诗','song-poetry','','[]','北地霜濃九月寒，駝裘破曉上征鞍。',32,'全唐诗/poet.song.175000.json','["北地霜濃九月寒，駝裘破曉上征鞍。", "也知骨相非麟鳳，慚愧州人向掌看。"]'),
('79ec05da-38d3-4268-9e1e-a95b505738d6','次韻張季長紅梅七言三首  其一','李壁','宋','宋诗','song-poetry','','[]','江路悠悠無驛使，道南特寄愜公心。',64,'全唐诗/poet.song.175000.json','["江路悠悠無驛使，道南特寄愜公心。", "似嫌大潔驚凡卉，故染輕紅伴醉吟。", "絕艷偷春來雪徑，絳葩翻露出瓊林。", "病餘不得陪真賞，祇玩新章抵碎金。"]'),
('3824f776-4dcc-4507-a87c-56c9058c868e','次韻張季長紅梅七言三首  其二','李壁','宋','宋诗','song-poetry','','[]','琳館清閒異馬曹，紅梅折得助揮毫。',64,'全唐诗/poet.song.175000.json','["琳館清閒異馬曹，紅梅折得助揮毫。", "眼明北客初疑杏，笑倚東風亦類桃。", "露浥檀心滋鼎實，春生玉面散宮醪。", "從今約略施丹粉，未害從來品格高。"]'),
('c669f881-e472-43aa-a094-a716376bcf11','次韻張季長紅梅七言三首  其三','李壁','宋','宋诗','song-poetry','','[]','雪裏橫枝凍不禁，故將濃麗變輕盈。',64,'全唐诗/poet.song.175000.json','["雪裏橫枝凍不禁，故將濃麗變輕盈。", "色分鶴頂真如醉，影借蟾輝也自清。", "晚覺鄭公殊嫵媚，生憎夷甫太鮮明。", "上林依舊羣芳首，翻笑唐昌浪得聲。"]'),
('9157c236-9e86-4399-95b3-0ad958f43751','賦黄香梅絕句八首正月二十三作時築樓居將就  其一','李壁','宋','宋诗','song-poetry','','[]','樹繞高花兀老蒼，風流舊日漢黄香。',32,'全唐诗/poet.song.175000.json','["樹繞高花兀老蒼，風流舊日漢黄香。", "雖非有意爭妍暖，豈是無心避雪霜。"]'),
('4aacab56-28fa-46a0-b465-0dafd2bea11d','賦黄香梅絕句八首正月二十三作時築樓居將就  其二','李壁','宋','宋诗','song-poetry','','[]','春風一樹斬新開，盡日花邊轉幾回。',32,'全唐诗/poet.song.175000.json','["春風一樹斬新開，盡日花邊轉幾回。", "怪底玉顔含瘴色，謫仙曾住夜郎來。"]'),
('7c929e5b-7ee6-46de-8510-2ce23052a726','賦黄香梅絕句八首正月二十三作時築樓居將就  其三','李壁','宋','宋诗','song-poetry','','[]','剪蠟霜前色太深，何如萬萼占春陰。',32,'全唐诗/poet.song.175000.json','["剪蠟霜前色太深，何如萬萼占春陰。", "今朝懶不行花徑，插遍銅彝供石林。"]'),
('14969878-f4bd-4151-87b9-cf1c6ba0391d','賦黄香梅絕句八首正月二十三作時築樓居將就  其四','李壁','宋','宋诗','song-poetry','','[]','滿園春物正關情，忽到梅邊眼倍明。',32,'全唐诗/poet.song.175000.json','["滿園春物正關情，忽到梅邊眼倍明。", "別有醉餘霞臉在，大都風格盡飛瓊。"]'),
('1cd675e2-b112-456b-8697-cf123132ddb9','賦黄香梅絕句八首正月二十三作時築樓居將就  其五','李壁','宋','宋诗','song-poetry','','[]','天留孤艷照青春，橫目何人解識真。',32,'全唐诗/poet.song.175000.json','["天留孤艷照青春，橫目何人解識真。", "蒸栗琢成渠不愛，內間梔貌幾番新。"]'),
('f91953bd-8b40-4aff-ac6a-ce3328a1bcd4','賦黄香梅絕句八首正月二十三作時築樓居將就  其六','李壁','宋','宋诗','song-poetry','','[]','姑射僊人爾匹儕，若爲塗額效宮娃。',32,'全唐诗/poet.song.175000.json','["姑射僊人爾匹儕，若爲塗額效宮娃。", "從來定價須平子，速剪繁枝送郡齋。"]'),
('ed8de540-154c-4097-bf92-448b1d4af8ed','賦黄香梅絕句八首正月二十三作時築樓居將就  其七','李壁','宋','宋诗','song-poetry','','[]','方琮分潤作幽姿，一點檀心說向誰。',32,'全唐诗/poet.song.175000.json','["方琮分潤作幽姿，一點檀心說向誰。", "正使持來供鼎事，輸他雪外兩三枝。"]'),
('b83411b6-829c-4be1-b237-bdb791379541','賦黄香梅絕句八首正月二十三作時築樓居將就  其八','李壁','宋','宋诗','song-poetry','','[]','一種清香屬當家，將黄對白本非差。',32,'全唐诗/poet.song.175000.json','["一種清香屬當家，將黄對白本非差。", "胡床十日花前坐，看得樓成管物華。"]'),
('0fb7f2ac-4a29-4045-b47a-7f5085a7783c','蠟梅數枝託悟上人持供南囿','李壁','宋','宋诗','song-poetry','','[]','色染薔薇水麝薰，靜中時有暗香聞。',32,'全唐诗/poet.song.175000.json','["色染薔薇水麝薰，靜中時有暗香聞。", "上人生怕花料理，未信真能惱石君。"]'),
('5812d336-96b3-4c9a-a716-a3c87877a331','余十歲時從亡兄仲氏侍先父攝帥江陵郡圃蠟梅數百株一昔盛開予爲記之仲兄頗賞愛以爲工今十六七年矣屬感前事重賦七言以紓余悲','李壁','宋','宋诗','song-poetry','','[]','病眼清晨欲泫霜，誰將幻色對山房。',64,'全唐诗/poet.song.175000.json','["病眼清晨欲泫霜，誰將幻色對山房。", "十年猶記湖陰夢，幾度愁聞漢苑香。", "臘雪近春纔一白，好花得地更深黄。", "祇應無復當時意，草木何知我自傷。"]'),
('6917caab-6c13-4eea-87d5-86740e63e451','青神道中','李壁','宋','宋诗','song-poetry','','[]','滄江掩映榿樹林，寶塔崷崒孤雲岑。',64,'全唐诗/poet.song.175000.json','["滄江掩映榿樹林，寶塔崷崒孤雲岑。", "田家春時相勞苦，結社分朋宴簫鼓。", "道邊兒女齊唱詞，釵梁復掛一鈎絲。", "相携却踏溪橋路，薺麥連雲住何處。"]'),
('584f1964-bf8f-4e4c-906a-7d32201ff6d4','湛庵出示憲使陳益之近作且蒙記憶再次韻一首適王令君國正携酒相過斷章併識之有便仍以寄陳也','李壁','宋','宋诗','song-poetry','','[]','重將倦翼羾天關，流浪深慚佛眼看。',64,'全唐诗/poet.song.175000.json','["重將倦翼羾天關，流浪深慚佛眼看。", "名宿青燈仍燕坐，故人白雪自幽彈。", "西江一吸還居士，寒涕雙垂任懶殘。", "應笑區區話陳迹，秋風吹老碧蘆灘。"]'),
('aebd1006-75cd-45ac-abcc-d94d8a0148c2','過昭君村賦詩','李壁','宋','宋诗','song-poetry','','[]','王嬙南郡良家子，靚飾豐容照江水。',96,'全唐诗/poet.song.175000.json','["王嬙南郡良家子，靚飾豐容照江水。", "何人引入光明宮，綠鬢雲鬟朝暮理。", "增成亦擬備充依，反向陰山嫁胡兒。", "陰山一去歸無期，塞雁南翥馬北嘶。", "當時送往穹廬底，安得屬車藏豹尾。", "何如灘頭媲東家，石上持竿釣游鯉。"]'),
('f7ab66ac-bf14-4725-89dd-f9426edfed85','二十九日遊桃李村分韻得春字','李壁','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','東風吹我出城闉，邂逅相逢得可人。',64,'全唐诗/poet.song.175000.json','["東風吹我出城闉，邂逅相逢得可人。", "踏雨先從沙路穩，怯寒更覺酒壺親。", "江山有意如違俗，桃李無心亦自春。", "便可名爲錦綉谷，匡廬東望隔烟塵。"]'),
('236d4bc0-29e0-48ca-97c8-e09214dde260','留題東屯詩四首  其一','李壁','宋','宋诗','song-poetry','','[]','千載風流表出師，帥龍山寺已題詩。',32,'全唐诗/poet.song.175000.json','["千載風流表出師，帥龍山寺已題詩。", "兩賢心跡元無異，更謁東屯老拾遺。"]'),
('cf731b5f-d7b4-4a2c-bee9-4101dfede651','留題東屯詩四首  其二','李壁','宋','宋诗','song-poetry','','[]','連峰疊嶂擁崢嶸，箇裏誰知掌樣平。',32,'全唐诗/poet.song.175000.json','["連峰疊嶂擁崢嶸，箇裏誰知掌樣平。", "還有人家留客醉，石榴花下聽啼鶑。"]'),
('a6ee8c24-2138-422a-ad2e-9c33e76ecb60','留題東屯詩四首  其三','李壁','宋','宋诗','song-poetry','','[]','作意元非谷口耕，後來更說以詩鳴。',32,'全唐诗/poet.song.175000.json','["作意元非谷口耕，後來更說以詩鳴。", "慇懃只有香溪在，曾照先生白髮莖。"]'),
('5f287d1d-8202-458c-ab88-4b55444005a1','留題東屯詩四首  其四','李壁','宋','宋诗','song-poetry','','[]','早日臯夔許致身，最憐一飯不忘君。',32,'全唐诗/poet.song.175000.json','["早日臯夔許致身，最憐一飯不忘君。", "飄零豈意窮山裏，目斷長安隔戍雲。"]'),
('40acbdf8-464f-41af-8c0a-fea7d3fac20e','黄陵題詠二首  其一','李壁','宋','宋诗','song-poetry','','[]','南雲哭重華，水死悲二女。',48,'全唐诗/poet.song.175000.json','["南雲哭重華，水死悲二女。", "天邊九點黛，白骨迷處所。", "朦朧波上瑟，清夜降北渚。", "萬古一雙魂，飄飄在煙雨。"]'),
('951fe500-11b2-4832-b4ea-fcc7aac7f620','黄陵題詠二首  其二','李壁','宋','宋诗','song-poetry','','[]','小哀洲北渚雲邊，二女明裝共儼然。',64,'全唐诗/poet.song.175000.json','["小哀洲北渚雲邊，二女明裝共儼然。", "野廟向江空寂寂，古碑無字草芊芊。", "東風近墓吹芳芷，落日深山哭杜鵑。", "猶似含顰望巡狩，九疑凝黛隔湘川。"]'),
('945d532f-e2dc-4929-a2d7-eac34539b9bf','買花','李壁','宋','宋诗','song-poetry','','[]','風格孤高却後時，夜來律管已灰吹。',32,'全唐诗/poet.song.175000.json','["風格孤高却後時，夜來律管已灰吹。", "無端紅紫偷先發，未見瓊瑶第一枝。"]'),
('3de3d3e4-8bad-4b89-a2fc-908d0f40a1d2','凌丹亭','李壁','宋','宋诗','song-poetry','','[]','猶憶兒時共酒杯，今看靈骨瑣蒼苔。',32,'全唐诗/poet.song.175000.json','["猶憶兒時共酒杯，今看靈骨瑣蒼苔。", "祇應解化元非死，萬一排空爲我來。"]'),
('35a5923e-2e19-4143-a444-3e92a0009518','題清虛庵皇甫真人坦之隠居','李壁','宋','宋诗','song-poetry','','[]','翠麓依然似夢中，撥雲軒檻正春風。',32,'全唐诗/poet.song.175000.json','["翠麓依然似夢中，撥雲軒檻正春風。", "安知松外雙飛鶴，不是桃椎與呂翁。"]'),
('07d1578c-7e78-4a3f-9f4f-d7b00cb95238','在唐安郡圃作','李壁','宋','宋诗','song-poetry','','[]','當年張李國長城，翻向天涯問大鈞。',32,'全唐诗/poet.song.175000.json','["當年張李國長城，翻向天涯問大鈞。", "爭似聖朝公道在，廟堂端要讀書人。"]'),
('38223f44-fa7a-47b6-ba2f-ad2c47b98575','中巖','李壁','宋','宋诗','song-poetry','','[]','塵土污人絕可憐，寶坊聊共炷爐煙。',64,'全唐诗/poet.song.175000.json','["塵土污人絕可憐，寶坊聊共炷爐煙。", "高懷已屬三峰上，舊事重尋千載前。", "暖吹靜翻花漠漠，晚雲深護竹娟娟。", "祇應難見惟神物，留取新詩結舊緣。"]'),
('b5a8ecd5-61b6-4283-8a0c-805fcb6e9092','下巖','李壁','宋','宋诗','song-poetry','','[]','破曉檣竿插釣磯，一生幾度扣禪扉。',64,'全唐诗/poet.song.175000.json','["破曉檣竿插釣磯，一生幾度扣禪扉。", "心如尊者巖中定，身比涪翁僰道歸。", "閲世雲藤那解老，近人空翠欲成圍。", "祇憐歲晚龍方卧，不放銀濤百尺飛。"]'),
('5de6240e-8b73-4bd8-95a8-d8e2720a7d57','題跋黄魯直讀書巖字二十言','李壁','宋','宋诗','song-poetry','','[]','筆法推黄子，鍾王共一機。',24,'全唐诗/poet.song.175000.json','["筆法推黄子，鍾王共一機。", "試摹三大字，歸榜舊巖扉。"]'),
('6ee90580-ccf0-4813-9e1e-70d49235142c','遊靈巖和韻三首  其一','李壁','宋','宋诗','song-poetry','','[]','觚棱木杪梵王宮，路轉峰回翠掃空。',32,'全唐诗/poet.song.175000.json','["觚棱木杪梵王宮，路轉峰回翠掃空。", "胸次淨無塵一點，亂雲堆裏聽松風。"]'),
('b5d87753-088e-4896-bc82-b4dbc2eaa5b0','遊靈巖和韻三首  其二','李壁','宋','宋诗','song-poetry','','[]','選勝寧辭屐齒尖，摩挲墨妙半儒先。',32,'全唐诗/poet.song.175000.json','["選勝寧辭屐齒尖，摩挲墨妙半儒先。", "八年兩到人爭問，香火靈山似有緣。"]'),
('272001fa-72cc-4c20-aed1-17aa358e029d','遊靈巖和韻三首  其三','李壁','宋','宋诗','song-poetry','','[]','蕭然陳跡寄林坰，千古誰分僞與真。',32,'全唐诗/poet.song.175000.json','["蕭然陳跡寄林坰，千古誰分僞與真。", "惟有離宮歌舞地，遺簪墜珥付耕人。"]'),
('8ad80a30-691f-4711-ae32-46d877a42fd1','知府丈袖賜新篇愈歎精奇勉綴俚辭干覽采','李壁','宋','宋诗','song-poetry','','[]','書邊慣度短檠宵，心和南山扣角謠。',64,'全唐诗/poet.song.175000.json','["書邊慣度短檠宵，心和南山扣角謠。", "霢霂幾隨風入夜，熒煌行見日升朝。", "自憐鏡裏吳霜滿，難敵毫端海蜃摇。", "好是濉陽桃李樹，春風新照玉麟腰。"]'),
('612023d6-0435-49ad-b67e-8d7ebb2162bf','知府李大諫特枉新詩存問甚厚以謝','李壁','宋','宋诗','song-poetry','','[]','蓋代今推骨鯁臣，朝來有使到漳濱。',64,'全唐诗/poet.song.175000.json','["蓋代今推骨鯁臣，朝來有使到漳濱。", "稍諳逆境寧非夢，不隔寒荄始是春。", "菜甲旋鋤聊誑口，茅堂新葺且怡神。", "故應猶喜斯文在，風雨鳴雞夜向晨。"]'),
('311f07c5-ab91-4d88-9ed2-b8d155bea963','東帥少才兄寵貺七言一首口占八句以謝','李壁','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u957f\u6c5f"]','辛苦燈窗少日同，未應歲晚馬牛風。',64,'全唐诗/poet.song.175000.json','["辛苦燈窗少日同，未應歲晚馬牛風。", "匡山何敢杜陵敵，子貢還憐顔巷空。", "紅旆碧油雖貴重，清泉白石也英雄。", "長哦缺月長江句，總是霜鬚六十翁。"]'),
('2ebfa914-2d7d-4467-b01d-3ac4de14f787','東帥張傳之遣人來相致將以七言次韻答之三首  其一','李壁','宋','宋诗','song-poetry','','[]','質非高古謝罍樽，漫向陳編挹聖言。',64,'全唐诗/poet.song.175000.json','["質非高古謝罍樽，漫向陳編挹聖言。", "久判餘生甘掃墓，尚懷先友欲登門。", "功名自昔歸羊傅，丘壑從來著謝鯤。", "何日扁舟澠若去，眼看荔子壓枝繁。"]'),
('df010006-7004-40bf-ab70-a4448ce0bda1','東帥張傳之遣人來相致將以七言次韻答之三首  其二','李壁','宋','宋诗','song-poetry','','[]','閬風當日奉清樽，猶記銀鈎洒七言。',64,'全唐诗/poet.song.175000.json','["閬風當日奉清樽，猶記銀鈎洒七言。", "別去凄凉渾一夢，只今疎懶且衡門。", "已非絕足那希驥，自比游塵或佐鯤。", "珍重曲江勞仰止，人間歲晚雪霜繁。"]'),
('fea89873-cedc-4522-92b1-35ce4ce6516c','東帥張傳之遣人來相致將以七言次韻答之三首  其三','李壁','宋','宋诗','song-poetry','','[]','媿無庭論發奇樽，閑放騷人大小言。',64,'全唐诗/poet.song.175000.json','["媿無庭論發奇樽，閑放騷人大小言。", "徐孺真能下蕃榻，孔公尚記出膺門。", "赤霄覽德聊追鳳，滄海尋仙更踏鯤。", "華髮蕭蕭公健在，一將金奏洗哇繁。"]'),
('34876630-5323-4717-a432-5eee14acd1ea','四月十八日送連帥毋丘厚卿三聖院即事','李壁','宋','宋诗','song-poetry','','[]','送客來山寺，客去獨凭欄。',108,'全唐诗/poet.song.175000.json','["送客來山寺，客去獨凭欄。", "新篁已解籜，瑩眼青琅玕。", "玉臺居上頭，連峰鬰巑岏。", "清泉動古甃，凉颸發輕紈。", "黄雲刮欲空，子規鳴聲酸。", "秋種亦已布，豆菽行漫漫。", "誠知藩寄忝，但願農畝安。", "歸路轉沙磧，廣川浩澄瀾。", "物色固自好，我憂何當寬。"]'),
('a960c3e0-ba41-4661-87ee-2c74174017f5','送梁漕帥夔二首  其一','李壁','宋','宋诗','song-poetry','','[]','天涯留滯幾星霜，兩見飛來詔版黄。',64,'全唐诗/poet.song.175000.json','["天涯留滯幾星霜，兩見飛來詔版黄。", "止水無私陶靜冶，干將不露起頹綱。", "拭看遠服恩波被，轉覺朝家德意長。", "持此便應歸法從，色絲先補舜衣裳。"]'),
('ecf9772a-8934-441c-8bfc-9b876fcd40aa','送梁漕帥夔二首  其二','李壁','宋','宋诗','song-poetry','','[]','先聲凜凜懾烏蠻，舟引旌旗略萬山。',64,'全唐诗/poet.song.175000.json','["先聲凜凜懾烏蠻，舟引旌旗略萬山。", "白帝城頭風日好，永安門外水雲閒。", "功名可致身爲重，富貴相尋髮未班。", "千古江濆卧龍在，請公携酒數開顔。"]'),
('a0f40bd4-1aa7-4a6a-b5cf-2ec2cee0e3ca','錢史君見贈元夕新什次韻答之','李壁','宋','宋诗','song-poetry','','[]','元夕風光付濕薪，更堪門外雨如塵。',64,'全唐诗/poet.song.175000.json','["元夕風光付濕薪，更堪門外雨如塵。", "千枝寶炬知何處，一寸清愁苦傍人。", "落紙驚蛇空妙墨，中庭獨鶴漫閒身。", "青藜不照蓬萊閣，雲斷蒼梧愴百神。"]'),
('79d1c460-6268-40b3-a872-b22ff84bed01','真州元夕和韻二首  其一','李壁','宋','宋诗','song-poetry','','[]','璧月舒金波，流光入窗蓬。',96,'全唐诗/poet.song.175000.json','["璧月舒金波，流光入窗蓬。", "江水碧杳杳，淮山直叢叢。", "牢落亦清甘，繁華兒輩事。", "一褐擁春寒，倦撥青編睡。", "絳紗眩紈綺，簫鼓沸隔船。", "龕燈獨耿耿，靜對花雙懸。", "更深共語笑，爲客何時了。", "紛兮總濁惡，文字有潜照。"]'),
('79af318c-343f-4085-8020-c0c0ce67b514','真州元夕和韻二首  其二','李壁','宋','宋诗','song-poetry','','[]','通宵風撼天，清曉雪壓蓬。',96,'全唐诗/poet.song.175000.json','["通宵風撼天，清曉雪壓蓬。", "蒼茫烟海涯，寂寞葭葦叢。", "龍驤水犀手，有亦安所事。", "洪波絳鼉翻，陰穴翠螭睡。", "孰能乘此險，惟應漢戈船。", "烱烱眸電閃，摇摇心旆懸。", "排烟把醆笑，鐵甕高了了。", "陰雲欣解剝，麗日廓清照。"]'),
('54b9f5fc-04be-4922-a781-96ff5e66333e','赤壁','李壁','宋','宋诗','song-poetry','','[]','赤壁危磯幾度過，沙頭江上鬰嵯峨。',32,'全唐诗/poet.song.175000.json','["赤壁危磯幾度過，沙頭江上鬰嵯峨。", "今人誤信黄州是，猶頼水經能正訛。"]'),
('1477ef40-3286-49fa-828a-40d8d44ac3d6','登擬峴臺詩','李壁','宋','宋诗','song-poetry','','[]','羊公洙泗人，易地即顔子。',156,'全唐诗/poet.song.175000.json','["羊公洙泗人，易地即顔子。", "功名真餘棄，邂逅照圖史。", "況復權利間，何啻鼠肝似。", "武庫偶並稱，相去不知幾。", "臺傾屬新葺，天遠暮山紫。", "佳月喚我來，拋却烏皮几。", "莫言風景非，世本無真是。", "有酒即宜城，有魚斯漢水。", "殷勤一樽共，清唱切雲起。", "羈旅聊自紓，高興未渠已。", "銀河簾旌接，斗柄屋山指。", "側聞急才秋，便坐引奇士。", "但遣君意陳，流落非予耻。"]'),
('14e18149-e43e-42c9-b8f5-6b00fa4083e2','青雲亭  其一','李壁','宋','宋诗','song-poetry','','[]','誰人此地著危欄，城郭江山表裏看。',32,'全唐诗/poet.song.175000.json','["誰人此地著危欄，城郭江山表裏看。", "時節不知春已半，天圍稍覺目前寬。"]'),
('9eab7fd1-b863-454a-b81e-06692e4dbcbd','青雲亭  其二','李壁','宋','宋诗','song-poetry','','[]','青雲歧路休回首，扁榜看來也自驚。',32,'全唐诗/poet.song.175000.json','["青雲歧路休回首，扁榜看來也自驚。", "何日深山更深處，只留黄犢伴春耕。"]'),
('321beaf4-cba2-4839-8278-0257476a08d8','青雲亭  其三','李壁','宋','宋诗','song-poetry','','[]','平林野水带孤城，倦客登臨太瘦生。',32,'全唐诗/poet.song.175000.json','["平林野水带孤城，倦客登臨太瘦生。", "過眼千花競紅紫，可憐霜鬢轉分明。"]'),
('7569bf49-e4da-42e7-a80e-0afbd36da2aa','金石山林宣參山房','李壁','宋','宋诗','song-poetry','','[]','高處渾無一點塵，平川極目淨於茵。',64,'全唐诗/poet.song.175000.json','["高處渾無一點塵，平川極目淨於茵。", "松聲滿院日亭午，世味著人誰識真。", "倘乞半巖容卜築，仍留別浦待垂綸。", "寒灰豈復重然望，獨愛新詩語不陳。"]'),
('a399d3e4-0477-416a-aacc-0bfdba648fcf','北園酌酒觀鶴','李壁','宋','宋诗','song-poetry','','[]','仰看翔翮俯游鱗，物意落落各自春。',32,'全唐诗/poet.song.175000.json','["仰看翔翮俯游鱗，物意落落各自春。", "遥想滄浪五君子，長身玉立伴閑人。"]'),
('607d73eb-9aeb-4d12-b36b-04bad3e4fea2','東山精舍','李壁','宋','宋诗','song-poetry','','[]','木落天清遠嶺多，水平煙盡鏡新磨。',32,'全唐诗/poet.song.175000.json','["木落天清遠嶺多，水平煙盡鏡新磨。", "周公謝傅皆塵土，病鶴閑來借一柯。"]'),
